          />
          {/* Wordmark */}
          <span style={{
            fontSize: "18px", fontWeight: "700", color: "#fff",
            fontFamily: "'Georgia', 'Times New Roman', serif",
            letterSpacing: "-0.02em",
          }}>
            Bond.
          </span>
        </Link>
        {/* Admin badge */}
        <span style={{
          fontSize: "9px", fontWeight: "800", letterSpacing: "0.12em",
