                      </span>
                    )}
                  </button>
                ))}
              </div>

              {/* Logout */}
              <div style={{ padding: "6px", borderTop: "1px solid #f0e8dc" }}>
                <button
                  onClick={handleLogout}
                  style={{
                    width: "100%", display: "flex", alignItems: "center", gap: "10px",
                    padding: "9px 12px", borderRadius: "10px",
                    background: "transparent", border: "none",
                    fontSize: "13px", fontWeight: "600",
                    color: "#9a3412", cursor: "pointer",
                    transition: "background 0.12s",
                  }}
                  onMouseEnter={(e) => { e.currentTarget.style.background = "#fff1ee"; }}
                  onMouseLeave={(e) => { e.currentTarget.style.background = "transparent"; }}
                >
                  <LogOut size={14} style={{ flexShrink: 0 }} />
                  Sign out
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}

import { useState, useEffect, useRef } from "react";
import { NavLink, Link, useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import {
  Map,
  Bell,
  ChevronDown,
  LogOut,
  User,
  LayoutDashboard,
  DollarSign,
  Menu,
} from "lucide-react";
import { useAuth } from "../../../hooks/useAuth";
import communityService from "../../../services/communityService";

export default function CommunityNav({ onMenuToggle }) {
  const { user, logout } = useAuth();
  const [profileOpen, setProfileOpen] = useState(false);
  const [notifCount] = useState(2);
  const [community, setCommunity] = useState(null);
  const navRef = useRef(null);
  const dropRef = useRef(null);
  const navigate = useNavigate();

  // Fetch the community profile owned by the logged-in user
  useEffect(() => {
    if (!user) return;
    communityService.getOwn()
      .then((res) => setCommunity(res.data?.community ?? null))
      .catch(() => setCommunity(null));
  }, [user]);

  // Nav entrance animation
  useEffect(() => {
    gsap.fromTo(
      navRef.current,
      { y: -20, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.55, ease: "power3.out" }
    );
  }, []);

  // Dropdown entrance animation
  useEffect(() => {
    if (!dropRef.current || !profileOpen) return;
    gsap.fromTo(
      dropRef.current,
      { opacity: 0, y: -8, scale: 0.97 },
      { opacity: 1, y: 0, scale: 1, duration: 0.2, ease: "power2.out" }
    );
  }, [profileOpen]);

  // Close dropdown on outside click
  useEffect(() => {
    const handler = (e) => {
      if (dropRef.current && !dropRef.current.parentElement.contains(e.target))
        setProfileOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleLogout = async () => {
    setProfileOpen(false);
    await logout();
    navigate("/login");
  };

  // Display name: prefer community name, fall back to user's full_name
  const displayName = community?.name ?? user?.full_name ?? "Community";
  const avatarUrl   = community?.logo_url ?? user?.avatar_url ?? null;
  const isVerified  = community?.status === "verified";

  const initials = displayName
    .split(" ")
    .slice(0, 2)
    .map((n) => n[0])
    .join("")
    .toUpperCase();

  return (
    <header
      ref={navRef}
      className="fixed top-0 left-0 right-0 z-50 h-16 flex items-center"
      style={{
        backgroundColor: "var(--color-cream-light)",
        borderBottom: "1px solid var(--color-border-soft)",
      }}
    >
      {/* Logo + mobile sidebar toggle */}
      <div
        className="flex items-center gap-3 px-4 md:px-6 shrink-0"
        style={{ width: "260px" }}
      >
        {/* Hamburger — only visible on mobile */}
        <button
          className="md:hidden p-2 rounded-lg hover:bg-black/5 transition-colors"
          style={{ color: "var(--color-text-muted)" }}
          onClick={onMenuToggle}
          aria-label="Toggle sidebar"
        >
          <Menu size={18} />
        </button>

        <Link to="/community" className="flex items-center gap-2.5 group">
          <img
            src="/logo.png"
            alt="Bond Logo"
            className="h-9 w-9 object-contain transition-transform duration-200 group-hover:scale-105"
          />
          <span
            className="text-lg font-semibold tracking-tight hidden sm:block"
            style={{
              fontFamily: "var(--font-display)",
              color: "var(--color-forest-deep)",
            }}
          >
            Bond.
          </span>
        </Link>
      </div>

      {/* Center: page label */}
      <div className="flex-1 px-4 hidden md:flex items-center">
        <p
          className="text-sm font-medium"
          style={{ color: "var(--color-text-muted)" }}
        >
          Community Dashboard
        </p>
      </div>

      {/* Right actions */}
      <div className="flex items-center gap-1 px-4 md:px-6 ml-auto">
        {/* Notifications */}
        <button
          className="relative p-2.5 rounded-lg hover:bg-black/5 transition-colors"
          style={{ color: "var(--color-text-muted)" }}
          aria-label="Notifications"
        >
          <Bell size={18} />
          {notifCount > 0 && (
            <span
              className="absolute top-1.5 right-1.5 w-4 h-4 rounded-full text-[10px] font-bold flex items-center justify-center"
              style={{ backgroundColor: "var(--color-amber)", color: "white" }}
            >
              {notifCount}
            </span>
          )}
        </button>

        {/* Earnings shortcut — hidden on very small screens */}
        <NavLink
          to="/community/earnings"
          className={({ isActive }) =>
            `hidden sm:flex items-center gap-1.5 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
              isActive ? "" : "hover:bg-black/5"
            }`
          }
          style={({ isActive }) => ({
            color: isActive ? "var(--color-amber)" : "var(--color-text-mid)",
            backgroundColor: isActive ? "var(--color-amber-light)" : "",
          })}
        >
          <DollarSign size={15} />
          Earnings
        </NavLink>

        {/* Profile dropdown */}
        <div className="relative ml-1">
          <button
            className="flex items-center gap-2 p-1.5 rounded-xl hover:bg-black/5 transition-colors"
            onClick={() => setProfileOpen((v) => !v)}
            aria-expanded={profileOpen}
            aria-haspopup="true"
          >
            {/* Avatar */}
            <span className="relative">
              {avatarUrl ? (
                <img
                  src={avatarUrl}
                  className="w-8 h-8 rounded-full object-cover"
                  alt={displayName}
                />
              ) : (
                <span
                  className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-semibold"
                  style={{
                    backgroundColor: "var(--color-amber-light)",
                    color: "var(--color-amber)",
                  }}
                >
                  {initials}
                </span>
              )}
              {isVerified && (
                <span
                  className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 rounded-full flex items-center justify-center"
                  style={{ backgroundColor: "var(--color-forest-light)" }}
                >
                  <svg width="7" height="7" viewBox="0 0 7 7" fill="none">
                    <path
                      d="M1 3.5L2.8 5.5L6 1.5"
                      stroke="white"
                      strokeWidth="1.2"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                    />
                  </svg>
                </span>
              )}
            </span>

            {/* Name — hidden on mobile */}
            <span
              className="hidden md:block text-sm font-medium max-w-[120px] truncate"
              style={{ color: "var(--color-text-dark)" }}
            >
              {displayName}
            </span>

            <ChevronDown
              size={14}
              style={{
                color: "var(--color-text-muted)",
                transform: profileOpen ? "rotate(180deg)" : "rotate(0deg)",
                transition: "transform 0.2s",
              }}
            />
          </button>

          {profileOpen && (
            <div
              ref={dropRef}
              className="absolute right-0 top-full mt-2 w-56 rounded-2xl overflow-hidden"
              style={{
                backgroundColor: "var(--color-cream-light)",
                border: "1px solid var(--color-border-soft)",
                boxShadow: "var(--shadow-modal)",
              }}
            >
              {/* Header */}
              <div
                className="px-4 py-3 border-b"
                style={{ borderColor: "var(--color-border-soft)" }}
              >
                <div className="flex items-center gap-1.5">
                  <p
                    className="text-sm font-semibold truncate"
                    style={{ color: "var(--color-text-dark)" }}
                  >
                    {displayName}
                  </p>
                  {isVerified && (
                    <span
                      className="w-4 h-4 rounded-full flex items-center justify-center shrink-0"
                      style={{ backgroundColor: "var(--color-forest-light)" }}
                    >
                      <svg width="8" height="8" viewBox="0 0 8 8" fill="none">
                        <path
                          d="M1.5 4L3 5.5L6.5 2"
                          stroke="white"
                          strokeWidth="1.2"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                        />
                      </svg>
                    </span>
                  )}
                </div>
                <p
                  className="text-xs mt-0.5 truncate"
                  style={{ color: "var(--color-text-muted)" }}
                >
                  {user?.full_name ?? "Community Host"}
                </p>
              </div>

              {/* Nav links */}
              <div className="py-1.5">
                {[
                  { icon: LayoutDashboard, label: "Dashboard",     to: "/community" },
                  { icon: User,            label: "Profile Setup",  to: "/community/profile" },
                  { icon: DollarSign,      label: "Earnings",       to: "/community/earnings" },
                ].map(({ icon: Icon, label, to }) => (
                  <button
                    key={label}
                    className="w-full flex items-center gap-3 px-4 py-2.5 text-sm hover:bg-black/5 transition-colors"
                    style={{ color: "var(--color-text-mid)" }}
                    onClick={() => { navigate(to); setProfileOpen(false); }}
                  >
                    <Icon size={15} />
                    {label}
                  </button>
                ))}
              </div>

              {/* Logout */}
              <div
                className="border-t py-1.5"
                style={{ borderColor: "var(--color-border-soft)" }}
              >
                <button
                  className="w-full flex items-center gap-3 px-4 py-2.5 text-sm hover:bg-red-50 transition-colors"
                  style={{ color: "var(--color-terracotta)" }}
                  onClick={handleLogout}
                >
                  <LogOut size={15} />
                  Log out
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}

import { useState, useEffect, useRef } from "react";
import { NavLink, Link, useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import { Compass, LogIn, LogOut, Map, Menu, Sparkles, User, X } from "lucide-react";
import { useAuth } from "../../../context/AuthContext";

const NAV_LINKS = [
  { to: "/",        label: "Home",    end: true  },
  { to: "/explore", label: "Explore", end: false },
  { to: "/stories", label: "Stories", end: false },
  { to: "/about",   label: "About",   end: false },
];

export default function PublicNav() {
  const [scrolled,    setScrolled]    = useState(false);
  const [mobileOpen,  setMobileOpen]  = useState(false);
  const navRef        = useRef(null);
  const mobileMenuRef = useRef(null);
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const isTourist = user?.role === "tourist";
  const activeLinks = isTourist
    ? [
        { to: "/tourist", label: "Home", end: true },
        { to: "/tourist/explore", label: "Explore", end: false },
        { to: "/tourist/bookings", label: "Bookings", end: false },
      ]
    : NAV_LINKS;

  /* ── scroll glass effect ── */
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 24);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  /* ── entrance animation ── */
  useEffect(() => {
    gsap.fromTo(
      navRef.current,
      { y: -20, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.6, ease: "power3.out", delay: 0.1 }
    );
  }, []);

  /* ── mobile menu animation ── */
  useEffect(() => {
    if (!mobileMenuRef.current) return;
    if (mobileOpen) {
      gsap.fromTo(
        mobileMenuRef.current,
        { height: 0, opacity: 0 },
        { height: "auto", opacity: 1, duration: 0.3, ease: "power2.out" }
      );
    } else {
      gsap.to(mobileMenuRef.current, {
        height: 0,
        opacity: 0,
        duration: 0.25,
        ease: "power2.in",
      });
    }
  }, [mobileOpen]);

  /* ── close mobile menu on route change ── */
  const closeMobile = () => setMobileOpen(false);
  const handleLogout = async () => {
    closeMobile();
    await logout();
    navigate("/auth/login", { replace: true });
  };

  return (
    <header ref={navRef} className="fixed left-0 right-0 top-0 z-50 px-3 pt-3">
      <nav
        className="mx-auto flex h-14 max-w-7xl items-center justify-between rounded-[12px] px-3.5 sm:px-5"
        style={{
          backgroundColor: scrolled ? "rgba(242,237,228,0.95)" : "transparent",
          backdropFilter: scrolled ? "blur(16px)" : "none",
          border: scrolled ? "1px solid rgba(28,61,46,0.12)" : "1px solid transparent",
          boxShadow: scrolled ? "0 12px 32px rgba(28,61,46,0.10)" : "none",
          transition: "all 0.4s ease",
        }}
      >

        {/* ── Logo ── */}
        <Link to={isTourist ? "/tourist" : "/"} className="flex items-center gap-2.5 group" onClick={closeMobile}>
          <img
            src="/logo.png"
            alt="Bond Logo"
            className="h-10 w-10 object-contain transition-transform duration-200 group-hover:scale-105"
          />
          <span
            className="text-lg font-semibold tracking-tight"
            style={{ fontFamily: "var(--font-display)", color: "var(--color-forest-deep)" }}
          >
            Bond.
          </span>
        </Link>

        {/* ── Desktop links ── */}
        <ul className="hidden md:flex items-center gap-1 rounded-full bg-white/55 p-1 ring-1 ring-[rgba(28,61,46,0.08)]">
          {activeLinks.map(({ to, label, end }) => (
            <li key={to}>
              <NavLink
                to={to}
                end={end}
                className={({ isActive }) =>
                  `rounded-full px-4 py-2 text-sm font-medium transition-all duration-200 ${isActive ? "" : "hover:bg-white/80"}`
                }
                style={({ isActive }) => ({
                  color:      isActive ? "var(--color-forest)" : "var(--color-text-mid)",
                  fontWeight: isActive ? 600 : 500,
                  backgroundColor: isActive ? "white" : "transparent",
                  boxShadow: isActive ? "0 4px 14px rgba(28,61,46,0.08)" : "none",
                })}
              >
                {label}
              </NavLink>
            </li>
          ))}
        </ul>

        {/* ── Desktop CTA ── */}
        <div className="hidden md:flex items-center gap-3">
          {isTourist ? (
            <>
              <Link
                to="/tourist/profile"
                className="inline-flex items-center gap-1.5 rounded-full px-3 py-2 text-sm font-medium transition-colors duration-200 hover:bg-white/70"
                style={{ color: "var(--color-text-mid)" }}
              >
                <User size={14} /> Profile
              </Link>
              <button
                type="button"
                onClick={handleLogout}
                className="inline-flex items-center gap-1.5 text-sm font-semibold px-5 py-2 rounded-full transition-all duration-200 hover:opacity-90 hover:shadow-md"
                style={{
                  background: "linear-gradient(135deg, var(--color-forest-deep), var(--color-river))",
                  color: "var(--color-cream-light)",
                  borderRadius: "var(--radius-pill)",
                }}
              >
                <LogOut size={14} /> Log out
              </button>
            </>
          ) : (
            <>
              <Link
                to="/auth/login"
                className="inline-flex items-center gap-1.5 rounded-full px-3 py-2 text-sm font-medium transition-colors duration-200 hover:bg-white/70"
                style={{ color: "var(--color-text-mid)" }}
                onMouseEnter={(e) => (e.target.style.color = "var(--color-forest)")}
                onMouseLeave={(e) => (e.target.style.color = "var(--color-text-mid)")}
              >
                <LogIn size={14} /> Log in
              </Link>
              <Link
                to="/auth/register"
                className="inline-flex items-center gap-1.5 text-sm font-semibold px-5 py-2 rounded-full transition-all duration-200 hover:opacity-90 hover:shadow-md"
                style={{
                  background: "linear-gradient(135deg, var(--color-forest-deep), var(--color-river))",
                  color: "var(--color-cream-light)",
                  borderRadius: "var(--radius-pill)",
                }}
              >
                <User size={14} /> Register
              </Link>
            </>
          )}
        </div>

        {/* ── Mobile hamburger ── */}
        <button
          className="md:hidden p-2 rounded-lg transition-colors hover:bg-white/70"
          onClick={() => setMobileOpen((v) => !v)}
          aria-label="Toggle menu"
          style={{ color: "var(--color-forest)" }}
        >
          {mobileOpen ? <X size={22} /> : <Menu size={22} />}
        </button>
      </nav>

      {/* ── Mobile menu ── */}
      <div
        ref={mobileMenuRef}
        className="md:hidden overflow-hidden"
        style={{
          height: 0,
          opacity: 0,
          backgroundColor: "rgba(250, 247, 242, 0.97)",
          backdropFilter: "blur(12px)",
          border: "1px solid var(--color-border-soft)",
          borderTop: 0,
          borderRadius: "0 0 12px 12px",
          margin: "0 auto",
          maxWidth: "calc(100% - 24px)",
        }}
      >
        <div className="px-6 py-4 flex flex-col gap-1">
          {activeLinks.map(({ to, label, end }) => (
            <NavLink
              key={to}
              to={to}
              end={end}
              onClick={closeMobile}
              className="text-sm font-medium py-2.5 px-3 rounded-xl transition-colors duration-150"
              style={({ isActive }) => ({
                color:           isActive ? "var(--color-forest)"      : "var(--color-text-mid)",
                fontWeight:      isActive ? 600 : 500,
                backgroundColor: isActive ? "var(--color-forest-pale)" : "transparent",
              })}
            >
              {label}
            </NavLink>
          ))}

          <div
            className="mt-3 pt-4 flex flex-col gap-2 border-t"
            style={{ borderColor: "var(--color-border-soft)" }}
          >
            {isTourist ? (
              <>
                <Link
                  to="/tourist/profile"
                  className="text-sm font-medium text-center py-2.5 rounded-xl transition-colors duration-150"
                  onClick={closeMobile}
                  style={{ color: "var(--color-text-mid)" }}
                >
                  Profile
                </Link>
                <button
                  type="button"
                  className="inline-flex items-center justify-center gap-2 text-sm font-semibold text-center py-2.5 rounded-full"
                  onClick={handleLogout}
                  style={{
                    background: "linear-gradient(135deg, var(--color-forest-deep), var(--color-river))",
                    color: "var(--color-cream-light)",
                    borderRadius: "var(--radius-pill)",
                  }}
                >
                  <Compass size={14} /> Log out
                </button>
              </>
            ) : (
              <>
                <Link
                  to="/auth/login"
                  className="text-sm font-medium text-center py-2.5 rounded-xl transition-colors duration-150"
                  onClick={closeMobile}
                  style={{ color: "var(--color-text-mid)" }}
                >
                  Log in
                </Link>
                <Link
                  to="/auth/register"
                  className="inline-flex items-center justify-center gap-2 text-sm font-semibold text-center py-2.5 rounded-full"
                  onClick={closeMobile}
                  style={{
                    background: "linear-gradient(135deg, var(--color-forest-deep), var(--color-river))",
                    color: "var(--color-cream-light)",
                    borderRadius: "var(--radius-pill)",
                  }}
                >
                  <Compass size={14} /> Register
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </header>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";
import { Link, useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import { Bell, ChevronDown, LogOut, ShieldCheck, User } from "lucide-react";
import { useAuth } from "../../../context/AuthContext";

export default function SecurityNav() {
  const { user, logout } = useAuth();
  const [profileOpen, setProfileOpen] = useState(false);
  const [notifCount] = useState(4);
  const navRef = useRef(null);
  const dropRef = useRef(null);
  const profileWrapRef = useRef(null);
  const navigate = useNavigate();

  // Entrance animation
  useEffect(() => {
    gsap.fromTo(
      navRef.current,
      { y: -20, opacity: 0 },
      { y: 0, opacity: 1, duration: 0.5, ease: "power3.out" }
    );
  }, []);

  // Callback ref — fires after the dropdown is mounted, so GSAP always
  // has a real DOM node (not null like a useEffect on the same tick would).
  const animateDropRef = useCallback((el) => {
    dropRef.current = el;
    if (!el) return;
    gsap.fromTo(
      el,
      { opacity: 0, y: -8, scale: 0.97 },
      { opacity: 1, y: 0, scale: 1, duration: 0.2, ease: "power2.out" }
    );
  }, []);

  // Outside-click against the stable wrapper div, never dropRef.parentElement
  useEffect(() => {
    const handler = (e) => {
      if (profileWrapRef.current && !profileWrapRef.current.contains(e.target)) {
        setProfileOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleLogout = async () => {
    try {
      await logout();
    } finally {
      // Always redirect — even if the server call fails the local state is cleared
      navigate("/login", { replace: true });
    }
  };

  // Normalise field names: backend returns full_name, frontend profile
  // may have already mapped it to name — handle both.
  const displayName = user?.name ?? user?.full_name ?? "Security Officer";
  const displayRole = user?.role ?? "Security";
  const avatarUrl   = user?.avatar_url ?? null;

  const initials = displayName
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  return (
    <header
      ref={navRef}
      className="fixed top-0 left-0 right-0 z-50 h-16 flex items-center"
      style={{
        backgroundColor: "var(--color-cream-light)",
        borderBottom: "1px solid var(--color-border-soft)",
      }}
    >
      {/* Logo — aligned with sidebar width */}
      <div
        className="flex items-center gap-3 px-6 shrink-0"
        style={{ width: "260px" }}
      >
        <Link to="/security" className="flex items-center gap-2.5 group">
          <img
            src="/logo.png"
            alt="Bond Logo"
            className="h-9 w-9 object-contain transition-transform duration-200 group-hover:scale-105"
          />
          <span
            className="text-lg font-semibold tracking-tight"
            style={{
              fontFamily: "var(--font-display)",
              color: "var(--color-forest-deep)",
            }}
          >
            Bond.
          </span>
        </Link>
        <span
          className="text-[10px] font-semibold px-1.5 py-0.5 rounded"
          style={{
            backgroundColor: "var(--color-forest-pale)",
            color: "var(--color-forest)",
          }}
        >
          SECURITY
        </span>
      </div>

      {/* Center label */}
      <div className="flex-1 px-6 hidden md:flex items-center">
        <p className="text-sm" style={{ color: "var(--color-text-muted)" }}>
          Security Dashboard
        </p>
      </div>

      {/* Right actions */}
      <div className="flex items-center gap-1 px-6">
        {/* Notifications */}
        <button
          className="relative p-2.5 rounded-lg hover:bg-black/5 transition-colors"
          style={{ color: "var(--color-text-muted)" }}
          title="Notifications"
        >
          <Bell size={18} />
          {notifCount > 0 && (
            <span
              className="absolute top-1.5 right-1.5 w-4 h-4 rounded-full text-[10px] font-bold flex items-center justify-center"
              style={{ backgroundColor: "var(--color-terracotta)", color: "white" }}
            >
              {notifCount}
            </span>
          )}
        </button>

        {/* Profile dropdown — profileWrapRef on the wrapper for reliable outside-click */}
        <div className="relative ml-1" ref={profileWrapRef}>
          <button
            className="flex items-center gap-2 p-1.5 rounded-xl hover:bg-black/5 transition-colors"
            onClick={() => setProfileOpen((v) => !v)}
          >
            {avatarUrl ? (
              <img
                src={avatarUrl}
                className="w-8 h-8 rounded-full object-cover"
                alt="avatar"
              />
            ) : (
              <span
                className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-semibold"
                style={{
                  backgroundColor: "var(--color-forest-pale)",
                  color: "var(--color-forest)",
                }}
              >
                {initials}
              </span>
            )}
            <ChevronDown
              size={14}
              style={{
                color: "var(--color-text-muted)",
                transform: profileOpen ? "rotate(180deg)" : "rotate(0deg)",
                transition: "transform 0.2s",
              }}
            />
          </button>

          {profileOpen && (
            <div
              ref={animateDropRef}
              className="absolute right-0 top-full mt-2 w-52 rounded-2xl overflow-hidden"
              style={{
                backgroundColor: "var(--color-cream-light)",
                border: "1px solid var(--color-border-soft)",
                boxShadow: "var(--shadow-modal)",
              }}
            >
              {/* User info */}
              <div
                className="px-4 py-3 border-b"
                style={{ borderColor: "var(--color-border-soft)" }}
              >
                <p
                  className="text-sm font-semibold truncate"
                  style={{ color: "var(--color-text-dark)" }}
                >
                  {displayName}
                </p>
                <p
                  className="text-xs mt-0.5 capitalize"
                  style={{ color: "var(--color-text-muted)" }}
                >
                  {displayRole}
                </p>
              </div>

              {/* Menu items */}
              <div className="py-1.5">
                <button
                  className="w-full flex items-center gap-3 px-4 py-2.5 text-sm hover:bg-black/5 transition-colors"
                  style={{ color: "var(--color-text-mid)" }}
                  onClick={() => {
                    navigate("/security/account");
                    setProfileOpen(false);
                  }}
                >
                  <User size={15} />
                  My Account
                </button>
              </div>

              {/* Logout */}
              <div
                className="border-t py-1.5"
                style={{ borderColor: "var(--color-border-soft)" }}
              >
                <button
                  className="w-full flex items-center gap-3 px-4 py-2.5 text-sm hover:bg-red-50 transition-colors"
                  style={{ color: "var(--color-terracotta)" }}
                  onClick={handleLogout}
                >
                  <LogOut size={15} />
                  Log out
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}

import { useEffect, useRef, useState } from "react";
import { Link, NavLink, useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import {
  BookOpen,
  ChevronDown,
  Compass,
  Heart,
  LogOut,
  Map,
  Menu,
  Search,
  User,
  X,
} from "lucide-react";
import { useAuth } from "../../../context/AuthContext";

const NAV_LINKS = [
  { to: "/tourist", label: "Home", end: true },
  { to: "/tourist/explore", label: "Explore", end: false },
  { to: "/tourist/stories", label: "Stories", end: false },
  { to: "/tourist/bookings", label: "Bookings", end: false },
];

export default function TouristNav() {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const navRef = useRef(null);
  const mobileMenuRef = useRef(null);
  const dropRef = useRef(null);
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 24);
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  useEffect(() => {
    gsap.fromTo(navRef.current, { y: -20, opacity: 0 }, { y: 0, opacity: 1, duration: 0.6, ease: "power3.out", delay: 0.1 });
  }, []);

  useEffect(() => {
    if (!mobileMenuRef.current) return;
    if (mobileOpen) {
      gsap.fromTo(mobileMenuRef.current, { height: 0, opacity: 0 }, { height: "auto", opacity: 1, duration: 0.3, ease: "power2.out" });
    } else {
      gsap.to(mobileMenuRef.current, { height: 0, opacity: 0, duration: 0.25, ease: "power2.in" });
    }
  }, [mobileOpen]);

  useEffect(() => {
    if (!dropRef.current || !profileOpen) return;
    gsap.fromTo(dropRef.current, { opacity: 0, y: -8, scale: 0.97 }, { opacity: 1, y: 0, scale: 1, duration: 0.2, ease: "power2.out" });
  }, [profileOpen]);

  useEffect(() => {
    const handler = (event) => {
      if (dropRef.current && !dropRef.current.parentElement.contains(event.target)) {
        setProfileOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const closeMobile = () => setMobileOpen(false);
  const displayName = user?.name || user?.full_name || "Traveller";
  const initials = displayName.split(" ").map((part) => part[0]).join("").slice(0, 2).toUpperCase();

  const handleLogout = async () => {
    setProfileOpen(false);
    await logout();
    navigate("/auth/login", { replace: true });
  };

  const menuItems = [
    { icon: User, label: "My Profile", to: "/tourist/profile" },
    { icon: BookOpen, label: "My Bookings", to: "/tourist/bookings" },
    { icon: Heart, label: "Favorites", to: "/tourist/favorites" },
  ];

  return (
    <header ref={navRef} className="fixed left-0 right-0 top-0 z-50 px-3 pt-3">
      <nav
        className="mx-auto flex h-14 max-w-7xl items-center justify-between rounded-[12px] px-3.5 sm:px-5"
        style={{
          backgroundColor: scrolled ? "rgba(250,247,242,0.92)" : "rgba(250,247,242,0.76)",
          backdropFilter: "blur(16px)",
          border: "1px solid rgba(28,61,46,0.12)",
          boxShadow: scrolled ? "0 12px 32px rgba(28,61,46,0.10)" : "0 6px 20px rgba(28,61,46,0.06)",
          transition: "background-color 0.25s, box-shadow 0.25s",
        }}
      >
        <Link to="/tourist" className="flex items-center gap-2.5 group" onClick={closeMobile}>
          <img
            src="/logo.png"
            alt="Bond Logo"
            className="h-10 w-10 object-contain transition-transform duration-200 group-hover:scale-105"
          />
          <span className="font-display text-lg font-semibold tracking-tight text-[#1C3D2E]">Bond.</span>
        </Link>

        <ul className="hidden items-center gap-1 rounded-full bg-white/55 p-1 ring-1 ring-[rgba(28,61,46,0.08)] md:flex">
          {NAV_LINKS.map(({ to, label, end }) => (
            <li key={to}>
              <NavLink
                to={to}
                end={end}
                className={({ isActive }) =>
                  `rounded-full px-4 py-2 text-sm font-medium transition-all duration-200 ${isActive ? "" : "hover:bg-white/80"}`
                }
                style={({ isActive }) => ({
                  color: isActive ? "var(--color-forest)" : "var(--color-text-mid)",
                  fontWeight: isActive ? 600 : 500,
                  backgroundColor: isActive ? "white" : "transparent",
                  boxShadow: isActive ? "0 4px 14px rgba(28,61,46,0.08)" : "none",
                })}
              >
                {label}
              </NavLink>
            </li>
          ))}
        </ul>

        <div className="hidden items-center gap-2 md:flex">
          <Link
            to="/tourist/explore"
            className="inline-flex items-center gap-1.5 rounded-full px-3 py-2 text-sm font-medium text-[#3D5448] transition-colors duration-200 hover:bg-white/70 hover:text-[#1C3D2E]"
          >
            <Search size={14} />
            Search
          </Link>
          <NavLink
            to="/tourist/favorites"
            className="inline-flex h-9 w-9 items-center justify-center rounded-full text-[#7A9285] transition hover:bg-white/70 hover:text-[#A04D38]"
            title="Favorites"
          >
            <Heart size={17} />
          </NavLink>

          <div className="relative">
            <button
              className="inline-flex items-center gap-2 rounded-full bg-white/60 py-1 pl-1 pr-2 text-sm font-medium text-[#3D5448] ring-1 ring-[rgba(28,61,46,0.08)] transition hover:bg-white"
              onClick={() => setProfileOpen((value) => !value)}
            >
              {user?.avatar_url ? (
                <img src={user.avatar_url} className="h-8 w-8 rounded-full object-cover" alt={displayName} />
              ) : (
                <span className="flex h-8 w-8 items-center justify-center rounded-full bg-[#D4E6DC] text-xs font-semibold text-[#1C3D2E]">
                  {initials}
                </span>
              )}
              <ChevronDown size={14} className={`transition ${profileOpen ? "rotate-180" : ""}`} />
            </button>

            {profileOpen && (
              <div
                ref={dropRef}
                className="absolute right-0 top-full mt-2 w-56 overflow-hidden rounded-xl border border-[#E8E1D5] bg-[#FAF7F2] shadow-xl"
              >
                <div className="border-b border-[#E8E1D5] px-4 py-3">
                  <p className="text-sm font-semibold text-[#1A2820]">{displayName}</p>
                  <p className="mt-0.5 truncate text-xs text-[#7A9285]">{user?.email || "Tourist"}</p>
                </div>
                <div className="py-1.5">
                  {menuItems.map(({ icon: Icon, label, to }) => (
                    <button
                      key={label}
                      className="flex w-full items-center gap-3 px-4 py-2.5 text-sm text-[#3D5448] transition hover:bg-white/70"
                      onClick={() => {
                        navigate(to);
                        setProfileOpen(false);
                      }}
                    >
                      <Icon size={15} />
                      {label}
                    </button>
                  ))}
                </div>
                <div className="border-t border-[#E8E1D5] py-1.5">
                  <button
                    className="flex w-full items-center gap-3 px-4 py-2.5 text-sm text-[#A04D38] transition hover:bg-[#FAF0EC]"
                    onClick={handleLogout}
                  >
                    <LogOut size={15} />
                    Log out
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>

        <button
          className="rounded-lg p-2 text-[#1C3D2E] transition-colors hover:bg-white/70 md:hidden"
          onClick={() => setMobileOpen((value) => !value)}
          aria-label="Toggle menu"
        >
          {mobileOpen ? <X size={22} /> : <Menu size={22} />}
        </button>
      </nav>

      <div
        ref={mobileMenuRef}
        className="overflow-hidden md:hidden"
        style={{
          height: 0,
          opacity: 0,
          backgroundColor: "rgba(250, 247, 242, 0.97)",
          backdropFilter: "blur(12px)",
          border: "1px solid var(--color-border-soft)",
          borderTop: 0,
          borderRadius: "0 0 12px 12px",
          margin: "0 auto",
          maxWidth: "calc(100% - 24px)",
        }}
      >
        <div className="flex flex-col gap-1 px-6 py-4">
          {NAV_LINKS.map(({ to, label, end }) => (
            <NavLink
              key={to}
              to={to}
              end={end}
              onClick={closeMobile}
              className="rounded-xl px-3 py-2.5 text-sm font-medium transition-colors duration-150"
              style={({ isActive }) => ({
                color: isActive ? "var(--color-forest)" : "var(--color-text-mid)",
                fontWeight: isActive ? 600 : 500,
                backgroundColor: isActive ? "var(--color-forest-pale)" : "transparent",
              })}
            >
              {label}
            </NavLink>
          ))}
          <div className="mt-3 flex flex-col gap-1 border-t border-[#E8E1D5] pt-4">
            {menuItems.map(({ icon: Icon, label, to }) => (
              <Link
                key={label}
                to={to}
                onClick={closeMobile}
                className="inline-flex items-center gap-2 rounded-xl px-3 py-2.5 text-sm font-medium text-[#3D5448]"
              >
                <Icon size={15} />
                {label}
              </Link>
            ))}
            <button
              className="mt-2 inline-flex items-center justify-center gap-2 rounded-full py-2.5 text-sm font-semibold text-[#F2EDE4]"
              style={{ background: "linear-gradient(135deg, var(--color-forest-deep), var(--color-river))" }}
              onClick={handleLogout}
            >
              <Compass size={14} />
              Log out
            </button>
          </div>
        </div>
      </div>
    </header>
  );
}

import { useEffect, useRef } from "react";
import { NavLink } from "react-router-dom";
import { gsap } from "gsap";
import {
  LayoutDashboard,
  Users,
  ScrollText,
  BarChart2,
  Flag,
  ChevronRight,
  Shield,
} from "lucide-react";

const ADMIN_NAV = [
  {
    group: "Overview",
    links: [
      { icon: LayoutDashboard, label: "Dashboard", to: "/admin", badge: null },
      { icon: BarChart2, label: "Analytics", to: "/admin/analytics", badge: null },
    ],
  },
  {
    group: "Management",
    links: [
      { icon: Users, label: "Manage Users", to: "/admin/users", badge: null },
      { icon: Flag, label: "Reports", to: "/admin/reports", badge: null },
      { icon: ScrollText, label: "Activity Logs", to: "/admin/logs", badge: null },
      { icon: Shield, label: "Manage Securities", to: "/admin/manage-securities", badge: null },
    ],
  },
];

// Flatten all links once, at module level, so indices are stable
const ALL_LINKS = ADMIN_NAV.flatMap(({ links }) => links);

export default function AdminSidebar({ collapsed = false }) {
  const sidebarRef = useRef(null);
  // Pre-size the array to the exact number of nav items so indices never shift
  const itemsRef = useRef(new Array(ALL_LINKS.length).fill(null));

  useEffect(() => {
    const ctx = gsap.context(() => {
      gsap.fromTo(
        sidebarRef.current,
        { x: -30, opacity: 0 },
        { x: 0, opacity: 1, duration: 0.5, ease: "power3.out", delay: 0.1 }
      );
      gsap.fromTo(
        itemsRef.current.filter(Boolean),
        { x: -12, opacity: 0 },
        {
          x: 0,
          opacity: 1,
          duration: 0.35,
          ease: "power2.out",
          stagger: 0.04,
          delay: 0.25,
        }
      );
    });
    return () => ctx.revert();
  }, []);

  // Track a stable flat index across groups using a ref so it never
  // triggers re-renders and is always current during the render pass.
  const indexCounter = useRef(0);
  indexCounter.current = 0; // reset at the top of every render

  return (
    <aside
      ref={sidebarRef}
      className="fixed left-0 top-16 bottom-0 flex flex-col overflow-y-auto z-40"
      style={{
        width: collapsed ? "72px" : "260px",
        backgroundColor: "var(--color-forest)",
        borderRight: "1px solid rgba(255,255,255,0.07)",
        transition: "width 0.3s ease",
      }}
    >
      <nav className="flex-1 py-5 px-3 space-y-6">
        {ADMIN_NAV.map(({ group, links }) => (
          <div key={group}>
            {!collapsed && (
              <p
                className="text-[10px] uppercase tracking-widest font-semibold px-3 mb-2"
                style={{ color: "var(--color-forest-muted)" }}
              >
                {group}
              </p>
            )}
            <ul className="space-y-0.5">
              {links.map(({ icon: Icon, label, to, badge }) => {
                // Capture the current flat index for this item, then advance
                const flatIndex = indexCounter.current++;

                return (
                  <li
                    key={to}
                    ref={(el) => {
                      itemsRef.current[flatIndex] = el;
                    }}
                  >
                    <NavLink
                      to={to}
                      end={to === "/admin"}
                      className={({ isActive }) =>
                        `flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 relative ${
                          isActive ? "" : "hover:bg-white/10"
                        }`
                      }
                      style={({ isActive }) => ({
                        backgroundColor: isActive
                          ? "rgba(255,255,255,0.12)"
                          : "",
                        color: isActive ? "white" : "var(--color-forest-soft)",
                        fontWeight: isActive ? 600 : 500,
                      })}
                      title={collapsed ? label : undefined}
                    >
                      {({ isActive }) => (
                        <>
                          {isActive && (
                            <span
                              className="absolute left-0 top-1/2 -translate-y-1/2 w-0.5 h-5 rounded-full"
                              style={{ backgroundColor: "var(--color-forest-pale)" }}
                            />
                          )}
                          <Icon
                            size={17}
                            style={{
                              color: isActive
                                ? "white"
                                : "var(--color-forest-muted)",
                              flexShrink: 0,
                            }}
                          />
                          {!collapsed && (
                            <span className="flex-1">{label}</span>
                          )}
                          {!collapsed && badge && (
                            <span
                              className="text-[10px] font-bold px-1.5 py-0.5 rounded-full"
                              style={{
                                backgroundColor: "var(--color-terracotta)",
                                color: "white",
                              }}
                            >
                              {badge}
                            </span>
                          )}
                          {!collapsed && isActive && !badge && (
                            <ChevronRight
                              size={13}
                              style={{ color: "var(--color-forest-soft)" }}
                            />
                          )}
                        </>
                      )}
                    </NavLink>
                  </li>
                );
              })}
            </ul>
          </div>
        ))}
      </nav>

      {!collapsed && (
        <div
          className="px-4 py-4 mx-3 mb-4 rounded-xl"
          style={{ backgroundColor: "rgba(255,255,255,0.06)" }}
        >
          <p
            className="text-[10px] uppercase tracking-widest font-semibold mb-1"
            style={{ color: "var(--color-forest-muted)" }}
          >
            Bond Admin
          </p>
          <p
            className="text-xs"
            style={{ color: "var(--color-forest-soft)" }}
          >
            v1.0.0 — Internal use only
          </p>
        </div>
      )}
    </aside>
  );
}

