};

import { useRef } from "react";
import { ChevronLeft, ChevronRight, MoreHorizontal } from "lucide-react";
import gsap from "gsap";

/**
 * Bond UI — Pagination
 *
 * Props:
 *  currentPage   number  (1-indexed)
 *  totalPages    number
 *  onPageChange  fn(page)
 *  siblings      number  pages on each side of current (default 1)
 *  showEdges     boolean show first/last page buttons (default true)
 *  className     string
 */

function getPageRange(current, total, siblings = 1) {
  const delta = siblings + 2;
  const range = [];
  const rangeWithDots = [];
  let l;

  for (let i = 1; i <= total; i++) {
    if (
      i === 1 ||
      i === total ||
      (i >= current - siblings && i <= current + siblings)
    ) {
      range.push(i);
    }
  }

  for (let i of range) {
    if (l) {
      if (i - l === 2) rangeWithDots.push(l + 1);
      else if (i - l !== 1) rangeWithDots.push("…");
    }
    rangeWithDots.push(i);
    l = i;
  }

  return rangeWithDots;
}

export default function Pagination({
  currentPage,
  totalPages,
  onPageChange,
  siblings = 1,
  showEdges = true,
  className = "",
}) {
  const wrapRef = useRef(null);

  const go = (page) => {
    if (page < 1 || page > totalPages || page === currentPage) return;

    gsap.fromTo(
      wrapRef.current,
      { opacity: 0.6, y: 2 },
      { opacity: 1, y: 0, duration: 0.25, ease: "power2.out" }
    );

    onPageChange?.(page);
  };

  const pages = getPageRange(currentPage, totalPages, siblings);

  const baseBtn =
    "inline-flex items-center justify-center w-9 h-9 rounded-lg text-sm font-medium transition-colors duration-150 select-none";
  const activeBtn =
    "bg-[#1C3D2E] text-[#F2EDE4] cursor-default";
  const inactiveBtn =
    "text-[#3D5448] hover:bg-[#F2EDE4] hover:text-[#1C3D2E] cursor-pointer border border-transparent hover:border-[rgba(28,61,46,0.12)]";
  const navBtn =
    "text-[#3D5448] hover:bg-[#F2EDE4] hover:text-[#1C3D2E] cursor-pointer border border-[rgba(28,61,46,0.15)] disabled:opacity-30 disabled:cursor-not-allowed";

  return (
    <div
      ref={wrapRef}
      className={`flex items-center gap-1 ${className}`}
      aria-label="Pagination"
    >
      {/* Prev */}
      <button
        onClick={() => go(currentPage - 1)}
        disabled={currentPage === 1}
        className={`${baseBtn} ${navBtn}`}
        aria-label="Previous page"
      >
        <ChevronLeft size={16} strokeWidth={2} />
      </button>

      {/* Pages */}
      {pages.map((p, i) =>
        p === "…" ? (
          <span
            key={`dots-${i}`}
            className="w-9 h-9 flex items-center justify-center text-[#7A9285]"
          >
            <MoreHorizontal size={14} />
          </span>
        ) : (
          <button
            key={p}
            onClick={() => go(p)}
            className={`${baseBtn} ${p === currentPage ? activeBtn : inactiveBtn}`}
            aria-current={p === currentPage ? "page" : undefined}
          >
            {p}
          </button>
        )
      )}

      {/* Next */}
      <button
        onClick={() => go(currentPage + 1)}
        disabled={currentPage === totalPages}
        className={`${baseBtn} ${navBtn}`}
        aria-label="Next page"
      >
        <ChevronRight size={16} strokeWidth={2} />
      </button>
    </div>
  );
}

import { useEffect, useRef } from "react";
import { CheckCircle, AlertCircle, Info, AlertTriangle, X } from "lucide-react";
import gsap from "gsap";

/**
 * Bond UI — Toast
 *
 * Render <ToastContainer> once at app root (inside ToastContext).
 * Use the useToast() hook to trigger toasts.
 *
 * Toast props:
 *  id       string  — unique id (auto-generated by context)
 *  type     "success" | "error" | "warning" | "info"
 *  title    string
 *  message  string  (optional detail)
 *  duration number  ms before auto-dismiss (default 4000, 0 = sticky)
 *  onClose  fn
 */

const configs = {
  success: {
    icon: CheckCircle,
    bar: "bg-[#3E7A58]",
    iconClass: "text-[#3E7A58]",
    bg: "bg-white",
    title: "text-[#1A2820]",
  },
  error: {
    icon: AlertCircle,
    bar: "bg-[#D4735A]",
    iconClass: "text-[#D4735A]",
    bg: "bg-white",
    title: "text-[#1A2820]",
  },
  warning: {
    icon: AlertTriangle,
    bar: "bg-[#C8883A]",
    iconClass: "text-[#C8883A]",
    bg: "bg-white",
    title: "text-[#1A2820]",
  },
  info: {
    icon: Info,
    bar: "bg-[#2A5940]",
    iconClass: "text-[#2A5940]",
    bg: "bg-white",
    title: "text-[#1A2820]",
  },
};

export function Toast({ id, type = "info", title, message, duration = 4000, onClose }) {
  const toastRef = useRef(null);
  const progressRef = useRef(null);
  const cfg = configs[type];
  const Icon = cfg.icon;

  useEffect(() => {
    const el = toastRef.current;

    /* Slide in */
    gsap.fromTo(
      el,
      { x: 60, opacity: 0 },
      { x: 0, opacity: 1, duration: 0.4, ease: "power3.out" }
    );

    /* Progress bar drain */
    if (duration > 0 && progressRef.current) {
      gsap.fromTo(
        progressRef.current,
        { scaleX: 1 },
        {
          scaleX: 0,
          duration: duration / 1000,
          ease: "none",
          transformOrigin: "left",
          onComplete: () => dismiss(),
        }
      );
    }
  }, []);

  const dismiss = () => {
    gsap.to(toastRef.current, {
      x: 60,
      opacity: 0,
      duration: 0.3,
      ease: "power2.in",
      onComplete: () => onClose?.(id),
    });
  };

  return (
    <div
      ref={toastRef}
      className={[
        "relative flex items-start gap-3 w-80 rounded-xl overflow-hidden",
        "border border-[rgba(28,61,46,0.12)] shadow-lg",
        "px-4 py-3.5",
        cfg.bg,
      ].join(" ")}
    >
      {/* left accent bar */}
      <div className={`absolute left-0 inset-y-0 w-[3px] ${cfg.bar}`} />

      <Icon size={17} strokeWidth={2} className={`shrink-0 mt-0.5 ${cfg.iconClass}`} />

      <div className="flex-1 min-w-0">
        {title && (
          <p className={`text-sm font-medium leading-snug ${cfg.title}`}>{title}</p>
        )}
        {message && (
          <p className="text-xs text-[#7A9285] leading-relaxed mt-0.5">{message}</p>
        )}
      </div>

      <button
        onClick={dismiss}
        className="shrink-0 p-0.5 rounded-md text-[#7A9285] hover:text-[#1C3D2E] hover:bg-[#F2EDE4] transition-colors"
      >
        <X size={13} strokeWidth={2} />
      </button>

      {/* progress bar */}
      {duration > 0 && (
        <div
          ref={progressRef}
          className={`absolute bottom-0 left-0 h-[2px] w-full origin-left ${cfg.bar} opacity-40`}
        />
      )}
    </div>
  );
}

/**
 * ToastContainer — place once at app root.
 * Receives `toasts` array from ToastContext.
 *
 * <ToastContainer toasts={toasts} onClose={removeToast} />
 */
export function ToastContainer({ toasts = [], onClose }) {
  return (
    <div
      className="fixed bottom-5 right-5 z-[9999] flex flex-col gap-2.5 items-end"
      aria-live="polite"
    >
      {toasts.map((t) => (
        <Toast key={t.id} {...t} onClose={onClose} />
      ))}
    </div>
  );
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import authService from '../services/authService';
import { clearAuthStorage, getStoredUser, setStoredUser } from '../utils/tokenUtils';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser]       = useState(null);
  const [loading, setLoading] = useState(true);

  // On mount: restore user from localStorage, then verify with server
  useEffect(() => {
    const checkAuth = async () => {
      try {
        const storedUser = getStoredUser();
        if (storedUser) {
          setUser(storedUser); // optimistic restore
          // Re-validate with server so stale/suspended users are caught
          const freshUser = await authService.getMe();
          setUser(freshUser);
          setStoredUser(freshUser); // keep localStorage in sync
        }
      } catch {
        // Token invalid / expired — clear everything
        clearAuthStorage();
        setUser(null);
      } finally {
        setLoading(false);
      }
    };
    checkAuth();
  }, []);

  // Throws on failure — callers (LoginForm, RegisterForm) handle the error
  const login = async (credentials) => {
    const { user } = await authService.login(credentials);
    setUser(user);
    // Login response only has basic fields — fetch full profile
    // so fields like phone, bio, city, country are available immediately
    try {
      const fullUser = await authService.getMe();
      setUser(fullUser);
      setStoredUser(fullUser);
    } catch {
      // Non-critical: profile page will still work on next refresh
    }
    return { user };
  };

  // Throws on failure — callers handle the error
  const register = async (payload) => {
    const { user } = await authService.register(payload);
    setUser(user);
    // Same as login — fetch full profile after registration
    try {
      const fullUser = await authService.getMe();
      setUser(fullUser);
      setStoredUser(fullUser);
    } catch {
      // Non-critical
    }
    return { user };
  };

  const logout = async () => {
    await authService.logout();
    setUser(null);
  };

  const value = {
    user,
    setUser,
    loading,
    login,
    register,
    logout,
    isAuthenticated: !!user,
  };

  return (
    <AuthContext.Provider value={value}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

