}

// ─── Main component ───────────────────────────────────────────
export default function CommunityProfileSetup() {
  const [form,        setForm]        = useState(EMPTY_FORM);
  const [languages,   setLanguages]   = useState([]);
  const [tagIds,      setTagIds]      = useState([]);
  const [coverUrl,    setCoverUrl]    = useState("");
  const [coverImages, setCoverImages] = useState([]);
  const [commId,      setCommId]      = useState(null);
  const [community,   setCommunity]   = useState(null);   // full community object
  const [tags,        setTags]        = useState([]);      // [{id,label,icon}]
  const [saving,      setSaving]      = useState(false);
  const [toast,       setToast]       = useState(null);
  const [loaded,      setLoaded]      = useState(false);
  const [isEditing,   setIsEditing]   = useState(false);  // false = view, true = edit form
  const [fieldErrors, setFieldErrors] = useState({});

  // ── Load existing profile on mount ───────────────────────────
  const loadProfile = () =>
    communityService.getOwn()
      .then(res => {
        const c = res?.data?.community ?? res?.community;
        if (!c) return;
        setCommunity(c);
        setCommId(c.id);
        setForm({
          name:              c.name              ?? "",
          short_description: c.short_description ?? "",
          description:       c.description       ?? "",
          village:           c.village           ?? "",
          district:          c.district          ?? "",
          state:             c.state             ?? "",
          country:           c.country           ?? "India",
          pincode:           c.pincode           ?? "",
          best_visit_season: c.best_visit_season ?? "",
        });
        setLanguages(c.languages_spoken ?? []);
        setTags(c.tags ?? []);
        setTagIds(c.tags?.map(t => t.id).filter(Boolean) ?? []);
        setCoverUrl(c.cover_image_url ?? "");
        setCoverImages(c.images ?? []);
      })
      .catch(err => {
        if (err?.status !== 404 && err?.response?.status !== 404) {
          console.error("Failed to load community profile:", err);
        }
      })
      .finally(() => setLoaded(true));

  useEffect(() => { loadProfile(); }, []);

  // ── Submit (create or update) ─────────────────────────────────
  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    setFieldErrors({});

    try {
      const payload = { ...form, languages_spoken: languages };

      if (commId) {
        await communityService.update(commId, payload);
        await communityService.updateTags(commId, tagIds);
      } else {
        payload.slug = form.name
          .toLowerCase()
          .replace(/[^a-z0-9]+/g, "-")
          .replace(/(^-|-$)+/g, "");

        const res     = await communityService.create(payload);
        const created = res?.data?.community ?? res?.community;
        if (created?.id) {
          setCommId(created.id);
          if (tagIds.length > 0) await communityService.updateTags(created.id, tagIds);
        }
      }

      // Re-fetch fresh data and switch to profile view
      await loadProfile();
      setIsEditing(false);
      setToast({ type: "success", message: commId ? "Profile updated!" : "Community created!", key: Date.now() });
    } catch (err) {
      if (err?.errors && Array.isArray(err.errors)) {
        const errMap = {};
        err.errors.forEach(e => { errMap[e.path] = e.msg; });
        setFieldErrors(errMap);
      }
      setToast({ type: "error", message: err?.message || "Save failed.", key: Date.now() });
    } finally {
      setSaving(false);
    }
  };

  // ── Loading skeleton ──────────────────────────────────────────
  if (!loaded) {
    return (
      <PageShell title="Community Profile" subtitle="Tell travellers what makes your place unique">
        <div className="max-w-2xl space-y-4">
          <div className="h-52 animate-pulse rounded-3xl bg-[#E8E1D5]" />
          {[1, 2, 3].map(i => (
            <div key={i} className="h-14 animate-pulse rounded-2xl bg-[#E8E1D5]" />
          ))}
        </div>
      </PageShell>
    );
  }

  // ── Decide what to render ─────────────────────────────────────
  // No community yet → always show setup form
  // Has community + not editing → show profile view
  // Has community + editing → show edit form
  const showForm    = !community || isEditing;
  const pageTitle   = community && !isEditing
    ? "Your Community"
    : community
      ? "Edit Profile"
      : "Community Setup";
  const pageSubtitle = community && !isEditing
    ? "Your community profile as seen by travellers"
    : "Tell travellers what makes your place unique";

  return (
    <PageShell title={pageTitle} subtitle={pageSubtitle}>

      {showForm ? (
        <EditForm
          form={form} setForm={setForm}
          languages={languages} setLanguages={setLanguages}
          tagIds={tagIds} setTagIds={setTagIds}
          coverUrl={coverUrl} setCoverUrl={setCoverUrl}
          coverImages={coverImages} setCoverImages={setCoverImages}
          commId={commId}
          saving={saving}
          fieldErrors={fieldErrors}
          onSubmit={handleSubmit}
          onCancel={community ? () => setIsEditing(false) : undefined}
        />
      ) : (
        <ProfileView
          community={community}
          tags={tags}
          languages={languages}
          onEditClick={() => setIsEditing(true)}
        />
      )}

      {toast && (
        <Toast key={toast.key} type={toast.type} message={toast.message} onDone={() => setToast(null)} />
      )}
    </PageShell>
  );
}

// ============================================================
// pages/community/CommunityRegistration.jsx
// Multi-step community registration wizard (Steps 1–4)
// ✓ Resumes saved data on page reload
// ✓ Offering images upload in background; required ID document upload blocks Step 2
// ✓ Shows "Verification in Progress" screen after submission
// ============================================================

import { useState, useEffect, useRef } from "react";
import { useNavigate, Link } from "react-router-dom";
import {
  CheckCircle, AlertCircle, ChevronRight, ChevronLeft, Loader2,
  Shield, Clock, Search, Bell, ArrowRight, FileCheck,
} from "lucide-react";
import communityService from "../../services/communityService";
import { WIZARD_STEPS } from "../../utils/verificationConstants";
import {
  Step1BasicInfo,
  Step2TeamAndDocs,
  Step3Offerings,
  Step4Consent,
} from "./CommunityRegistrationSteps";

// ─── Progress stepper ─────────────────────────────────────────
function Stepper({ current }) {
  return (
    <div className="flex items-center gap-0 mb-8">
      {WIZARD_STEPS.map((step, idx) => {
        const done   = current > step.num;
        const active = current === step.num;
        return (
          <div key={step.num} className="flex items-center flex-1 last:flex-none">
            <div className="flex flex-col items-center gap-1">
              <div className={`flex h-9 w-9 items-center justify-center rounded-full text-sm font-bold transition-all
                ${done   ? "bg-[#3E7A58] text-white"
                : active ? "bg-[#1C3D2E] text-white shadow-lg shadow-[#1C3D2E]/30"
                         : "bg-[#F0EBE3] text-[#9A9285]"}`}>
                {done ? "✓" : step.icon}
              </div>
              <span className={`text-[10px] font-semibold uppercase tracking-wide whitespace-nowrap
                ${active ? "text-[#1C3D2E]" : done ? "text-[#3E7A58]" : "text-[#B8AFA4]"}`}>
                {step.label}
              </span>
            </div>
            {idx < WIZARD_STEPS.length - 1 && (
              <div className={`flex-1 h-0.5 mx-2 mb-4 rounded-full transition-all
                ${current > step.num ? "bg-[#3E7A58]" : "bg-[#E8E1D5]"}`} />
            )}
          </div>
        );
      })}
    </div>
  );
}

// ─── Toast ────────────────────────────────────────────────────
function Toast({ type, message, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 3500); return () => clearTimeout(t); }, []);
  const ok = type === "success";
  return (
    <div className="fixed bottom-6 right-6 z-50 flex items-center gap-2.5 rounded-xl px-4 py-3 text-sm font-medium shadow-xl animate-[slideUp_0.3s_ease]"
      style={{ background: ok ? "#1C3D2E" : "#5C1A1A", color: "#F2EDE4" }}>
      {ok ? <CheckCircle size={15} /> : <AlertCircle size={15} />} {message}
    </div>
  );
}

// ─── Main wizard ──────────────────────────────────────────────
const EMPTY_FORM = {
  name: "", short_description: "", description: "",
  village: "", district: "", state: "", country: "India",
  pincode: "", best_visit_season: "",
};

export default function CommunityRegistration() {
  const navigate = useNavigate();

  const [step,      setStep]      = useState(1);
  const [commId,    setCommId]    = useState(null);
  const [saving,    setSaving]    = useState(false);
  const [loading,   setLoading]   = useState(true);
  const [toast,     setToast]     = useState(null);
  const [errors,    setErrors]    = useState({});
  const [submitted, setSubmitted] = useState(false);  // true after consent or on resume
  const [communityData, setCommunityData] = useState(null); // for status screen

  // Upload tracking
  const [uploading, setUploading] = useState(false);
  const [uploadMsg, setUploadMsg] = useState("");

  // Step 1 state
  const [form,      setForm]      = useState(EMPTY_FORM);

  // Step 2 state
  const [members,   setMembers]   = useState([{ full_name: "", phone: "", role: "", is_owner: true }]);
  const [docFiles,  setDocFiles]  = useState([]);
  const [savedDocs, setSavedDocs] = useState([]);

  // Step 3 state
  const [offerings, setOfferings] = useState([]);

  // Step 4 state
  const [accepted,  setAccepted]  = useState(false);

  // Ref to track commId in async callbacks
  const commIdRef = useRef(null);
  useEffect(() => { commIdRef.current = commId; }, [commId]);

  // ── Resume: fetch existing community + verification data ────
  useEffect(() => {
    let cancelled = false;

    communityService.getOwn()
      .then(async (res) => {
        const c = res?.data?.community ?? res?.community;
        if (!c || cancelled) { setLoading(false); return; }

        setCommId(c.id);
        setForm({
          name:              c.name              ?? "",
          short_description: c.short_description ?? "",
          description:       c.description       ?? "",
          village:           c.village           ?? "",
          district:          c.district          ?? "",
          state:             c.state             ?? "",
          country:           c.country           ?? "India",
          pincode:           c.pincode           ?? "",
          best_visit_season: c.best_visit_season ?? "",
        });

        // If already submitted, show verification status screen
        if (c.consent_accepted_at) {
          setCommunityData(c);
          setSubmitted(true);
          setLoading(false);
          return;
        }

        // Fetch verification data for resume (only if we have a valid id)
        if (c.id) {
          try {
            const vRes = await communityService.getVerificationData(c.id);
            const v = vRes?.data ?? {};

          if (v.members?.length > 0) {
            setMembers(v.members.map((m) => ({
              full_name: m.full_name ?? "",
              phone:     m.phone ?? "",
              role:      m.role ?? "",
              is_owner:  m.is_owner ?? false,
            })));
          }

          if (v.documents?.length > 0) setSavedDocs(v.documents);

          if (v.offerings?.length > 0) {
            setOfferings(v.offerings.map((o) => ({
              category:     o.category ?? "",
              custom_label: o.custom_label ?? "",
              description:  o.description ?? "",
              imageFiles:   [],
              savedImages:  o.images || [],
            })));
          }

          if (v.consent) setAccepted(true);
          } catch { /* no verification data yet */ }
        }

        const resumeStep = Math.max(1, Math.min(c.registration_step ?? 1, 4));
        if (!cancelled) setStep(resumeStep);
      })
      .catch(() => {})
      .finally(() => { if (!cancelled) setLoading(false); });

    return () => { cancelled = true; };
  }, []);

  // ── Validation ───────────────────────────────────────────────
  const validateStep = () => {
    const errs = {};
    if (step === 1) {
      if (!form.name.trim())        errs.name        = "Community name is required";
      if (!form.description.trim()) errs.description = "Description is required";
      if (!form.village.trim())     errs.village     = "Village is required";
      if (!form.state)              errs.state       = "State is required";
    }
    if (step === 2) {
      const hasInvalid = members.some((m) => !m.full_name.trim() || !m.phone.trim());
      if (hasInvalid) errs.members = "All members must have a name and phone number";
      if (docFiles.length === 0 && savedDocs.length === 0) errs.doc = "Please upload at least one ID document";
    }
    if (step === 3) {
      if (offerings.length === 0) errs.offerings = "Please add at least one offering";
      const hasNoCategory = offerings.some((o) => !o.category);
      if (hasNoCategory) errs.offerings = "All offerings must have a category selected";
    }
    if (step === 4) {
      if (!accepted) errs.consent = "You must accept the terms and conditions";
    }
    setErrors(errs);
    return Object.keys(errs).length === 0;
  };

  // ── Required ID document uploader ───────────────────────────
  const uploadDocumentsNow = async (currentCommId, files) => {
    if (!currentCommId) throw new Error("Community profile is not ready yet. Please save Step 1 again.");
    if (!files || files.length === 0) return null;

    setUploading(true);
    setUploadMsg(`Uploading ${files.length} document(s)...`);

    try {
      const fd = new FormData();
      files.forEach((f) => fd.append("document", f));
      fd.append("doc_type", "id_bundle");

      const res = await communityService.uploadDocument(currentCommId, fd);
      const newDocs = res?.data?.documents || [];

      setSavedDocs((prev) => [...newDocs, ...prev]);
      setDocFiles([]);
      return newDocs;
    } finally {
      setUploading(false);
      setUploadMsg("");
    }
  };

  // ── Background image uploader (doesn't block step transition) ─
  const uploadFilesInBackground = (currentCommId, stepNum, files) => {
    setUploading(true);

    const tasks = [];

    // Step 3: upload offering images
    if (stepNum === 3 && files.offeringImages?.length > 0) {
      setUploadMsg(`Uploading ${files.offeringImages.reduce((n, o) => n + o.files.length, 0)} image(s)…`);
      for (const { offeringId, files: imageFiles } of files.offeringImages) {
        const fd = new FormData();
        imageFiles.forEach((f) => fd.append("images", f));
        tasks.push(communityService.uploadOfferingImages(currentCommId, offeringId, fd));
      }
    }

    if (tasks.length === 0) {
      setUploading(false);
      return;
    }

    Promise.all(tasks)
      .then(() => {
        setToast({ type: "success", message: "✓ Files uploaded successfully", key: Date.now() });
        // Clear imageFiles from offerings state
        if (stepNum === 3) {
          setOfferings((prev) => prev.map((o) => ({ ...o, imageFiles: [] })));
        }
      })
      .catch((err) => {
        setToast({ type: "error", message: "File upload failed — you can re-upload later.", key: Date.now() });
        console.error("Background upload error:", err);
      })
      .finally(() => {
        setUploading(false);
        setUploadMsg("");
      });
  };

  // ── Next handler ─────────────────────────────────────────────
  const handleNext = async () => {
    if (!validateStep()) return;
    setSaving(true);
    setErrors({});

    try {
      // ── Step 1 → create / update community ──────────────────
      if (step === 1) {
        const payload = {
          ...form,
          slug: form.name.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)+/g, ""),
        };
        if (commId) {
          await communityService.update(commId, payload);
        } else {
          const res = await communityService.create(payload);
          const created = res?.data?.community ?? res?.community;
          if (created?.id) setCommId(created.id);
          else throw new Error("Failed to create community");
        }
      }

      // ── Step 2 → save members, then upload required ID doc before continuing
      if (step === 2) {
        if (!commId) throw new Error("Community profile is not ready yet. Please save Step 1 again.");
        await communityService.saveMembers(commId, members);

        if (docFiles.length > 0) {
          await uploadDocumentsNow(commId, docFiles);
          setToast({ type: "success", message: "✓ ID documents uploaded and saved", key: Date.now() });
        }
      }

      // ── Step 3 → save offerings (fast), upload images in background
      if (step === 3) {
        const offeringPayload = offerings.map(({ category, custom_label, description }) => ({
          category, custom_label, description,
        }));
        const res = await communityService.saveOfferings(commId, offeringPayload);
        const savedOffs = res?.data?.offerings ?? [];

        // Collect any new image files to upload
        const offeringImages = [];
        savedOffs.forEach((saved, idx) => {
          const imageFiles = offerings[idx]?.imageFiles || [];
          if (imageFiles.length > 0) {
            offeringImages.push({ offeringId: saved.id, files: imageFiles });
          }
        });

        if (offeringImages.length > 0) {
          uploadFilesInBackground(commId, 3, { offeringImages });
        }
      }

      // ── Step 4 → record consent → show status screen ────────
      if (step === 4) {
        await communityService.recordConsent(commId);
        setCommunityData({ ...form, id: commId, consent_accepted_at: new Date().toISOString() });
        setSubmitted(true);
        setSaving(false);
        return;
      }

      setSaving(false);
      setStep((s) => s + 1);
      setToast({ type: "success", message: "✓ Saved", key: Date.now() });
    } catch (err) {
      setSaving(false);
      setUploading(false);
      setUploadMsg("");
      setToast({ type: "error", message: err?.response?.data?.message || err?.message || "Something went wrong.", key: Date.now() });
    }
  };

  // ── Loading state ───────────────────────────────────────────
  if (loading) {
    return (
      <div className="min-h-screen bg-[#F5F2EE] flex items-center justify-center">
        <div className="flex flex-col items-center gap-3 text-[#6B7C6E]">
          <Loader2 size={28} className="animate-spin" />
          <p className="text-sm font-medium">Loading your registration data…</p>
        </div>
      </div>
    );
  }

  // ── Submitted / Verification in Progress screen ─────────────
  if (submitted) {
    const submittedDate = communityData?.consent_accepted_at
      ? new Date(communityData.consent_accepted_at).toLocaleDateString("en-IN", {
          day: "numeric", month: "long", year: "numeric",
        })
      : new Date().toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" });

    const communityName = communityData?.name || form.name || "Your community";
    const status = communityData?.verification_status || communityData?.status || "pending";

    return (
      <div className="min-h-screen bg-[#F5F2EE] py-10 px-4">
        <style>{`
          @keyframes pulse-ring {
            0% { transform: scale(0.9); opacity: 0.7; }
            50% { transform: scale(1.15); opacity: 0; }
            100% { transform: scale(0.9); opacity: 0; }
          }
          @keyframes float {
            0%, 100% { transform: translateY(0); }
            50% { transform: translateY(-6px); }
          }
        `}</style>

        <div className="max-w-xl mx-auto">
          {/* Hero card */}
          <div className="rounded-3xl border border-[#E8E1D5] bg-white shadow-sm p-8 md:p-10 text-center">

            {/* Animated shield */}
            <div className="relative mx-auto w-24 h-24 mb-6">
              <div className="absolute inset-0 rounded-full bg-[#3E7A58]/10"
                style={{ animation: "pulse-ring 2s ease-in-out infinite" }} />
              <div className="absolute inset-2 rounded-full bg-[#3E7A58]/15"
                style={{ animation: "pulse-ring 2s ease-in-out infinite 0.3s" }} />
              <div className="relative flex items-center justify-center w-full h-full rounded-full bg-gradient-to-br from-[#3E7A58] to-[#1C3D2E] shadow-lg shadow-[#3E7A58]/30"
                style={{ animation: "float 3s ease-in-out infinite" }}>
                <Shield size={36} className="text-white" />
              </div>
            </div>

            <h1 className="text-2xl font-bold text-[#1A2820] mb-2">Verification in Progress</h1>
            <p className="text-sm text-[#6B7C6E] max-w-sm mx-auto leading-relaxed">
              <strong className="text-[#1A2820]">{communityName}</strong> has been submitted for security review. Our team will verify your details shortly.
            </p>

            {/* Status badge */}
            <div className="inline-flex items-center gap-2 mt-5 rounded-full px-4 py-2"
              style={{ background: status === "verified" ? "#D1FAE5" : status === "rejected" ? "#FEE2E2" : "#FEF3C7" }}>
              <span className="relative flex h-2.5 w-2.5">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full opacity-75"
                  style={{ background: status === "verified" ? "#10B981" : status === "rejected" ? "#EF4444" : "#F59E0B" }} />
                <span className="relative inline-flex rounded-full h-2.5 w-2.5"
                  style={{ background: status === "verified" ? "#10B981" : status === "rejected" ? "#EF4444" : "#F59E0B" }} />
              </span>
              <span className="text-xs font-bold uppercase tracking-wider"
                style={{ color: status === "verified" ? "#065F46" : status === "rejected" ? "#991B1B" : "#92400E" }}>
                {status === "verified" ? "Verified" : status === "rejected" ? "Rejected" : "Under Review"}
              </span>
            </div>

            {/* Submitted date */}
            <p className="mt-4 text-xs text-[#9A9285]">
              Submitted on {submittedDate}
            </p>
          </div>

          {/* What happens next timeline */}
          <div className="mt-6 rounded-3xl border border-[#E8E1D5] bg-white shadow-sm p-6 md:p-8">
            <h2 className="text-sm font-bold text-[#1A2820] uppercase tracking-wider mb-5">What happens next?</h2>

            <div className="space-y-0">
              {[
                {
                  icon: FileCheck, color: "#3E7A58", bg: "#D1FAE5",
                  title: "Application Received",
                  desc: "Your registration details, team info, ID documents, and offerings have been submitted.",
                  done: true,
                },
                {
                  icon: Search, color: "#D97706", bg: "#FEF3C7",
                  title: "Security Review",
                  desc: "Our security team will verify your identity documents and community details within 2–3 business days.",
                  done: false, active: true,
                },
                {
                  icon: Bell, color: "#6B7280", bg: "#F3F4F6",
                  title: "Notification",
                  desc: "You'll receive an email and dashboard notification once the review is complete.",
                  done: false,
                },
                {
                  icon: CheckCircle, color: "#6B7280", bg: "#F3F4F6",
                  title: "Go Live!",
                  desc: "Once approved, your community will be visible to travellers and you can start creating experiences.",
                  done: false,
                },
              ].map((item, idx, arr) => (
                <div key={idx} className="flex gap-4">
                  {/* Timeline line + dot */}
                  <div className="flex flex-col items-center">
                    <div className="flex items-center justify-center w-9 h-9 rounded-full shrink-0"
                      style={{ background: item.bg }}>
                      <item.icon size={16} style={{ color: item.color }} />
                    </div>
                    {idx < arr.length - 1 && (
                      <div className="w-0.5 flex-1 my-1 rounded-full"
                        style={{ background: item.done ? "#3E7A58" : "#E8E1D5" }} />
                    )}
                  </div>

                  {/* Content */}
                  <div className={`pb-5 ${idx === arr.length - 1 ? "pb-0" : ""}`}>
                    <p className={`text-sm font-semibold ${item.done ? "text-[#3E7A58]" : item.active ? "text-[#92400E]" : "text-[#6B7C6E]"}`}>
                      {item.title}
                      {item.done && <span className="ml-1.5 text-xs">✓</span>}
                      {item.active && <span className="ml-1.5 text-xs font-normal text-amber-500">(in progress)</span>}
                    </p>
                    <p className="text-xs text-[#9A9285] mt-0.5 leading-relaxed">{item.desc}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Action buttons */}
          <div className="mt-6 flex flex-col sm:flex-row gap-3">
            <Link to="/community"
              className="flex-1 flex items-center justify-center gap-2 rounded-xl px-5 py-3 text-sm font-semibold text-white transition-all hover:opacity-90"
              style={{ background: "#1C3D2E" }}>
              Go to Dashboard <ArrowRight size={14} />
            </Link>
            <Link to="/community/profile"
              className="flex-1 flex items-center justify-center gap-2 rounded-xl border border-[#E0D8CE] px-5 py-3 text-sm font-medium text-[#6B7C6E] hover:bg-white transition-all">
              Edit Profile
            </Link>
          </div>

          <p className="mt-4 text-center text-xs text-[#B8AFA4]">
            Questions? Contact support at bond-support@example.com
          </p>
        </div>
      </div>
    );
  }

  const isLastStep = step === 4;

  return (
    <div className="min-h-screen bg-[#F5F2EE] py-10 px-4">
      <style>{`
        @keyframes slideUp {
          from { opacity: 0; transform: translateY(12px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>

      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-[#1A2820]">Community Registration</h1>
          <p className="text-sm text-[#6B7C6E] mt-1">
            Complete all steps to submit your community for verification.
          </p>
        </div>

        <Stepper current={step} />

        {/* Background upload indicator */}
        {uploading && (
          <div className="mb-4 flex items-center gap-2.5 rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800">
            <Loader2 size={14} className="animate-spin shrink-0" />
            <span className="font-medium">{uploadMsg || "Uploading files in background…"}</span>
            <span className="text-xs text-amber-600 ml-auto">You can continue filling the next step</span>
          </div>
        )}

        {/* Step card */}
        <div className="rounded-3xl border border-[#E8E1D5] bg-white shadow-sm p-6 md:p-8">
          <div className="mb-6 pb-4 border-b border-[#F0EBE3]">
            <h2 className="text-lg font-bold text-[#1A2820]">
              Step {step} — {WIZARD_STEPS[step - 1]?.label}
            </h2>
            <p className="text-xs text-[#9A9285] mt-0.5">
              {step === 1 && "Basic information about your community"}
              {step === 2 && "List all team members and upload their ID documents"}
              {step === 3 && "Tell us what your community can offer to travellers"}
              {step === 4 && "Review and accept the terms before submitting"}
            </p>
          </div>

          {step === 1 && <Step1BasicInfo form={form} setForm={setForm} errors={errors} />}
          {step === 2 && (
            <Step2TeamAndDocs
              members={members} setMembers={setMembers}
              docFiles={docFiles} setDocFiles={setDocFiles}
              savedDocs={savedDocs}
              errors={errors}
            />
          )}
          {step === 3 && <Step3Offerings offerings={offerings} setOfferings={setOfferings} errors={errors} />}
          {step === 4 && <Step4Consent accepted={accepted} setAccepted={setAccepted} errors={errors} />}

          {/* Navigation */}
          <div className="flex items-center justify-between mt-8 pt-5 border-t border-[#F0EBE3]">
            <button
              type="button"
              onClick={() => setStep((s) => s - 1)}
              disabled={step === 1}
              className="flex items-center gap-2 rounded-xl border border-[#E0D8CE] px-5 py-2.5 text-sm font-medium text-[#6B7C6E] hover:bg-[#F5F2EE] transition-all disabled:opacity-30 disabled:cursor-not-allowed">
              <ChevronLeft size={15} /> Back
            </button>

            <div className="flex items-center gap-2">
              <span className="text-xs text-[#B8AFA4]">{step} of {WIZARD_STEPS.length}</span>
              <button
                type="button"
                onClick={handleNext}
                disabled={saving}
                className="flex items-center gap-2 rounded-xl px-6 py-2.5 text-sm font-semibold text-white transition-all hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed"
                style={{ background: "#1C3D2E" }}>
                {saving
                  ? <><Loader2 size={14} className="animate-spin" /> Saving…</>
                  : isLastStep
                    ? <><CheckCircle size={14} /> Submit for Review</>
                    : <>Next <ChevronRight size={14} /></>}
              </button>
            </div>
          </div>
        </div>

        {commId && step > 1 && (
          <p className="mt-3 text-center text-xs text-[#9A9285]">
            ✓ Progress is saved. You can close and resume anytime.
          </p>
        )}
      </div>

      {toast && <Toast key={toast.key} type={toast.type} message={toast.message} onDone={() => setToast(null)} />}
    </div>
  );
}

// ============================================================
// pages/community/CommunityRegistrationSteps.jsx
// Individual step components for the 4-step registration wizard
// ✓ Shows previously saved docs and images on resume
// ============================================================

import { useState, useRef } from "react";
import {
  Plus, Trash2, Upload, X, FileText, User, Phone,
  Briefcase, Home, Utensils, Music, Image, ExternalLink,
  CheckCircle,
} from "lucide-react";
import {
  OFFERING_CATEGORIES, EVENT_SUBTYPES, MEMBER_ROLES,
  CONSENT_TEXT, INDIAN_STATES, SEASONS,
} from "../../utils/verificationConstants";

// ─── Shared UI atoms ──────────────────────────────────────────
const Label = ({ children }) => (
  <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-1.5">
    {children}
  </label>
);

const Input = ({ error, ...props }) => (
  <input
    {...props}
    className={`w-full rounded-xl border ${error ? "border-red-400" : "border-[#E0D8CE] focus:border-[#3E7A58]"} bg-white px-3.5 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]`}
  />
);

const Textarea = ({ error, ...props }) => (
  <textarea
    rows={3}
    {...props}
    className={`w-full rounded-xl border ${error ? "border-red-400" : "border-[#E0D8CE] focus:border-[#3E7A58]"} bg-white px-3.5 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8] resize-none`}
  />
);

const Select = ({ options, placeholder = "Select…", ...props }) => (
  <select
    {...props}
    className="w-full rounded-xl border border-[#E0D8CE] focus:border-[#3E7A58] bg-white px-3.5 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:ring-2 focus:ring-[#3E7A58]/10 transition-all appearance-none"
  >
    <option value="">{placeholder}</option>
    {options.map((o) => <option key={o} value={o}>{o}</option>)}
  </select>
);

// ─── STEP 1 — Basic Info ──────────────────────────────────────
export function Step1BasicInfo({ form, setForm, errors }) {
  const set = (e) => setForm((f) => ({ ...f, [e.target.name]: e.target.value }));

  return (
    <div className="space-y-5">
      <p className="text-sm text-[#6B7C6E]">Tell us about your community. This information will be shown to travellers.</p>

      <div>
        <Label>Community Name *</Label>
        <Input name="name" value={form.name} onChange={set} placeholder="e.g. Ziro Valley Heritage Community" error={errors.name} />
        {errors.name && <p className="mt-1 text-xs text-red-500">{errors.name}</p>}
      </div>

      <div>
        <Label>Short Description</Label>
        <Input name="short_description" value={form.short_description} onChange={set} placeholder="One-line summary (max 500 chars)" />
      </div>

      <div>
        <Label>Full Description *</Label>
        <Textarea name="description" value={form.description} onChange={set} placeholder="Describe your community, culture, and what makes it special…" rows={5} error={errors.description} />
        {errors.description && <p className="mt-1 text-xs text-red-500">{errors.description}</p>}
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div>
          <Label>Village *</Label>
          <Input name="village" value={form.village} onChange={set} placeholder="e.g. Hong Village" error={errors.village} />
          {errors.village && <p className="mt-1 text-xs text-red-500">{errors.village}</p>}
        </div>
        <div>
          <Label>District *</Label>
          <Input name="district" value={form.district} onChange={set} placeholder="e.g. Lower Subansiri" error={errors.district} />
        </div>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div>
          <Label>State *</Label>
          <Select name="state" value={form.state} onChange={set} options={INDIAN_STATES} placeholder="Select state" />
          {errors.state && <p className="mt-1 text-xs text-red-500">{errors.state}</p>}
        </div>
        <div>
          <Label>Pincode</Label>
          <Input name="pincode" value={form.pincode} onChange={set} placeholder="e.g. 791120" />
        </div>
        <div>
          <Label>Best Season</Label>
          <Select name="best_visit_season" value={form.best_visit_season} onChange={set} options={SEASONS} placeholder="Select season" />
        </div>
      </div>
    </div>
  );
}

// ─── STEP 2 — Team Members + ID Upload ───────────────────────
const EMPTY_MEMBER = { full_name: "", phone: "", role: "", is_owner: false };

export function Step2TeamAndDocs({ members, setMembers, docFiles = [], setDocFiles, savedDocs = [], errors }) {
  const fileRef = useRef(null);

  const addMember = () => setMembers((m) => [...m, { ...EMPTY_MEMBER }]);
  const removeMember = (i) => setMembers((m) => m.filter((_, idx) => idx !== i));
  const updateMember = (i, field, value) =>
    setMembers((m) => m.map((mem, idx) => (idx === i ? { ...mem, [field]: value } : mem)));

  const handleFiles = (e) => {
    const files = Array.from(e.target.files || []);
    if (files.length > 0) {
      setDocFiles((prev) => [...prev, ...files].slice(0, 10)); // Max 10
    }
  };

  const removeDocFile = (idx) => {
    setDocFiles((prev) => prev.filter((_, i) => i !== idx));
  };

  const hasExistingDoc = savedDocs.length > 0;

  return (
    <div className="space-y-6">
      {/* Members */}
      <div>
        <div className="flex items-center justify-between mb-3">
          <div>
            <h3 className="text-sm font-semibold text-[#1A2820]">Team Members *</h3>
            <p className="text-xs text-[#9A9285] mt-0.5">Add all members who will be part of the community operations.</p>
          </div>
          <button type="button" onClick={addMember}
            className="flex items-center gap-1.5 rounded-xl bg-[#1C3D2E] px-3 py-2 text-xs font-semibold text-white hover:opacity-90 transition-all">
            <Plus size={13} /> Add Member
          </button>
        </div>

        {errors.members && <p className="mb-2 text-xs text-red-500">{errors.members}</p>}

        <div className="space-y-3">
          {members.map((m, i) => (
            <div key={i} className="rounded-2xl border border-[#E8E1D5] bg-[#FAFAF8] p-4 space-y-3">
              <div className="flex items-center justify-between">
                <span className="text-xs font-semibold text-[#9A9285] uppercase tracking-widest">Member {i + 1}</span>
                {members.length > 1 && (
                  <button type="button" onClick={() => removeMember(i)}
                    className="text-[#9A9285] hover:text-red-500 transition-colors">
                    <Trash2 size={14} />
                  </button>
                )}
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                <div>
                  <Label>Full Name *</Label>
                  <div className="relative">
                    <User size={14} className="absolute left-3 top-3 text-[#B8AFA4] pointer-events-none" />
                    <input value={m.full_name} onChange={(e) => updateMember(i, "full_name", e.target.value)}
                      placeholder="Full name"
                      className="w-full rounded-xl border border-[#E0D8CE] bg-white pl-8 pr-3 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]" />
                  </div>
                </div>
                <div>
                  <Label>Phone Number *</Label>
                  <div className="relative">
                    <Phone size={14} className="absolute left-3 top-3 text-[#B8AFA4] pointer-events-none" />
                    <input value={m.phone} onChange={(e) => updateMember(i, "phone", e.target.value)}
                      placeholder="+91 98765 43210"
                      className="w-full rounded-xl border border-[#E0D8CE] bg-white pl-8 pr-3 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]" />
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3 items-center">
                <div>
                  <Label>Role</Label>
                  <div className="relative">
                    <Briefcase size={14} className="absolute left-3 top-3 text-[#B8AFA4] pointer-events-none z-10" />
                    <select value={m.role} onChange={(e) => updateMember(i, "role", e.target.value)}
                      className="w-full rounded-xl border border-[#E0D8CE] bg-white pl-8 pr-3 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] transition-all appearance-none">
                      <option value="">Select role…</option>
                      {MEMBER_ROLES.map((r) => <option key={r} value={r}>{r}</option>)}
                    </select>
                  </div>
                </div>
                <div className="flex items-center gap-2 pt-5">
                  <input type="checkbox" id={`owner_${i}`} checked={m.is_owner}
                    onChange={(e) => updateMember(i, "is_owner", e.target.checked)}
                    className="h-4 w-4 rounded border-[#E0D8CE] text-[#3E7A58] focus:ring-[#3E7A58]" />
                  <label htmlFor={`owner_${i}`} className="text-xs text-[#4A5E52] cursor-pointer">This is the community owner</label>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Previously uploaded documents */}
      {hasExistingDoc && (
        <div>
          <h3 className="text-sm font-semibold text-[#1A2820] mb-2">✓ Previously Uploaded Documents</h3>
          <div className="space-y-2">
            {savedDocs.map((doc) => (
              <div
                key={doc.id}
                className="flex items-center gap-3 rounded-xl border border-emerald-200 bg-emerald-50 px-4 py-3"
              >
                <CheckCircle size={16} className="text-emerald-600 shrink-0" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-emerald-800 truncate">
                    {doc.doc_type === "id_bundle" ? "ID Document" : doc.doc_type}
                  </p>
                  <p className="text-xs text-emerald-600">
                    Uploaded {new Date(doc.created_at).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })}
                  </p>
                </div>
                <a
                  href={doc.file_url}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="flex items-center gap-1 text-xs font-medium text-emerald-700 hover:underline"
                  onClick={(e) => e.stopPropagation()}
                >
                  View <ExternalLink size={11} />
                </a>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Document Upload */}
      <div>
        <h3 className="text-sm font-semibold text-[#1A2820] mb-1">
          {hasExistingDoc ? "Upload More ID Documents (optional)" : "ID Documents (Photos or PDF) *"}
        </h3>
        <p className="text-xs text-[#9A9285] mb-3">
          {hasExistingDoc
            ? "You can upload additional ID photos or documents for new team members."
            : "Upload photos or PDF copies of all team members' government-issued IDs (Aadhaar, PAN, Passport, etc.)."}
        </p>

        {errors.doc && <p className="mb-2 text-xs text-red-500">{errors.doc}</p>}

        <div className="space-y-3">
          {/* List of pending files */}
          {docFiles.map((file, idx) => (
            <div key={idx} className="flex items-center gap-3 rounded-xl border border-[#3E7A58] bg-[#EEF5F1] px-4 py-3">
              <FileText size={18} className="text-[#3E7A58] shrink-0" />
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-[#1C3D2E] truncate">{file.name}</p>
                <p className="text-[10px] text-[#6B7C6E]">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
              </div>
              <button type="button" onClick={() => removeDocFile(idx)}
                className="text-red-500 hover:text-red-700 transition-colors">
                <X size={14} />
              </button>
            </div>
          ))}

          {/* Upload trigger */}
          {docFiles.length < 10 && (
            <div
              onClick={() => fileRef.current?.click()}
              className="flex flex-col items-center justify-center gap-3 rounded-2xl border-2 border-dashed border-[#D4C9BB] bg-[#F5F2EE] p-8 cursor-pointer transition-all hover:border-[#3E7A58] hover:bg-[#EEF5F1]">
              <Upload size={28} className="text-[#B8AFA4]" />
              <div className="text-center">
                <p className="text-sm font-medium text-[#6B7C6E]">Click to upload IDs</p>
                <p className="text-xs text-[#9A9285] mt-0.5">Select multiple JPG, PNG or PDF · max 10 MB each</p>
              </div>
            </div>
          )}
        </div>
        <input ref={fileRef} type="file" multiple accept=".pdf,image/*" className="hidden" onChange={handleFiles} />
      </div>
    </div>
  );
}

// ─── STEP 3 — Offerings ───────────────────────────────────────
const EMPTY_OFFERING = { category: "", custom_label: "", description: "", imageFiles: [], savedImages: [] };

export function Step3Offerings({ offerings, setOfferings, errors }) {
  const imageRefs = useRef({});

  const addOffering = () => setOfferings((o) => [...o, { ...EMPTY_OFFERING }]);
  const removeOffering = (i) => setOfferings((o) => o.filter((_, idx) => idx !== i));
  const updateOffering = (i, field, value) =>
    setOfferings((o) => o.map((item, idx) => (idx === i ? { ...item, [field]: value } : item)));

  const handleImages = (i, files) => {
    const arr = Array.from(files).slice(0, 5);
    const current = offerings[i].imageFiles || [];
    const savedCount = (offerings[i].savedImages || []).length;
    const maxNew = 5 - savedCount;
    updateOffering(i, "imageFiles", [...current, ...arr].slice(0, maxNew));
  };

  const removeImage = (offeringIdx, imgIdx) =>
    updateOffering(offeringIdx, "imageFiles",
      offerings[offeringIdx].imageFiles.filter((_, idx) => idx !== imgIdx));

  const getCategoryMeta = (id) => OFFERING_CATEGORIES.find((c) => c.id === id);

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm text-[#6B7C6E]">
            Add what your community offers. For each offering, provide a description and original photos.
          </p>
        </div>
        <button type="button" onClick={addOffering}
          className="flex items-center gap-1.5 rounded-xl bg-[#1C3D2E] px-3 py-2 text-xs font-semibold text-white hover:opacity-90 transition-all">
          <Plus size={13} /> Add Offering
        </button>
      </div>

      {/* Category quick-pick */}
      <div>
        <Label>Quick Add by Category</Label>
        <div className="flex flex-wrap gap-2">
          {OFFERING_CATEGORIES.map((cat) => (
            <button key={cat.id} type="button"
              onClick={() => setOfferings((o) => [...o, { ...EMPTY_OFFERING, category: cat.id }])}
              className="flex items-center gap-2 rounded-xl border border-[#E0D8CE] bg-white px-3 py-2 text-xs font-medium text-[#4A5E52] hover:border-[#3E7A58] hover:bg-[#EEF5F1] transition-all">
              {cat.icon} {cat.label}
            </button>
          ))}
          {EVENT_SUBTYPES.map((sub) => (
            <button key={sub.id} type="button"
              onClick={() => setOfferings((o) => [...o, { ...EMPTY_OFFERING, category: "event", custom_label: sub.label }])}
              className="flex items-center gap-2 rounded-xl border border-[#E0D8CE] bg-white px-3 py-2 text-xs font-medium text-[#4A5E52] hover:border-[#3E7A58] hover:bg-[#EEF5F1] transition-all">
              {sub.icon} {sub.label}
            </button>
          ))}
        </div>
      </div>

      {errors.offerings && <p className="text-xs text-red-500">{errors.offerings}</p>}

      {offerings.length === 0 && (
        <div className="rounded-2xl border border-dashed border-[#D4C9BB] bg-[#F5F2EE] p-8 text-center">
          <p className="text-sm text-[#9A9285]">No offerings added yet. Use "Quick Add" above or click "Add Offering".</p>
        </div>
      )}

      {offerings.map((off, i) => {
        const meta = getCategoryMeta(off.category);
        const saved = off.savedImages || [];
        const newFiles = off.imageFiles || [];
        const totalImages = saved.length + newFiles.length;

        return (
          <div key={i} className="rounded-2xl border border-[#E8E1D5] bg-[#FAFAF8] p-5 space-y-4">
            <div className="flex items-center justify-between">
              <span className="flex items-center gap-2 text-sm font-semibold text-[#1A2820]">
                {meta?.icon || "🎁"} {meta?.label || "Offering"} {i + 1}
                {off.custom_label && <span className="text-xs text-[#6B7C6E]">({off.custom_label})</span>}
              </span>
              <button type="button" onClick={() => removeOffering(i)}
                className="text-[#9A9285] hover:text-red-500 transition-colors"><Trash2 size={14} /></button>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Category *</Label>
                <select value={off.category} onChange={(e) => updateOffering(i, "category", e.target.value)}
                  className="w-full rounded-xl border border-[#E0D8CE] bg-white px-3 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] transition-all appearance-none">
                  <option value="">Select…</option>
                  {OFFERING_CATEGORIES.map((c) => <option key={c.id} value={c.id}>{c.icon} {c.label}</option>)}
                </select>
              </div>
              <div>
                <Label>Custom Label / Sub-type</Label>
                <Input value={off.custom_label} onChange={(e) => updateOffering(i, "custom_label", e.target.value)}
                  placeholder="e.g. Dancing, Crafting, Farming…" />
              </div>
            </div>

            <div>
              <Label>Description</Label>
              <Textarea value={off.description}
                onChange={(e) => updateOffering(i, "description", e.target.value)}
                placeholder="Describe this offering in detail — what guests will experience, duration, what's included…" />
            </div>

            {/* Images: show saved images from server + new file uploads */}
            <div>
              <Label>Photos ({totalImages}/5)</Label>
              <div className="flex flex-wrap gap-2">
                {/* Saved images from server */}
                {saved.map((img) => (
                  <div key={img.id} className="relative h-20 w-20 rounded-xl overflow-hidden border-2 border-emerald-300">
                    <img src={img.image_url} alt={img.caption || "Saved"} className="h-full w-full object-cover" />
                    <div className="absolute bottom-0 inset-x-0 bg-emerald-600/80 text-white text-center text-[8px] py-0.5 font-semibold">
                      Saved ✓
                    </div>
                  </div>
                ))}

                {/* New file uploads (not yet on server) */}
                {newFiles.map((file, imgIdx) => (
                  <div key={`new-${imgIdx}`} className="relative h-20 w-20 rounded-xl overflow-hidden border border-[#E0D8CE]">
                    <img src={URL.createObjectURL(file)} alt="" className="h-full w-full object-cover" />
                    <button type="button" onClick={() => removeImage(i, imgIdx)}
                      className="absolute top-0.5 right-0.5 rounded-full bg-black/60 p-0.5 text-white hover:bg-red-500 transition-colors">
                      <X size={10} />
                    </button>
                  </div>
                ))}

                {/* Add button */}
                {totalImages < 5 && (
                  <div onClick={() => imageRefs.current[i]?.click()}
                    className="flex h-20 w-20 cursor-pointer flex-col items-center justify-center gap-1 rounded-xl border-2 border-dashed border-[#D4C9BB] bg-[#F5F2EE] hover:border-[#3E7A58] transition-all">
                    <Image size={16} className="text-[#B8AFA4]" />
                    <span className="text-[10px] text-[#9A9285]">Add</span>
                  </div>
                )}
                <input ref={(el) => (imageRefs.current[i] = el)} type="file" multiple accept="image/*"
                  className="hidden" onChange={(e) => handleImages(i, e.target.files)} />
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ─── STEP 4 — Consent ─────────────────────────────────────────
export function Step4Consent({ accepted, setAccepted, errors }) {
  return (
    <div className="space-y-5">
      <div>
        <h3 className="text-sm font-semibold text-[#1A2820] mb-1">Terms & Conditions</h3>
        <p className="text-xs text-[#9A9285]">Please read the following carefully before submitting.</p>
      </div>

      <div className="rounded-2xl border border-[#E8E1D5] bg-[#FAFAF8] p-5 max-h-60 overflow-y-auto">
        <pre className="whitespace-pre-wrap text-xs text-[#4A5E52] leading-relaxed font-sans">{CONSENT_TEXT}</pre>
      </div>

      <label className={`flex items-start gap-3 rounded-2xl border-2 p-4 cursor-pointer transition-all ${accepted ? "border-[#3E7A58] bg-[#EEF5F1]" : "border-[#E0D8CE] bg-white"}`}>
        <input type="checkbox" checked={accepted} onChange={(e) => setAccepted(e.target.checked)}
          className="mt-0.5 h-4 w-4 shrink-0 rounded border-[#C4B8A8] text-[#3E7A58] focus:ring-[#3E7A58]" />
        <div>
          <p className="text-sm font-semibold text-[#1A2820]">I accept the Terms & Conditions</p>
          <p className="text-xs text-[#6B7C6E] mt-0.5">
            I confirm that all information provided is accurate and I agree to the platform's guidelines.
          </p>
        </div>
      </label>

      {errors.consent && <p className="text-xs text-red-500">{errors.consent}</p>}

      {accepted && (
        <div className="flex items-start gap-3 rounded-2xl border border-emerald-200 bg-emerald-50 p-4">
          <span className="text-lg">✅</span>
          <div>
            <p className="text-sm font-semibold text-emerald-800">Ready to submit!</p>
            <p className="text-xs text-emerald-700 mt-0.5">
              Your community will be submitted for security review. You'll be notified within 2–3 business days.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { TrendingUp, Clock, CheckCircle, AlertCircle, ArrowDownCircle } from "lucide-react";
import PageShell from "../PageShell";
import communityService from "../../services/communityService";
import bookingService from "../../services/bookingService";

const fmt = (n) => n != null ? `₹${Number(n).toLocaleString("en-IN")}` : "₹0";
const fmtDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" }) : "—";

function MetricCard({ label, value, icon: Icon, color, bg, loading }) {
  return (
    <div className="bg-white rounded-2xl border border-[#E8E1D5] p-5 flex flex-col gap-3">
      <div className="flex items-center justify-between">
        <p className="text-xs font-semibold uppercase tracking-widest text-[#9A9285]">{label}</p>
        <span className="flex h-8 w-8 items-center justify-center rounded-xl" style={{ background: bg }}>
          <Icon size={15} style={{ color }} />
        </span>
      </div>
      {loading
        ? <div className="h-9 w-28 animate-pulse rounded-lg bg-[#E8E1D5]" />
        : <p className="text-[2rem] font-bold tracking-tight text-[#1A2820]" style={{ fontFamily: "'Playfair Display', serif" }}>{value}</p>
      }
    </div>
  );
}

const STATUS_MAP = {
  pending:   { color: "#C8883A", bg: "#FDF3E7" },
  confirmed: { color: "#3E7A58", bg: "#EAF3EE" },
  completed: { color: "#1C3D2E", bg: "#DFF0E7" },
  rejected:  { color: "#B94040", bg: "#FAEAEA" },
  cancelled: { color: "#9A9285", bg: "#F0EBE3" },
};

export default function Earnings() {
  const [stats,    setStats]    = useState(null);
  const [bookings, setBookings] = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [error,    setError]    = useState(null);

  useEffect(() => {
    Promise.all([
      communityService.getStats(),
      bookingService.getCommunityBookings(),
    ])
      .then(([sRes, bRes]) => {
        setStats(sRes?.data ?? sRes);
        const list = Array.isArray(bRes?.data?.bookings) ? bRes.data.bookings : (Array.isArray(bRes?.bookings) ? bRes.bookings : (Array.isArray(bRes) ? bRes : []));
        setBookings(list);
      })
      .catch(err => setError(err.message))
      .finally(() => setLoading(false));
  }, []);

  const s = stats ?? {};

  // Derive payout breakdown from stats or bookings
  // Derive payout breakdown dynamically from local bookings state
  const pendingAmount = Array.isArray(bookings)
    ? bookings.filter(b => b.status === 'pending').reduce((acc, b) => acc + Number(b.total_amount || 0), 0)
    : 0;

  const paidOut = Array.isArray(bookings)
    ? bookings.filter(b => b.status === 'completed').reduce((acc, b) => acc + Number(b.total_amount || 0), 0)
    : 0;

  const availableAmount = Array.isArray(bookings)
    ? bookings.filter(b => b.status === 'confirmed').reduce((acc, b) => acc + Number(b.total_amount || 0), 0)
    : 0;

  return (
    <PageShell title="Earnings" subtitle="Revenue and payout summary">

      {error && (
        <div className="mb-6 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-600 flex items-center gap-2">
          <AlertCircle size={14} />{error}
        </div>
      )}

      {/* ── Metric cards ── */}
      <div className="grid gap-4 sm:grid-cols-3 mb-8">
        <MetricCard label="Available"  value={fmt(availableAmount)} icon={CheckCircle}     color="#3E7A58" bg="#EAF3EE" loading={loading} />
        <MetricCard label="Pending"    value={fmt(pendingAmount)}   icon={Clock}           color="#C8883A" bg="#FDF3E7" loading={loading} />
        <MetricCard label="Paid out"   value={fmt(paidOut)}         icon={ArrowDownCircle} color="#1C3D2E" bg="#DFF0E7" loading={loading} />
      </div>

      {/* ── Earnings ledger ── */}
      <div className="bg-white rounded-2xl border border-[#E8E1D5] overflow-hidden">
        <div className="px-5 py-4 border-b border-[#F0EBE3]">
          <h2 className="text-sm font-semibold text-[#1A2820]">Transaction History</h2>
        </div>

        {loading ? (
          <div className="p-5 space-y-3">
            {[1,2,3,4].map(i => <div key={i} className="h-12 animate-pulse rounded-xl bg-[#F5F2EE]" />)}
          </div>
        ) : bookings.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 text-center">
            <TrendingUp size={32} className="text-[#D4C9BB] mb-3" />
            <p className="text-sm font-medium text-[#9A9285]">No transactions yet</p>
            <p className="text-xs text-[#B8AFA4] mt-1">Completed bookings will appear here</p>
          </div>
        ) : (
          <div className="divide-y divide-[#F5F2EE]">
            {bookings.map(b => {
              const meta = STATUS_MAP[b.status] ?? STATUS_MAP.pending;
              return (
                <div key={b.id} className="flex items-center justify-between gap-4 px-5 py-4">
                  <div className="min-w-0 flex-1">
                    <p className="truncate text-sm font-medium text-[#1A2820]">
                      {b.experience_title ?? b.title ?? "Booking"}
                    </p>
                    <p className="mt-0.5 text-xs text-[#9A9285]">
                      {fmtDate(b.date)}
                      {b.tourist_name ? ` · ${b.tourist_name}` : ""}
                      {b.guests ? ` · ${b.guests} guest${b.guests > 1 ? "s" : ""}` : ""}
                    </p>
                  </div>
                  <div className="flex shrink-0 items-center gap-3">
                    <span className="text-sm font-bold text-[#1C3D2E]">{fmt(b.total_amount)}</span>
                    <span className="rounded-full px-2.5 py-1 text-xs font-semibold"
                      style={{ background: meta.bg, color: meta.color }}>
                      {b.status}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </PageShell>
  );
}

import { useState, useEffect, useCallback } from "react";
import { CheckCircle, XCircle, Clock, AlertCircle, Users, Calendar, IndianRupee, Search, Filter, FileText } from "lucide-react";
import PageShell from "../PageShell";
import bookingService from "../../services/bookingService";

const fmt = (n) => n != null ? `₹${Number(n).toLocaleString("en-IN")}` : "—";
const fmtDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" }) : "—";

const STATUS_META = {
  pending:   { label: "Pending",   color: "#C8883A", bg: "#FDF3E7", Icon: Clock },
  confirmed: { label: "Confirmed", color: "#3E7A58", bg: "#EAF3EE", Icon: CheckCircle },
  completed: { label: "Completed", color: "#1C3D2E", bg: "#DFF0E7", Icon: CheckCircle },
  rejected:  { label: "Rejected",  color: "#B94040", bg: "#FAEAEA", Icon: XCircle },
  cancelled: { label: "Cancelled", color: "#9A9285", bg: "#F0EBE3", Icon: AlertCircle },
};

function StatusBadge({ status }) {
  const m = STATUS_META[status] ?? STATUS_META.pending;
  return (
    <span className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-semibold"
      style={{ background: m.bg, color: m.color }}>
      <m.Icon size={11} />{m.label}
    </span>
  );
}

function ActionButton({ onClick, label, color, bg, loading, icon: Icon }) {
  return (
    <button onClick={onClick} disabled={loading}
      className="inline-flex items-center gap-1.5 rounded-xl px-3 py-1.5 text-xs font-semibold transition-all hover:opacity-80 disabled:opacity-40"
      style={{ background: bg, color }}>
      {loading
        ? <span className="h-3 w-3 animate-spin rounded-full border border-current border-t-transparent" />
        : <Icon size={12} />}
      {label}
    </button>
  );
}

function BookingRow({ booking, onAction }) {
  const [acting, setActing] = useState(null);

  const doAction = async (actionFn, key) => {
    setActing(key);
    try { await actionFn(); }
    catch (err) { console.error(err); }
    finally { setActing(null); }
  };

  const isPending   = booking.status === "pending";
  const isConfirmed = booking.status === "confirmed";

  return (
    <div className="rounded-2xl border border-[#E8E1D5] bg-white p-4 flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
      {/* Info */}
      <div className="min-w-0 flex-1 space-y-1">
        <div className="flex items-start gap-2 flex-wrap">
          <p className="text-sm font-semibold text-[#1A2820]">
            {booking.experience_title ?? booking.title ?? "Booking"}
          </p>
          <StatusBadge status={booking.status} />
        </div>
        <div className="flex flex-wrap gap-x-4 gap-y-1 text-xs text-[#9A9285]">
          <span className="flex items-center gap-1"><Calendar size={11} />{fmtDate(booking.booking_date || booking.date)}</span>
          {(booking.num_guests || booking.guests) && <span className="flex items-center gap-1"><Users size={11} />{booking.num_guests || booking.guests} guest{(booking.num_guests || booking.guests) > 1 ? "s" : ""}</span>}
          {booking.total_amount && <span className="flex items-center gap-1"><IndianRupee size={11} />{fmt(booking.total_amount)}</span>}
          {booking.tourist_name && <span>{booking.tourist_name}</span>}
        </div>
        {booking.notes && (
          <p className="text-xs text-[#9A9285] italic mt-1">"{booking.notes}"</p>
        )}

        {/* ID Proof Visibility for Community */}
        {booking.id_document_url && (
          <div className="mt-2 text-xs border-t border-[#F0EBE3] pt-2 flex items-center gap-1.5 text-[#3E7A58]">
            <FileText size={12} />
            <a href={booking.id_document_url} target="_blank" rel="noopener noreferrer" className="font-medium underline hover:text-[#1C3D2E] transition-colors">
              View Tourist ID Proof
            </a>
          </div>
        )}
      </div>

      {/* Actions */}
      {(isPending || isConfirmed) && (
        <div className="flex flex-wrap gap-2 shrink-0">
          {isPending && (
            <>
              <ActionButton
                label="Confirm" color="#3E7A58" bg="#EAF3EE" icon={CheckCircle}
                loading={acting === "confirm"}
                onClick={() => doAction(() => bookingService.confirm(booking.id).then(() => onAction(booking.id, "confirmed")), "confirm")}
              />
              <ActionButton
                label="Reject" color="#B94040" bg="#FAEAEA" icon={XCircle}
                loading={acting === "reject"}
                onClick={() => doAction(() => bookingService.reject(booking.id).then(() => onAction(booking.id, "rejected")), "reject")}
              />
            </>
          )}
          {isConfirmed && (
            <ActionButton
              label="Mark complete" color="#1C3D2E" bg="#DFF0E7" icon={CheckCircle}
              loading={acting === "complete"}
              onClick={() => doAction(() => bookingService.complete(booking.id).then(() => onAction(booking.id, "completed")), "complete")}
            />
          )}
        </div>
      )}
    </div>
  );
}

const FILTERS = ["all", "pending", "confirmed", "completed", "rejected", "cancelled"];

export default function ManageBookings() {
  const [bookings, setBookings] = useState([]);
  const [filter,   setFilter]   = useState("all");
  const [search,   setSearch]   = useState("");
  const [loading,  setLoading]  = useState(true);
  const [error,    setError]    = useState(null);

  useEffect(() => {
    bookingService.getCommunityBookings()
      .then(res => {
        const list = res?.data?.bookings ?? res?.bookings ?? res ?? [];
        setBookings(Array.isArray(list) ? list : []);
      })
      .catch(err => setError(err.message))
      .finally(() => setLoading(false));
  }, []);

  // Optimistic status update
  const handleAction = useCallback((id, newStatus) => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status: newStatus } : b));
  }, []);

  const visible = bookings.filter(b => {
    const matchFilter = filter === "all" || b.status === filter;
    const matchSearch = !search || (b.experience_title ?? b.title ?? "").toLowerCase().includes(search.toLowerCase())
      || (b.tourist_name ?? "").toLowerCase().includes(search.toLowerCase());
    return matchFilter && matchSearch;
  });

  const counts = FILTERS.reduce((acc, f) => {
    acc[f] = f === "all" ? bookings.length : bookings.filter(b => b.status === f).length;
    return acc;
  }, {});

  return (
    <PageShell title="Manage Bookings" subtitle="Approve, prepare, and track guest visits">

      {error && (
        <div className="mb-6 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-600 flex items-center gap-2">
          <AlertCircle size={14} />{error}
        </div>
      )}

      {/* ── Search + filter bar ── */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center mb-6">
        <div className="relative flex-1 max-w-xs">
          <Search size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-[#B8AFA4]" />
          <input type="text" value={search} onChange={e => setSearch(e.target.value)}
            placeholder="Search bookings…"
            className="w-full rounded-xl border border-[#E0D8CE] bg-white pl-9 pr-4 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]"
          />
        </div>
        <div className="flex flex-wrap gap-2">
          {FILTERS.map(f => (
            <button key={f} onClick={() => setFilter(f)}
              className="rounded-xl px-3 py-2 text-xs font-semibold capitalize transition-all"
              style={{
                background: filter === f ? "#1C3D2E" : "#F0EBE3",
                color:      filter === f ? "#F2EDE4"  : "#7A9285",
              }}>
              {f} {counts[f] > 0 && <span className="ml-1 opacity-70">({counts[f]})</span>}
            </button>
          ))}
        </div>
      </div>

      {/* ── List ── */}
      {loading ? (
        <div className="space-y-3">
          {[1,2,3].map(i => <div key={i} className="h-24 animate-pulse rounded-2xl bg-[#E8E1D5]" />)}
        </div>
      ) : visible.length === 0 ? (
        <div className="flex flex-col items-center justify-center rounded-2xl border border-[#E8E1D5] bg-white py-20 text-center">
          <Calendar size={32} className="text-[#D4C9BB] mb-3" />
          <p className="text-sm font-medium text-[#9A9285]">
            {bookings.length === 0 ? "No bookings yet" : "No bookings match this filter"}
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {visible.map(b => (
            <BookingRow key={b.id} booking={b} onAction={handleAction} />
          ))}
        </div>
      )}
    </PageShell>
  );
}

import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { Plus, Pencil, Trash2, Upload, CheckCircle, AlertCircle, MapPin, Clock, Tag, IndianRupee, X } from "lucide-react";
import PageShell from "../PageShell";
import experienceService from "../../services/experienceService";
import uploadService, { UPLOAD_FOLDERS } from "../../services/uploadService";

// ─── Field ────────────────────────────────────────────────────
function Field({ label, name, value, onChange, icon: Icon, type = "text", placeholder = "", required = false }) {
  return (
    <div className="group">
      <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">
        {label}{required && <span className="text-red-400 ml-1">*</span>}
      </label>
      <div className="relative">
        {Icon && <Icon size={14} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-[#B8AFA4] group-focus-within:text-[#3E7A58] transition-colors pointer-events-none" />}
        <input type={type} name={name} value={value} onChange={onChange} placeholder={placeholder} required={required}
          className="w-full rounded-xl border border-[#E0D8CE] bg-white py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]"
          style={{ paddingLeft: Icon ? "2.5rem" : "1rem", paddingRight: "1rem" }}
        />
      </div>
    </div>
  );
}

// ─── Cover uploader ───────────────────────────────────────────
function CoverUploader({ experienceId, currentUrl, currentImages = [], onUploaded }) {
  const [uploading, setUploading] = useState(false);
  const [preview,   setPreview]   = useState(currentUrl || "");
  const [gallery, setGallery] = useState(currentImages);
  const inputRef = useRef(null);

  const handleFile = async (e) => {
    const selected = Array.from(e.target.files || []).slice(0, 5);
    if (!selected.length) return;
    const previewUrls = selected.map((file) => ({ image_url: URL.createObjectURL(file) }));
    setPreview(previewUrls[0].image_url);
    setGallery((prev) => [...previewUrls, ...(prev || [])].slice(0, 5));
    setUploading(true);
    try {
      if (experienceId) {
        const fd = new FormData();
        selected.forEach((file) => fd.append("images", file));
        const res = await experienceService.uploadImages(experienceId, fd);
        const images = res?.data?.images ?? res?.images ?? [];
        const url = images[0]?.image_url;
        if (url) onUploaded(url);
        if (images.length) {
          setGallery((prev) => [...images, ...(prev || []).filter((image) => !image.image_url?.startsWith("blob:"))].slice(0, 5));
        }
      } else {
        const res = await uploadService.uploadImages(selected, UPLOAD_FOLDERS.EXPERIENCE);
        const images = res?.data?.images ?? res?.images ?? [];
        const url = images[0]?.url;
        if (url) onUploaded(url);
      }
    } catch (err) {
      console.error("Experience image upload failed:", err);
    } finally {
      setUploading(false);
      e.target.value = "";
    }
  };

  return (
    <div>
      <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">Experience Photos</label>
      <div onClick={() => inputRef.current?.click()}
        className="relative flex h-36 cursor-pointer items-center justify-center overflow-hidden rounded-xl border-2 border-dashed border-[#D4C9BB] bg-[#F5F2EE] transition-all hover:border-[#3E7A58] hover:bg-[#EEF5F1]">
        {preview
          ? <img src={preview} alt="Cover" className="h-full w-full object-cover" />
          : <div className="flex flex-col items-center gap-1.5 text-[#9A9285]">
              <Upload size={20} />
              <p className="text-xs font-medium">Upload up to 5 photos</p>
              <p className="text-[10px] opacity-60">1920×1080 recommended for best quality</p>
            </div>
        }
        {uploading && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/30">
            <span className="h-5 w-5 animate-spin rounded-full border-2 border-white/30 border-t-white" />
          </div>
        )}
      </div>
      {gallery.length > 0 && (
        <div className="mt-3 grid grid-cols-4 gap-2">
          {gallery.slice(0, 5).map((image, index) => (
            <img
              key={`${image.id || image.image_url}-${index}`}
              src={image.image_url}
              alt={`Experience ${index + 1}`}
              className="h-14 w-full rounded-lg object-cover"
            />
          ))}
        </div>
      )}
      <input ref={inputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleFile} />
    </div>
  );
}

// ─── Toast ────────────────────────────────────────────────────
function Toast({ type, message, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 3200); return () => clearTimeout(t); }, []);
  const ok = type === "success";
  return (
    <div className="fixed bottom-6 right-6 z-50 flex items-center gap-2.5 rounded-xl px-4 py-3 text-sm font-medium shadow-xl"
      style={{ background: ok ? "#1C3D2E" : "#5C1A1A", color: "#F2EDE4" }}>
      {ok ? <CheckCircle size={15} /> : <AlertCircle size={15} />}
      {message}
    </div>
  );
}

const EMPTY_FORM = { title: "", description: "", location: "", price: "", duration: "", category: "" };

// ─── Experience Form Panel ────────────────────────────────────
function ExperienceFormPanel({ editing, onSaved, onCancel }) {
  const [form,     setForm]     = useState(editing ? {
    title:       editing.title        ?? "",
    description: editing.description  ?? "",
    location:    editing.location     ?? "",
    price:       editing.price        ?? "",
    duration:    editing.duration     ?? "",
    category:    editing.category     ?? "",
  } : EMPTY_FORM);
  const [coverUrl, setCoverUrl] = useState(editing?.cover_image_url ?? editing?.cover_url ?? "");
  const [saving,   setSaving]   = useState(false);

  const update = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        price: form.price ? Number(form.price) : undefined,
        cover_url: coverUrl || undefined,
      };
      let saved;
      if (editing?.id) {
        const res = await experienceService.update(editing.id, payload);
        saved = res?.data?.experience ?? res?.experience ?? { ...editing, ...payload };
      } else {
        const res = await experienceService.create(payload);
        saved = res?.data?.experience ?? res?.experience ?? payload;
      }
      onSaved(saved, !!editing);
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-2xl border border-[#E8E1D5] p-5 space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-sm font-semibold text-[#1A2820]">{editing ? "Edit experience" : "New experience"}</h2>
        <button type="button" onClick={onCancel} className="text-[#9A9285] hover:text-[#1A2820] transition-colors">
          <X size={16} />
        </button>
      </div>

      <CoverUploader experienceId={editing?.id} currentUrl={coverUrl} currentImages={editing?.images || []} onUploaded={setCoverUrl} />

      <Field label="Title"       name="title"       value={form.title}       onChange={update} icon={Tag}        placeholder="e.g. Traditional weaving workshop" required />
      <Field label="Location"    name="location"    value={form.location}    onChange={update} icon={MapPin}     placeholder="e.g. Nagaland" />
      <Field label="Price (₹)"   name="price"       value={form.price}       onChange={update} icon={IndianRupee} type="number" placeholder="1800" />
      <Field label="Duration"    name="duration"    value={form.duration}    onChange={update} icon={Clock}      placeholder="e.g. 3 hours" />
      <Field label="Category"    name="category"    value={form.category}    onChange={update} icon={Tag}        placeholder="e.g. Craft, Food, Culture" />

      <div className="group">
        <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">Description</label>
        <textarea name="description" value={form.description} onChange={update} rows={4}
          placeholder="Describe the experience in detail…"
          className="w-full rounded-xl border border-[#E0D8CE] bg-white px-4 py-3 text-sm text-[#1A2820] resize-none focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]"
        />
      </div>

      <div className="flex gap-2 pt-1">
        <button type="submit" disabled={saving || !form.title.trim()}
          className="flex items-center gap-2 rounded-xl px-5 py-2.5 text-sm font-semibold text-[#F2EDE4] hover:opacity-90 disabled:opacity-50 transition-all"
          style={{ background: "#1C3D2E" }}>
          {saving
            ? <span className="h-4 w-4 animate-spin rounded-full border-2 border-white/30 border-t-white" />
            : <CheckCircle size={14} />}
          {editing ? "Save changes" : "Create"}
        </button>
        {editing && (
          <button type="button" onClick={onCancel}
            className="rounded-xl border border-[#E0D8CE] px-4 py-2.5 text-sm font-medium text-[#9A9285] hover:bg-[#F5F2EE] transition-all">
            Cancel
          </button>
        )}
      </div>
    </form>
  );
}

// ─── Experience Card ──────────────────────────────────────────
function ExperienceCard({ exp, onEdit, onDelete, deleting }) {
  const navigate = useNavigate();
  return (
    <div
      onClick={() => navigate(`/community/experience/${exp.slug || exp.id}`)}
      className="flex gap-3 rounded-2xl border border-[#E8E1D5] bg-white p-4 items-start cursor-pointer hover:border-[#3E7A58]/40 transition-all"
    >
      {(exp.images?.[0]?.image_url || exp.cover_image_url || exp.cover_url) ? (
        <img src={exp.images?.[0]?.image_url || exp.cover_image_url || exp.cover_url} alt={exp.title} className="w-16 h-16 rounded-xl object-cover shrink-0" />
      ) : (
        <div className="w-16 h-16 rounded-xl bg-[#E8F0EC] flex items-center justify-center shrink-0">
          <Tag size={20} className="text-[#3E7A58]" />
        </div>
      )}
      <div className="min-w-0 flex-1">
        <p className="text-sm font-semibold text-[#1A2820] truncate">{exp.title}</p>
        <div className="flex flex-wrap gap-x-3 gap-y-0.5 mt-1 text-xs text-[#9A9285]">
          {exp.location && <span className="flex items-center gap-1"><MapPin size={10} />{exp.location}</span>}
          {exp.price && <span className="flex items-center gap-1"><IndianRupee size={10} />₹{Number(exp.price).toLocaleString("en-IN")}</span>}
          {exp.duration && <span className="flex items-center gap-1"><Clock size={10} />{exp.duration}</span>}
          {exp.category && <span className="flex items-center gap-1"><Tag size={10} />{exp.category}</span>}
        </div>
      </div>
      <div className="flex gap-1.5 shrink-0" onClick={e => e.stopPropagation()}>
        <button onClick={() => onEdit(exp)}
          className="flex h-8 w-8 items-center justify-center rounded-xl border border-[#E0D8CE] text-[#9A9285] hover:border-[#3E7A58] hover:text-[#3E7A58] transition-all">
          <Pencil size={13} />
        </button>
        <button onClick={() => onDelete(exp.id)} disabled={deleting === exp.id}
          className="flex h-8 w-8 items-center justify-center rounded-xl border border-[#E0D8CE] text-[#9A9285] hover:border-red-400 hover:text-red-500 transition-all disabled:opacity-40">
          {deleting === exp.id
            ? <span className="h-3 w-3 animate-spin rounded-full border border-current border-t-transparent" />
            : <Trash2 size={13} />}
        </button>
      </div>
    </div>
  );
}

export default function ManageExperiences() {
  const [experiences, setExperiences] = useState([]);
  const [editing,     setEditing]     = useState(null);   // null = create mode, object = edit mode
  const [showForm,    setShowForm]    = useState(false);
  const [deleting,    setDeleting]    = useState(null);
  const [loading,     setLoading]     = useState(true);
  const [error,       setError]       = useState(null);
  const [toast,       setToast]       = useState(null);

  useEffect(() => {
    experienceService.list("mine=true")
      .then(res => {
        const list = res?.data?.experiences ?? res?.experiences ?? res ?? [];
        setExperiences(Array.isArray(list) ? list : []);
      })
      .catch(err => setError(err.message))
      .finally(() => setLoading(false));
  }, []);

  const handleSaved = (saved, wasEditing) => {
    if (wasEditing) {
      setExperiences(prev => prev.map(e => e.id === saved.id ? saved : e));
      setToast({ type: "success", message: "Experience updated!", key: Date.now() });
    } else {
      setExperiences(prev => [saved, ...prev]);
      setToast({ type: "success", message: "Experience created!", key: Date.now() });
    }
    setEditing(null);
    setShowForm(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this experience?")) return;
    setDeleting(id);
    try {
      await experienceService.remove(id);
      setExperiences(prev => prev.filter(e => e.id !== id));
      setToast({ type: "success", message: "Experience deleted.", key: Date.now() });
    } catch (err) {
      setToast({ type: "error", message: err.message || "Delete failed.", key: Date.now() });
    } finally {
      setDeleting(null);
    }
  };

  const openEdit = (exp) => { setEditing(exp); setShowForm(true); };
  const openCreate = () => { setEditing(null); setShowForm(true); };
  const closeForm = () => { setEditing(null); setShowForm(false); };

  return (
    <PageShell title="Manage Experiences" subtitle="Create and edit packages for travellers">

      {error && (
        <div className="mb-6 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-600 flex items-center gap-2">
          <AlertCircle size={14} />{error}
        </div>
      )}

      <div className="grid gap-6 lg:grid-cols-[1fr_1.1fr]">
        {/* ── Left: form ── */}
        <div>
          {showForm ? (
            <ExperienceFormPanel editing={editing} onSaved={handleSaved} onCancel={closeForm} />
          ) : (
            <button onClick={openCreate}
              className="w-full flex items-center justify-center gap-2 rounded-2xl border-2 border-dashed border-[#D4C9BB] bg-white py-8 text-sm font-semibold text-[#9A9285] transition-all hover:border-[#3E7A58] hover:text-[#3E7A58] hover:bg-[#EEF5F1]">
              <Plus size={16} /> Add new experience
            </button>
          )}
        </div>

        {/* ── Right: list ── */}
        <div className="space-y-3">
          {loading ? (
            [1,2,3].map(i => <div key={i} className="h-24 animate-pulse rounded-2xl bg-[#E8E1D5]" />)
          ) : experiences.length === 0 ? (
            <div className="flex flex-col items-center justify-center rounded-2xl border border-[#E8E1D5] bg-white py-16 text-center">
              <Tag size={28} className="text-[#D4C9BB] mb-3" />
              <p className="text-sm font-medium text-[#9A9285]">No experiences yet</p>
              <p className="text-xs text-[#B8AFA4] mt-1">Create your first listing to get started</p>
            </div>
          ) : (
            experiences.map(exp => (
              <ExperienceCard key={exp.id} exp={exp} onEdit={openEdit} onDelete={handleDelete} deleting={deleting} />
            ))
          )}
        </div>
      </div>

      {toast && <Toast key={toast.key} type={toast.type} message={toast.message} onDone={() => setToast(null)} />}
    </PageShell>
  );
}

import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { Plus, Pencil, Trash2, Upload, CheckCircle, AlertCircle, BookOpen, Calendar, X, Eye } from "lucide-react";
import PageShell from "../PageShell";
import storyService from "../../services/storyService";
import uploadService, { UPLOAD_FOLDERS } from "../../services/uploadService";

// ─── Toast ────────────────────────────────────────────────────
function Toast({ type, message, onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 3200); return () => clearTimeout(t); }, []);
  const ok = type === "success";
  return (
    <div className="fixed bottom-6 right-6 z-50 flex items-center gap-2.5 rounded-xl px-4 py-3 text-sm font-medium shadow-xl"
      style={{ background: ok ? "#1C3D2E" : "#5C1A1A", color: "#F2EDE4" }}>
      {ok ? <CheckCircle size={15} /> : <AlertCircle size={15} />}
      {message}
    </div>
  );
}

// ─── Cover uploader ───────────────────────────────────────────
function CoverUploader({ storyId, currentUrl, onUploaded }) {
  const [uploading, setUploading] = useState(false);
  const [preview,   setPreview]   = useState(currentUrl || "");
  const inputRef = useRef(null);

  const handleFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPreview(URL.createObjectURL(file));
    setUploading(true);
    try {
      if (storyId) {
        const fd = new FormData();
        fd.append("cover", file);
        const res = await storyService.updateCover(storyId, fd);
        const url = res?.data?.cover_url ?? res?.cover_url;
        if (url) onUploaded(url);
      } else {
        const res = await uploadService.uploadImage(file, UPLOAD_FOLDERS.STORY);
        const url = res?.data?.url ?? res?.url;
        if (url) onUploaded(url);
      }
    } catch (err) {
      console.error("Cover upload failed:", err);
    } finally {
      setUploading(false);
    }
  };

  return (
    <div>
      <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">Cover Image</label>
      <div onClick={() => inputRef.current?.click()}
        className="relative flex h-36 cursor-pointer items-center justify-center overflow-hidden rounded-xl border-2 border-dashed border-[#D4C9BB] bg-[#F5F2EE] transition-all hover:border-[#3E7A58] hover:bg-[#EEF5F1]">
        {preview
          ? <img src={preview} alt="Cover" className="h-full w-full object-cover" />
          : <div className="flex flex-col items-center gap-1.5 text-[#9A9285]">
              <Upload size={20} />
              <p className="text-xs font-medium">Upload cover image</p>
            </div>
        }
        {uploading && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/30">
            <span className="h-5 w-5 animate-spin rounded-full border-2 border-white/30 border-t-white" />
          </div>
        )}
      </div>
      <input ref={inputRef} type="file" accept="image/*" className="hidden" onChange={handleFile} />
    </div>
  );
}

// ─── Story form panel ─────────────────────────────────────────
function StoryFormPanel({ editing, onSaved, onCancel }) {
  const [form, setForm] = useState({
    title:   editing?.title   ?? "",
    excerpt: editing?.excerpt ?? "",
    content: editing?.content ?? "",
    tags:    editing?.tags?.join(", ") ?? "",
  });
  const [coverUrl, setCoverUrl] = useState(editing?.cover_url ?? "");
  const [saving,   setSaving]   = useState(false);

  const update = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        title:     form.title.trim(),
        excerpt:   form.excerpt.trim(),
        content:   form.content.trim(),
        tags:      form.tags ? form.tags.split(",").map(t => t.trim()).filter(Boolean) : [],
        cover_url: coverUrl || undefined,
      };
      let saved;
      if (editing?.id) {
        const res = await storyService.update(editing.id, payload);
        saved = res?.data?.story ?? res?.story ?? { ...editing, ...payload };
      } else {
        const res = await storyService.create(payload);
        saved = res?.data?.story ?? res?.story ?? payload;
      }
      onSaved(saved, !!editing);
    } catch (err) {
      console.error(err);
    } finally {
      setSaving(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white rounded-2xl border border-[#E8E1D5] p-5 space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-sm font-semibold text-[#1A2820]">{editing ? "Edit story" : "Write a story"}</h2>
        <button type="button" onClick={onCancel} className="text-[#9A9285] hover:text-[#1A2820] transition-colors">
          <X size={16} />
        </button>
      </div>

      <CoverUploader storyId={editing?.id} currentUrl={coverUrl} onUploaded={setCoverUrl} />

      <div className="group">
        <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">Title <span className="text-red-400">*</span></label>
        <input type="text" name="title" value={form.title} onChange={update} required
          placeholder="e.g. A harvest song at dusk"
          className="w-full rounded-xl border border-[#E0D8CE] bg-white px-4 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]"
        />
      </div>

      <div className="group">
        <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">Excerpt</label>
        <input type="text" name="excerpt" value={form.excerpt} onChange={update}
          placeholder="One-line summary shown in feeds…"
          className="w-full rounded-xl border border-[#E0D8CE] bg-white px-4 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]"
        />
      </div>

      <div className="group">
        <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">Content</label>
        <textarea name="content" value={form.content} onChange={update} rows={7}
          placeholder="Share the full story…"
          className="w-full rounded-xl border border-[#E0D8CE] bg-white px-4 py-3 text-sm text-[#1A2820] resize-none focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]"
        />
      </div>

      <div className="group">
        <label className="block text-xs font-semibold uppercase tracking-widest text-[#9A9285] mb-2">Tags <span className="font-normal text-[#B8AFA4]">(comma separated)</span></label>
        <input type="text" name="tags" value={form.tags} onChange={update}
          placeholder="culture, harvest, tradition"
          className="w-full rounded-xl border border-[#E0D8CE] bg-white px-4 py-2.5 text-sm text-[#1A2820] focus:outline-none focus:border-[#3E7A58] focus:ring-2 focus:ring-[#3E7A58]/10 transition-all placeholder:text-[#C4B8A8]"
        />
      </div>

      <div className="flex gap-2 pt-1">
        <button type="submit" disabled={saving || !form.title.trim()}
          className="flex items-center gap-2 rounded-xl px-5 py-2.5 text-sm font-semibold text-[#F2EDE4] hover:opacity-90 disabled:opacity-50 transition-all"
          style={{ background: "#1C3D2E" }}>
          {saving
            ? <span className="h-4 w-4 animate-spin rounded-full border-2 border-white/30 border-t-white" />
            : <CheckCircle size={14} />}
          {editing ? "Save changes" : "Publish story"}
        </button>
        <button type="button" onClick={onCancel}
          className="rounded-xl border border-[#E0D8CE] px-4 py-2.5 text-sm font-medium text-[#9A9285] hover:bg-[#F5F2EE] transition-all">
          Cancel
        </button>
      </div>
    </form>
  );
}

// ─── Story card ───────────────────────────────────────────────
function StoryCard({ story, onEdit, onDelete, deleting }) {
  const navigate = useNavigate();
  const fmtDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" }) : "";
