            <div className="mt-2 flex flex-wrap gap-1">
              {tags.slice(0, 4).map(t => (
                <span key={t} className="rounded-full bg-[#E8F0EC] px-2 py-0.5 text-xs font-medium text-[#3E7A58]">{t}</span>
              ))}
