function FadeUp({ children, delay = 0 }) {
  const ref = useRef(null);
  useEffect(() => {
    gsap.fromTo(ref.current,
      { opacity: 0, y: 36 },
      {
        opacity: 1, y: 0, duration: 0.65, delay, ease: "power3.out",
        scrollTrigger: { trigger: ref.current, start: "top 87%", once: true },
