            style={{ background: "var(--color-cream-mid)" }}>
            {exp.cover_image_url
              ? <img src={exp.cover_image_url} alt={exp.title} className="w-full h-full object-cover" />
              : <div className="w-full h-full flex items-center justify-center">
                  <Compass size={16} style={{ color: "var(--color-text-muted)" }} />
                </div>
            }
          </div>
          <div className="min-w-0">
            <p className="text-sm font-semibold truncate max-w-52" style={{ color: "var(--color-text-dark)" }}>
              {exp.title}
            </p>
            <p className="text-xs" style={{ color: "var(--color-text-muted)" }}>
              {exp.id} · {exp.host_name || exp.community_name || "—"}
            </p>
          </div>
        </div>
      </td>
      <td className="px-4 py-3.5 hidden sm:table-cell">
        <span className="text-[11px] font-semibold px-2.5 py-1 rounded-full"
          style={{ background: cs.bg, color: cs.color }}>
          {exp.category || "Cultural"}
        </span>
      </td>
      <td className="px-4 py-3.5 hidden md:table-cell">
        <span className="flex items-center gap-1 text-xs" style={{ color: "var(--color-text-muted)" }}>
          <MapPin size={11} />{location}
        </span>
      </td>
      <td className="px-4 py-3.5">
        <div className="flex items-center gap-1.5">
          <span className="w-1.5 h-1.5 rounded-full" style={{ background: ss.dot }} />
          <span className="text-[11px] font-bold" style={{ color: ss.color }}>{ss.label}</span>
        </div>
      </td>
      <td className="px-4 py-3.5 hidden lg:table-cell">
        {rating ? (
          <span className="flex items-center gap-1 text-xs font-semibold" style={{ color: "var(--color-text-dark)" }}>
            <Star size={11} fill="var(--color-amber)" color="var(--color-amber)" />
            {rating.toFixed(1)}
            <span style={{ color: "var(--color-text-muted)", fontWeight: 400 }}>
              ({exp.review_count || 0})
            </span>
          </span>
        ) : (
          <span className="text-xs" style={{ color: "var(--color-text-muted)" }}>No ratings</span>
        )}
      </td>
      <td className="px-4 py-3.5 hidden lg:table-cell">
        {price ? (
          <>
            <span className="text-xs font-semibold" style={{ color: "var(--color-forest-deep)" }}>
              ₹{price.toLocaleString()}
            </span>
            {duration && (
              <span className="text-xs ml-1" style={{ color: "var(--color-text-muted)" }}>
                · {duration}
              </span>
            )}
          </>
        ) : (
          <span className="text-xs" style={{ color: "var(--color-text-muted)" }}>—</span>
        )}
      </td>
      <td className="px-4 py-3.5 hidden xl:table-cell">
        <span className="text-xs font-semibold" style={{ color: "var(--color-text-dark)" }}>
          {exp.booking_count ?? "0"}
        </span>
      </td>
      <td className="px-4 py-3.5">
        {exp.report_count > 0 ? (
          <span className="text-[11px] font-bold px-2 py-0.5 rounded-full"
            style={{ background: "#FEF2F2", color: "var(--color-terracotta)" }}>
            {exp.report_count}
          </span>
        ) : (
          <span className="text-xs" style={{ color: "var(--color-text-muted)" }}>—</span>
        )}
      </td>
      <td className="px-4 py-3.5">
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          {exp.status === "under_review" && (
            <button title="Approve" onClick={() => onAction("approve", exp)}
              className="w-7 h-7 rounded-lg flex items-center justify-center hover:bg-black/8 transition-colors"
              style={{ color: "var(--color-forest)" }}>
              <CheckCircle size={14} />
            </button>
          )}
          {(exp.status === "live" || exp.status === "under_review") && (
            <button title="Flag & Warn" onClick={() => onAction("flag", exp)}
              className="w-7 h-7 rounded-lg flex items-center justify-center hover:bg-black/8 transition-colors"
              style={{ color: "#F59E0B" }}>
              <Flag size={14} />
            </button>
          )}
          {(exp.status === "flagged" || exp.status === "under_review") && (
            <button title="Suspend" onClick={() => onAction("suspend", exp)}
              className="w-7 h-7 rounded-lg flex items-center justify-center hover:bg-black/8 transition-colors"
              style={{ color: "var(--color-terracotta)" }}>
              <XCircle size={14} />
            </button>
          )}
        </div>
      </td>
    </tr>
  );
}

/* ════════════════════════════════════════════════════════ */
export default function MonitorExperiences() {
  const headerRef = useRef(null);

  const [experiences, setExperiences]   = useState([]);
  const [stats, setStats]               = useState(null);
  const [loading, setLoading]           = useState(true);
  const [statsLoading, setStatsLoading] = useState(true);
  const [error, setError]               = useState(null);

  const [search, setSearch] = useState("");

  const [modal, setModal]         = useState(null); // { type, exp }
  const [submitting, setSubmitting] = useState(false);
  const [toast, setToast]         = useState(null);

  /* ── Entrance animation ── */
  useEffect(() => {
    gsap.fromTo(headerRef.current,
      { opacity: 0, y: -16 },
      { opacity: 1, y: 0, duration: 0.5, ease: "power3.out" }
    );
  }, []);

  /* ── Fetch stats ── */
  const fetchStats = () => {
    setStatsLoading(true);
    securityService.getStats()
      .then((res) => setStats(res.data))
      .catch(() => {})
      .finally(() => setStatsLoading(false));
  };

  useEffect(() => { fetchStats(); }, []);

  /* ── Fetch experiences ── */
  const fetchExperiences = useCallback(() => {
    setLoading(true);
    setError(null);
    const params = new URLSearchParams();
    if (search) params.set("search", search);

    securityService.getAllExperiences(params.toString())
      .then((res) => {
        const list = res?.data?.experiences ?? res?.data ?? [];
        setExperiences(Array.isArray(list) ? list : []);
      })
      .catch((err) => setError(err?.response?.data?.message ?? "Failed to load experiences."))
      .finally(() => setLoading(false));
  }, [search]);

  useEffect(() => {
    const t = setTimeout(fetchExperiences, search ? 350 : 0);
    return () => clearTimeout(t);
  }, [fetchExperiences]);

  /* ── Actions ── */
  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3500);
  };

  const handleConfirm = async (reason) => {
    if (!modal) return;
    setSubmitting(true);
    try {
      const { type, exp } = modal;
      if (type === "approve") await securityService.approveExperience(exp.id);
      if (type === "flag")    await securityService.flagExperience(exp.id, reason);
      if (type === "suspend") await securityService.suspendExperience(exp.id, reason);

      showToast(
        type === "approve" ? `"${exp.title}" is now live.` :
        type === "flag"    ? `Warning sent to owner. "${exp.title}" flagged.` :
                             `"${exp.title}" has been suspended.`
      );
      setModal(null);
      fetchExperiences();
      fetchStats();
    } catch (e) {
      showToast(e?.response?.data?.message ?? "Action failed. Please try again.");
    } finally {
      setSubmitting(false);
    }
  };

  /* ── Derived stats ── */
  const statCards = [
    { label: "Total Experiences", value: stats?.total_experiences,    icon: Compass,       color: "var(--color-forest)" },
    { label: "Live Now",          value: stats?.live_experiences,     icon: TrendingUp,    color: "#10B981" },
    { label: "Under Review",      value: stats?.review_experiences,   icon: Clock,         color: "#6366F1" },
    { label: "Flagged",           value: stats?.flagged_experiences,  icon: AlertOctagon,  color: "var(--color-terracotta)" },
  ];

  return (
    <div className="min-h-screen px-6 py-8" style={{ background: "var(--color-cream)" }}>

      {/* ── Toast ── */}
      {toast && (
        <div className="fixed top-5 right-5 z-50 px-5 py-3 rounded-2xl text-sm font-medium shadow-lg"
          style={{ background: "var(--color-forest)", color: "white" }}>
          {toast}
        </div>
      )}

      {/* ── Modal ── */}
      {modal && (
        <ConfirmModal
          exp={modal.exp}
          actionType={modal.type}
          onConfirm={handleConfirm}
          onCancel={() => setModal(null)}
          submitting={submitting}
        />
      )}

      {/* ── Header ── */}
      <div ref={headerRef} className="mb-8">
        <div className="flex items-start justify-between flex-wrap gap-4">
          <div>
            <h1 className="text-3xl font-bold tracking-tight"
              style={{ fontFamily: "var(--font-display)", color: "var(--color-text-dark)" }}>
              Monitor Experiences
            </h1>
            <p className="mt-1 text-sm" style={{ color: "var(--color-text-muted)" }}>
              Oversee listings, review flags, and manage experience quality across the platform.
            </p>
          </div>
        </div>
      </div>

      {/* ── Stat cards ── */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {statCards.map((s) => <StatCard key={s.label} {...s} loading={statsLoading} />)}
      </div>

      {/* ── Table card ── */}
      <div className="rounded-2xl overflow-hidden"
        style={{
          background: "var(--color-cream-light)",
          border: "1px solid var(--color-border-soft)",
          boxShadow: "0 1px 4px rgba(0,0,0,0.05)",
        }}
      >
        {/* Toolbar */}
        <div className="px-5 py-4 flex flex-wrap items-center gap-3"
          style={{ borderBottom: "1px solid var(--color-border-soft)" }}>
          <div className="flex items-center gap-2 flex-1 min-w-48 px-3.5 py-2 rounded-xl"
            style={{ background: "var(--color-cream)", border: "1px solid var(--color-border-soft)" }}>
            <Search size={14} style={{ color: "var(--color-text-muted)" }} />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search title, host, ID…"
              className="flex-1 bg-transparent outline-none text-sm"
              style={{ color: "var(--color-text-dark)" }}
            />
            {search && (
              <button onClick={() => setSearch("")} style={{ color: "var(--color-text-muted)" }}>×</button>
            )}
          </div>
          {!loading && (
            <span className="ml-auto text-xs" style={{ color: "var(--color-text-muted)" }}>
              {experiences.length} experiences
            </span>
          )}
        </div>

        {/* Error */}
        {error && (
          <div className="mx-5 mt-4 px-4 py-3 rounded-xl text-sm flex items-center gap-2"
            style={{ background: "#FEF2F2", color: "var(--color-terracotta)", border: "1px solid #FECACA" }}>
            <AlertOctagon size={14} /> {error}
          </div>
        )}

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr style={{ borderBottom: "1px solid var(--color-border-soft)" }}>
                {[
                  { h: "Experience", cls: "px-5" },
                  { h: "Category",   cls: "px-4 hidden sm:table-cell" },
                  { h: "Location",   cls: "px-4 hidden md:table-cell" },
                  { h: "Status",     cls: "px-4" },
                  { h: "Rating",     cls: "px-4 hidden lg:table-cell" },
                  { h: "Price",      cls: "px-4 hidden lg:table-cell" },
                  { h: "Bookings",   cls: "px-4 hidden xl:table-cell" },
                  { h: "Reports",    cls: "px-4" },
                  { h: "",           cls: "px-4" },
                ].map(({ h, cls }) => (
                  <th key={h} className={`py-3 text-left text-[11px] font-semibold uppercase tracking-widest ${cls}`}
                    style={{ color: "var(--color-text-muted)" }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading
                ? Array.from({ length: 8 }).map((_, i) => <SkeletonRow key={i} />)
                : experiences.length > 0
                  ? experiences.map((exp, i) => (
                      <ExperienceRow key={exp.id} exp={exp} index={i}
                        onAction={(type, e) => setModal({ type, exp: e })} />
                    ))
                  : (
                    <tr>
                      <td colSpan={9} className="text-center py-16">
                        <p className="text-sm" style={{ color: "var(--color-text-muted)" }}>
                          No experiences match your search.
                        </p>
                      </td>
                    </tr>
                  )
              }
            </tbody>
          </table>
        </div>

        {/* Footer */}
        <div className="px-5 py-3 flex items-center justify-between text-xs"
          style={{ borderTop: "1px solid var(--color-border-soft)", color: "var(--color-text-muted)" }}>
          <span>{loading ? "Loading…" : `${experiences.length} experiences loaded`}</span>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef, useState, useCallback } from "react";
import { gsap } from "gsap";
import {
  Search, Filter, MoreHorizontal, UserCheck, UserX,
  ShieldAlert, Eye, ChevronDown, RefreshCw, Download,
  Users, TrendingUp, AlertOctagon, Clock, MapPin,
  ArrowUpRight, Loader2,
} from "lucide-react";
import securityService from "../../services/securityService";

/* ── Style maps ── */
const STATUS_STYLE = {
  active:    { bg: "#DCFCE7", color: "#166534",                         dot: "#22C55E" },
  flagged:   { bg: "#FEF3C7", color: "#92400E",                         dot: "#F59E0B" },
  suspended: { bg: "#FEF2F2", color: "var(--color-terracotta)",         dot: "#EF4444" },
  inactive:  { bg: "var(--color-cream-mid)", color: "var(--color-text-muted)", dot: "#9CA3AF" },
};
const ROLE_STYLE = {
  traveller: { bg: "#EFF6FF", color: "#1D4ED8" },
  host:      { bg: "var(--color-forest-pale)", color: "var(--color-forest)" },
};

/* ── Skeleton row ── */
function SkeletonRow() {
  return (
    <tr style={{ borderBottom: "1px solid var(--color-border-soft)" }}>
      {[48, 24, 32, 20, 16, 12, 12, 20].map((w, i) => (
        <td key={i} className="px-4 py-4">
          <div
            className="animate-pulse rounded-lg h-4"
            style={{ width: `${w * 3}px`, background: "var(--color-cream-mid)" }}
          />
        </td>
      ))}
    </tr>
  );
}

/* ── Stat card ── */
function StatCard({ label, value, delta, icon: Icon, color, loading }) {
  const ref = useRef(null);
  useEffect(() => {
    gsap.fromTo(ref.current,
      { opacity: 0, y: 20 },
      { opacity: 1, y: 0, duration: 0.45, ease: "power2.out" }
    );
  }, []);
  return (
    <div
      ref={ref}
      className="rounded-2xl p-5 flex flex-col gap-3"
      style={{
        background: "var(--color-cream-light)",
        border: "1px solid var(--color-border-soft)",
        boxShadow: "0 1px 4px rgba(0,0,0,0.05)",
      }}
    >
      <div className="flex items-center justify-between">
        <span className="text-xs font-semibold uppercase tracking-widest" style={{ color: "var(--color-text-muted)" }}>
          {label}
        </span>
        <span className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ background: color + "18" }}>
          <Icon size={15} style={{ color }} />
        </span>
      </div>
      {loading ? (
        <div className="animate-pulse h-8 w-24 rounded-lg" style={{ background: "var(--color-cream-mid)" }} />
      ) : (
        <div className="flex items-end gap-2">
          <span className="text-3xl font-bold tracking-tight"
            style={{ color: "var(--color-text-dark)", fontFamily: "var(--font-display)" }}>
            {value ?? "—"}
          </span>
        </div>
      )}
    </div>
  );
}

/* ── Action confirm modal ── */
function ConfirmModal({ user, actionType, onConfirm, onCancel, submitting }) {
  const [reason, setReason] = useState("");
  const needsReason = actionType === "suspend" || actionType === "flag";

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center px-4"
      style={{ background: "rgba(0,0,0,0.35)", backdropFilter: "blur(4px)" }}>
      <div className="w-full max-w-md rounded-3xl p-6 flex flex-col gap-5"
        style={{ background: "var(--color-cream-light)", border: "1px solid var(--color-border-soft)", boxShadow: "0 20px 60px rgba(0,0,0,0.15)" }}>
        <div>
          <h3 className="text-lg font-bold" style={{ fontFamily: "var(--font-display)", color: "var(--color-text-dark)" }}>
            {actionType === "suspend" ? "Suspend User" : actionType === "reinstate" ? "Reinstate User" : "Flag User"}
          </h3>
          <p className="text-sm mt-1" style={{ color: "var(--color-text-muted)" }}>
            {actionType === "suspend" && `You're about to suspend ${user.name}. They will lose platform access.`}
            {actionType === "reinstate" && `Reinstate ${user.name}? They will regain full platform access.`}
            {actionType === "flag" && `Flag ${user.name}'s account for review.`}
          </p>
        </div>
        {needsReason && (
          <div>
            <label className="block text-xs font-semibold uppercase tracking-widest mb-2"
              style={{ color: "var(--color-text-muted)" }}>
              Reason <span style={{ color: "var(--color-terracotta)" }}>*</span>
            </label>
            <textarea
              rows={3}
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="Provide a reason…"
              className="w-full rounded-xl px-4 py-3 text-sm resize-none outline-none"
              style={{
                background: "var(--color-cream)",
                border: "1.5px solid var(--color-border-soft)",
                color: "var(--color-text-dark)",
              }}
              onFocus={(e) => (e.target.style.borderColor = "var(--color-forest)")}
              onBlur={(e) => (e.target.style.borderColor = "var(--color-border-soft)")}
            />
          </div>
        )}
        <div className="flex gap-3">
          <button
            onClick={() => onConfirm(reason)}
            disabled={submitting || (needsReason && !reason.trim())}
            className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-semibold disabled:opacity-60 transition-all hover:brightness-95"
            style={{
              background: actionType === "reinstate" ? "var(--color-forest)" : "var(--color-terracotta)",
              color: "white",
            }}
          >
            {submitting ? <Loader2 size={14} className="animate-spin" /> : null}
            Confirm
          </button>
          <button
            onClick={onCancel}
            disabled={submitting}
            className="flex-1 py-2.5 rounded-xl text-sm font-medium hover:bg-black/5 transition-colors disabled:opacity-60"
            style={{ border: "1px solid var(--color-border-soft)", color: "var(--color-text-muted)" }}
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
}

/* ── User row ── */
function UserRow({ user, index, onAction }) {
  const ref = useRef(null);
  const ss = STATUS_STYLE[user.status] || STATUS_STYLE.inactive;
  const rs = ROLE_STYLE[user.role] || ROLE_STYLE.traveller;

  useEffect(() => {
    gsap.fromTo(ref.current,
      { opacity: 0, x: -10 },
      { opacity: 1, x: 0, duration: 0.35, ease: "power2.out", delay: 0.1 + index * 0.03 }
    );
  }, []);

  return (
    <tr ref={ref} className="group transition-colors duration-150"
      style={{ borderBottom: "1px solid var(--color-border-soft)" }}
      onMouseEnter={(e) => (e.currentTarget.style.background = "var(--color-cream-mid)")}
      onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}
    >
      <td className="px-5 py-3.5">
        <div className="flex items-center gap-3">
          <div className="relative">
            {user.avatar_url ? (
              <img src={user.avatar_url} alt={user.name} className="w-8 h-8 rounded-full object-cover" />
            ) : (
              <div className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold"
                style={{ background: "var(--color-forest-pale)", color: "var(--color-forest)" }}>
                {user.name?.[0]?.toUpperCase()}
              </div>
            )}
            <span className="absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 rounded-full border-2"
              style={{ background: ss.dot, borderColor: "var(--color-cream-light)" }} />
          </div>
          <div>
            <p className="text-sm font-semibold" style={{ color: "var(--color-text-dark)" }}>{user.name}</p>
            <p className="text-xs" style={{ color: "var(--color-text-muted)" }}>{user.email}</p>
          </div>
        </div>
      </td>
      <td className="px-4 py-3.5">
        <span className="text-[11px] font-semibold px-2.5 py-1 rounded-full capitalize"
          style={{ background: rs.bg, color: rs.color }}>
          {user.role}
        </span>
      </td>
      <td className="px-4 py-3.5 hidden md:table-cell">
        <span className="flex items-center gap-1 text-xs" style={{ color: "var(--color-text-muted)" }}>
          <MapPin size={11} />{user.location || "—"}
        </span>
      </td>
      <td className="px-4 py-3.5">
        <div className="flex items-center gap-1.5">
          <span className="w-1.5 h-1.5 rounded-full" style={{ background: ss.dot }} />
          <span className="text-[11px] font-bold capitalize" style={{ color: ss.color }}>{user.status}</span>
        </div>
      </td>
      <td className="px-4 py-3.5 hidden lg:table-cell">
        <span className="text-xs" style={{ color: "var(--color-text-muted)" }}>
          {user.last_active
            ? new Date(user.last_active).toLocaleDateString("en-IN", { day: "numeric", month: "short" })
            : "—"}
        </span>
      </td>
      <td className="px-4 py-3.5 hidden lg:table-cell">
        <span className="text-xs font-semibold" style={{ color: "var(--color-text-dark)" }}>
          {user.booking_count ?? "—"}
        </span>
      </td>
      <td className="px-4 py-3.5">
        {user.report_count > 0 ? (
          <span className="text-[11px] font-bold px-2 py-0.5 rounded-full"
            style={{ background: "#FEF2F2", color: "var(--color-terracotta)" }}>
            {user.report_count}
          </span>
        ) : (
          <span className="text-xs" style={{ color: "var(--color-text-muted)" }}>—</span>
        )}
      </td>
      <td className="px-4 py-3.5">
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
          {user.status === "active" && (
            <button title="Suspend" onClick={() => onAction("suspend", user)}
              className="w-7 h-7 rounded-lg flex items-center justify-center hover:bg-black/8 transition-colors"
              style={{ color: "var(--color-terracotta)" }}>
              <UserX size={14} />
            </button>
          )}
          {user.status === "suspended" && (
            <button title="Reinstate" onClick={() => onAction("reinstate", user)}
              className="w-7 h-7 rounded-lg flex items-center justify-center hover:bg-black/8 transition-colors"
              style={{ color: "var(--color-forest)" }}>
              <UserCheck size={14} />
            </button>
          )}
          {user.status === "flagged" && (
            <button title="Review flag" onClick={() => onAction("flag", user)}
              className="w-7 h-7 rounded-lg flex items-center justify-center hover:bg-black/8 transition-colors"
              style={{ color: "#F59E0B" }}>
              <ShieldAlert size={14} />
            </button>
          )}
          {user.status === "active" && (
            <button title="Flag" onClick={() => onAction("flag", user)}
              className="w-7 h-7 rounded-lg flex items-center justify-center hover:bg-black/8 transition-colors"
              style={{ color: "var(--color-text-muted)" }}>
              <ShieldAlert size={14} />
            </button>
          )}
        </div>
      </td>
    </tr>
  );
}

/* ════════════════════════════════════════════════════════ */
export default function MonitorUsers() {
  const headerRef = useRef(null);

  const [users, setUsers]           = useState([]);
  const [stats, setStats]           = useState(null);
  const [loading, setLoading]       = useState(true);
  const [statsLoading, setStatsLoading] = useState(true);
  const [error, setError]           = useState(null);

  const [search, setSearch]             = useState("");
  const [statusFilter, setStatusFilter] = useState("all");
  const [roleFilter, setRoleFilter]     = useState("all");

  const [modal, setModal]       = useState(null); // { type, user }
  const [submitting, setSubmitting] = useState(false);
  const [toast, setToast]       = useState(null);

  /* ── Entrance animation ── */
  useEffect(() => {
    gsap.fromTo(headerRef.current,
      { opacity: 0, y: -16 },
      { opacity: 1, y: 0, duration: 0.5, ease: "power3.out" }
    );
  }, []);

  /* ── Fetch stats ── */
  useEffect(() => {
    setStatsLoading(true);
    securityService.getStats()
      .then((res) => setStats(res.data))
      .catch(() => {})
      .finally(() => setStatsLoading(false));
  }, []);

  /* ── Fetch users ── */
  const fetchUsers = useCallback(() => {
    setLoading(true);
    setError(null);
    const params = new URLSearchParams();
    if (statusFilter !== "all") params.set("status", statusFilter);
    if (roleFilter !== "all")   params.set("role", roleFilter);
    if (search)                 params.set("search", search);

    securityService.getAllUsers(params.toString())
      .then((res) => {
        const list = res?.data?.users ?? res?.data ?? [];
        setUsers(Array.isArray(list) ? list : []);
      })
      .catch((err) => setError(err?.response?.data?.message ?? "Failed to load users."))
      .finally(() => setLoading(false));
  }, [statusFilter, roleFilter, search]);

  useEffect(() => {
    const t = setTimeout(fetchUsers, search ? 350 : 0);
    return () => clearTimeout(t);
  }, [fetchUsers]);

  /* ── Actions ── */
  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(null), 3500);
  };

  const handleConfirm = async (reason) => {
    if (!modal) return;
    setSubmitting(true);
    try {
      const { type, user } = modal;
      if (type === "suspend")   await securityService.suspendUser(user.id, reason);
      if (type === "reinstate") await securityService.unsuspendUser(user.id);
      if (type === "flag")      await securityService.flagUser(user.id, reason);

      showToast(
        type === "suspend"   ? `${user.name} has been suspended.` :
        type === "reinstate" ? `${user.name} has been reinstated.` :
                               `${user.name} has been flagged for review.`
      );
      setModal(null);
      fetchUsers();
    } catch (e) {
      showToast(e?.response?.data?.message ?? "Action failed. Please try again.");
    } finally {
      setSubmitting(false);
    }
  };

  /* ── Derived stats ── */
  const statCards = [
    { label: "Total Users",    value: stats?.total_users,    delta: stats?.user_delta,    icon: Users,         color: "var(--color-forest)" },
    { label: "Active Today",   value: stats?.active_today,   delta: stats?.active_delta,  icon: TrendingUp,    color: "var(--color-amber)" },
    { label: "Flagged",        value: stats?.flagged_users,  delta: null,                 icon: ShieldAlert,   color: "var(--color-terracotta)" },
    { label: "Suspended",      value: stats?.suspended_users, delta: null,                icon: Clock,         color: "#6366F1" },
  ];

  return (
    <div className="min-h-screen px-6 py-8" style={{ background: "var(--color-cream)" }}>

      {/* ── Toast ── */}
      {toast && (
        <div
          className="fixed top-5 right-5 z-50 px-5 py-3 rounded-2xl text-sm font-medium shadow-lg"
          style={{ background: "var(--color-forest)", color: "white" }}
        >
          {toast}
        </div>
      )}

      {/* ── Modal ── */}
      {modal && (
        <ConfirmModal
          user={modal.user}
          actionType={modal.type}
          onConfirm={handleConfirm}
          onCancel={() => setModal(null)}
          submitting={submitting}
        />
      )}

      {/* ── Header ── */}
      <div ref={headerRef} className="mb-8">
        <div className="flex items-start justify-between flex-wrap gap-4">
          <div>
            <h1 className="text-3xl font-bold tracking-tight"
              style={{ fontFamily: "var(--font-display)", color: "var(--color-text-dark)" }}>
              Monitor Users
            </h1>
            <p className="mt-1 text-sm" style={{ color: "var(--color-text-muted)" }}>
              Review activity, flags, and account health across all platform users.
            </p>
          </div>
        </div>
      </div>

      {/* ── Stat cards ── */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {statCards.map((s) => (
          <StatCard key={s.label} {...s} loading={statsLoading} />
        ))}
      </div>

      {/* ── Table card ── */}
      <div className="rounded-2xl overflow-hidden"
        style={{
          background: "var(--color-cream-light)",
          border: "1px solid var(--color-border-soft)",
          boxShadow: "0 1px 4px rgba(0,0,0,0.05)",
        }}
      >
        {/* Toolbar */}
        <div className="px-5 py-4 flex flex-wrap items-center gap-3"
          style={{ borderBottom: "1px solid var(--color-border-soft)" }}>
          <div className="flex items-center gap-2 flex-1 min-w-48 px-3.5 py-2 rounded-xl"
            style={{ background: "var(--color-cream)", border: "1px solid var(--color-border-soft)" }}>
            <Search size={14} style={{ color: "var(--color-text-muted)" }} />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search name, email…"
              className="flex-1 bg-transparent outline-none text-sm"
              style={{ color: "var(--color-text-dark)" }}
            />
            {search && (
              <button onClick={() => setSearch("")} style={{ color: "var(--color-text-muted)" }}>
                ×
              </button>
            )}
          </div>
          <div className="flex items-center gap-1.5 px-3.5 py-2 rounded-xl"
            style={{ background: "var(--color-cream)", border: "1px solid var(--color-border-soft)" }}>
            <Filter size={13} style={{ color: "var(--color-text-muted)" }} />
            <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)}
              className="bg-transparent outline-none text-sm appearance-none pr-4"
              style={{ color: "var(--color-text-dark)" }}>
              <option value="all">All Status</option>
              <option value="active">Active</option>
              <option value="flagged">Flagged</option>
              <option value="suspended">Suspended</option>
              <option value="inactive">Inactive</option>
            </select>
            <ChevronDown size={12} style={{ color: "var(--color-text-muted)" }} />
          </div>
          <div className="flex items-center gap-1.5 px-3.5 py-2 rounded-xl"
            style={{ background: "var(--color-cream)", border: "1px solid var(--color-border-soft)" }}>
            <Users size={13} style={{ color: "var(--color-text-muted)" }} />
            <select value={roleFilter} onChange={(e) => setRoleFilter(e.target.value)}
              className="bg-transparent outline-none text-sm appearance-none pr-4"
              style={{ color: "var(--color-text-dark)" }}>
              <option value="all">All Roles</option>
              <option value="tourist">Tourist</option>
              <option value="community">Community</option>
            </select>
            <ChevronDown size={12} style={{ color: "var(--color-text-muted)" }} />
          </div>
          {!loading && (
            <span className="ml-auto text-xs" style={{ color: "var(--color-text-muted)" }}>
              {users.length} users
            </span>
          )}
        </div>

        {/* Error */}
        {error && (
          <div className="mx-5 mt-4 px-4 py-3 rounded-xl text-sm flex items-center gap-2"
            style={{ background: "#FEF2F2", color: "var(--color-terracotta)", border: "1px solid #FECACA" }}>
            <AlertOctagon size={14} /> {error}
          </div>
        )}

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr style={{ borderBottom: "1px solid var(--color-border-soft)" }}>
                {[
                  { h: "User",        cls: "px-5" },
                  { h: "Role",        cls: "px-4" },
                  { h: "Location",    cls: "px-4 hidden md:table-cell" },
                  { h: "Status",      cls: "px-4" },
                  { h: "Last Active", cls: "px-4 hidden lg:table-cell" },
                  { h: "Bookings",    cls: "px-4 hidden lg:table-cell" },
                  { h: "Reports",     cls: "px-4" },
                  { h: "",            cls: "px-4" },
                ].map(({ h, cls }) => (
                  <th key={h} className={`py-3 text-left text-[11px] font-semibold uppercase tracking-widest ${cls}`}
                    style={{ color: "var(--color-text-muted)" }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading
                ? Array.from({ length: 8 }).map((_, i) => <SkeletonRow key={i} />)
                : users.length > 0
                  ? users.map((user, i) => (
                      <UserRow key={user.id} user={user} index={i}
                        onAction={(type, u) => setModal({ type, user: u })} />
                    ))
                  : (
                    <tr>
                      <td colSpan={8} className="text-center py-16">
                        <p className="text-sm" style={{ color: "var(--color-text-muted)" }}>
                          No users match your filters.
                        </p>
                      </td>
                    </tr>
                  )
              }
            </tbody>
          </table>
        </div>

        {/* Footer */}
        <div className="px-5 py-3 flex items-center justify-between text-xs"
          style={{ borderTop: "1px solid var(--color-border-soft)", color: "var(--color-text-muted)" }}>
          <span>{loading ? "Loading…" : `${users.length} users loaded`}</span>
          <span>Filters: {statusFilter} · {roleFilter}</span>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from "react";
import {
  User,
  Mail,
  Phone,
  Shield,
  Camera,
  Pencil,
  Check,
  X,
  Lock,
  Eye,
  EyeOff,
  Loader2,
  AlertTriangle,
  CheckCircle2,
  BadgeCheck,
  CalendarDays,
} from "lucide-react";
import userService from "../../services/userService";

/* ─── Tiny helpers ──────────────────────────────────────────── */

function Toast({ message, type = "success", onDone }) {
  useEffect(() => {
    const t = setTimeout(onDone, 3000);
    return () => clearTimeout(t);
  }, [onDone]);

  return (
    <div
      className="fixed bottom-6 right-6 z-50 flex items-center gap-2.5 px-5 py-3.5 rounded-2xl text-sm font-medium shadow-lg"
      style={{
        backgroundColor: type === "success" ? "var(--color-forest)" : "var(--color-terracotta)",
        color: "white",
        animation: "slideUp 0.25s ease",
      }}
    >
      {type === "success"
        ? <CheckCircle2 size={15} strokeWidth={2} />
        : <AlertTriangle size={15} strokeWidth={2} />}
      {message}
      <style>{`@keyframes slideUp { from { opacity:0; transform:translateY(10px) } to { opacity:1; transform:translateY(0) } }`}</style>
    </div>
  );
}

function SectionCard({ title, icon: Icon, children, action }) {
  return (
    <div
      className="rounded-2xl overflow-hidden"
      style={{
        backgroundColor: "var(--color-cream-light)",
        border: "1px solid var(--color-border-soft)",
        boxShadow: "0 1px 4px rgba(0,0,0,0.05)",
      }}
    >
      <div
        className="flex items-center justify-between px-6 py-4 border-b"
        style={{ borderColor: "var(--color-border-soft)" }}
      >
        <div className="flex items-center gap-2.5">
          <span
            className="w-7 h-7 rounded-lg flex items-center justify-center"
            style={{ backgroundColor: "var(--color-forest-pale)" }}
          >
            <Icon size={13} style={{ color: "var(--color-forest)" }} strokeWidth={2} />
          </span>
          <h2
            className="text-xs font-bold uppercase tracking-widest"
            style={{ color: "var(--color-text-muted)" }}
          >
            {title}
          </h2>
        </div>
        {action}
      </div>
      <div className="px-6 py-5">{children}</div>
    </div>
  );
}

function Field({ label, value, placeholder = "—" }) {
  return (
    <div>
      <p
        className="text-[10px] font-bold uppercase tracking-widest mb-1"
        style={{ color: "var(--color-text-muted)" }}
      >
        {label}
      </p>
      <p className="text-sm" style={{ color: value ? "var(--color-text-dark)" : "var(--color-text-muted)" }}>
        {value || placeholder}
      </p>
    </div>
  );
}

function Input({ label, name, value, onChange, type = "text", placeholder, required, disabled }) {
  return (
    <div>
      <label
        className="block text-[10px] font-bold uppercase tracking-widest mb-1.5"
        style={{ color: "var(--color-text-muted)" }}
      >
        {label} {required && <span style={{ color: "var(--color-terracotta)" }}>*</span>}
      </label>
      <input
        type={type}
        name={name}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        disabled={disabled}
        className="w-full rounded-xl px-4 py-2.5 text-sm outline-none transition-all disabled:opacity-50"
        style={{
          backgroundColor: "var(--color-cream-light)",
          border: "1.5px solid var(--color-border-soft)",
          color: "var(--color-text-dark)",
        }}
        onFocus={(e) => (e.target.style.borderColor = "var(--color-forest)")}
        onBlur={(e) => (e.target.style.borderColor = "var(--color-border-soft)")}
      />
    </div>
  );
}

function PasswordInput({ label, name, value, onChange, disabled }) {
  const [show, setShow] = useState(false);
  return (
    <div>
      <label
        className="block text-[10px] font-bold uppercase tracking-widest mb-1.5"
        style={{ color: "var(--color-text-muted)" }}
      >
        {label} <span style={{ color: "var(--color-terracotta)" }}>*</span>
      </label>
      <div className="relative">
        <input
          type={show ? "text" : "password"}
          name={name}
          value={value}
          onChange={onChange}
          disabled={disabled}
          className="w-full rounded-xl px-4 py-2.5 pr-11 text-sm outline-none transition-all disabled:opacity-50"
          style={{
            backgroundColor: "var(--color-cream-light)",
            border: "1.5px solid var(--color-border-soft)",
            color: "var(--color-text-dark)",
          }}
          onFocus={(e) => (e.target.style.borderColor = "var(--color-forest)")}
          onBlur={(e) => (e.target.style.borderColor = "var(--color-border-soft)")}
        />
        <button
          type="button"
          onClick={() => setShow((v) => !v)}
          className="absolute right-3 top-1/2 -translate-y-1/2 p-1 rounded-lg transition-colors hover:bg-black/5"
          style={{ color: "var(--color-text-muted)" }}
        >
          {show ? <EyeOff size={14} /> : <Eye size={14} />}
        </button>
      </div>
    </div>
  );
}

/* ─── Main component ────────────────────────────────────────── */

const EMPTY_PROFILE = { name: "", username: "", phone: "", bio: "", country: "", city: "" };
const EMPTY_PW = { currentPassword: "", newPassword: "", confirmPassword: "" };

export default function OfficerProfile() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [toast, setToast] = useState(null); // { message, type }

  // Edit profile state
  const [editingProfile, setEditingProfile] = useState(false);
  const [profileForm, setProfileForm] = useState(EMPTY_PROFILE);
  const [savingProfile, setSavingProfile] = useState(false);
  const [profileError, setProfileError] = useState(null);

  // Password state
  const [editingPassword, setEditingPassword] = useState(false);
  const [pwForm, setPwForm] = useState(EMPTY_PW);
  const [savingPw, setSavingPw] = useState(false);
  const [pwError, setPwError] = useState(null);

  // Avatar state
  const [uploadingAvatar, setUploadingAvatar] = useState(false);
  const avatarInputRef = useRef(null);

  /* Load profile */
  useEffect(() => {
    userService
      .updateProfile // sanity: confirm service exists, then fetch own profile
    // Use a dedicated "getMe" if available; falling back to a reasonable endpoint
    fetch("/api/users/me", { credentials: "include" })
      .then((r) => r.json())
      .then((data) => {
        const u = data?.data?.user ?? data?.data ?? data;
        setProfile(u);
        setProfileForm({
          name: u.name ?? u.full_name ?? "",
          username: u.username ?? "",
          phone: u.phone ?? "",
          bio: u.bio ?? "",
          country: u.country ?? "",
          city: u.city ?? "",
        });
      })
      .catch(() => {
        // Fallback: show empty editable state
        setProfile({});
      })
      .finally(() => setLoading(false));
  }, []);

  /* ── Avatar upload ── */
  const handleAvatarChange = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploadingAvatar(true);
    try {
      const formData = new FormData();
      formData.append("avatar", file);
      const res = await userService.updateAvatar(formData);
      const updated = res.data.data.user;
      setProfile((p) => ({ ...p, avatar_url: updated.avatar_url }));
      setToast({ message: "Avatar updated.", type: "success" });
    } catch {
      setToast({ message: "Avatar upload failed.", type: "error" });
    } finally {
      setUploadingAvatar(false);
      e.target.value = "";
    }
  };

  /* ── Profile save ── */
  const handleProfileSave = async () => {
    if (!profileForm.name.trim()) {
      setProfileError("Full name is required.");
      return;
    }
    setSavingProfile(true);
    setProfileError(null);
    try {
      const res = await userService.updateProfile(profileForm);
      const updated = res.data.data.user;
      setProfile((p) => ({ ...p, ...updated }));
      setEditingProfile(false);
      setToast({ message: "Profile saved successfully.", type: "success" });
    } catch (e) {
      setProfileError(e?.response?.data?.message ?? "Failed to save profile.");
    } finally {
      setSavingProfile(false);
    }
  };

  const handleProfileCancel = () => {
    setEditingProfile(false);
    setProfileError(null);
    setProfileForm({
      name: profile?.name ?? profile?.full_name ?? "",
      username: profile?.username ?? "",
      phone: profile?.phone ?? "",
      bio: profile?.bio ?? "",
      country: profile?.country ?? "",
      city: profile?.city ?? "",
    });
  };

  /* ── Password save ── */
  const handlePasswordSave = async () => {
    if (!pwForm.currentPassword || !pwForm.newPassword || !pwForm.confirmPassword) {
      setPwError("All fields are required.");
      return;
    }
    if (pwForm.newPassword !== pwForm.confirmPassword) {
      setPwError("New passwords do not match.");
      return;
    }
    if (pwForm.newPassword.length < 8) {
      setPwError("Password must be at least 8 characters.");
      return;
    }
    setSavingPw(true);
    setPwError(null);
    try {
      await fetch("/api/users/me/password", {
        method: "PATCH",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          current_password: pwForm.currentPassword,
          new_password: pwForm.newPassword,
        }),
      }).then((r) => { if (!r.ok) throw new Error(); });
      setEditingPassword(false);
      setPwForm(EMPTY_PW);
      setToast({ message: "Password changed successfully.", type: "success" });
    } catch {
      setPwError("Current password is incorrect or request failed.");
    } finally {
      setSavingPw(false);
    }
  };

  /* ── Avatar initials ── */
  const displayName = profile?.name ?? profile?.full_name ?? "";
  const initials = displayName
    ? displayName.split(" ").map((n) => n[0]).join("").toUpperCase().slice(0, 2)
    : "?";

  const joinedDate = profile?.created_at
    ? new Date(profile.created_at).toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" })
    : null;

  /* ─── Loading skeleton ─── */
  if (loading) {
    return (
      <div className="max-w-2xl mx-auto px-6 py-10 space-y-5">
        {[120, 80, 100].map((h, i) => (
          <div key={i} className="rounded-2xl animate-pulse" style={{ height: h, backgroundColor: "var(--color-border-soft)" }} />
        ))}
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto px-6 py-10 space-y-6">
      {/* ── Page header ── */}
      <div>
        <h1
          className="text-3xl font-bold tracking-tight"
          style={{ color: "var(--color-text-dark)", fontFamily: "var(--font-display)" }}
        >
          My Profile
        </h1>
        <p className="mt-1 text-sm" style={{ color: "var(--color-text-muted)" }}>
          Manage your officer account and credentials.
        </p>
      </div>

      {/* ── Identity card ── */}
      <div
        className="relative rounded-2xl px-6 py-6 flex items-center gap-5"
        style={{
          backgroundColor: "var(--color-forest)",
          boxShadow: "0 4px 24px rgba(0,0,0,0.12)",
          overflow: "hidden",
        }}
      >
        {/* Background texture rings */}
        <div
          className="pointer-events-none absolute -right-12 -top-12 w-48 h-48 rounded-full opacity-10"
          style={{ border: "1px solid white" }}
        />
        <div
          className="pointer-events-none absolute -right-4 -top-4 w-32 h-32 rounded-full opacity-10"
          style={{ border: "1px solid white" }}
        />

        {/* Avatar */}
        <div className="relative shrink-0">
          {profile?.avatar_url ? (
            <img
              src={profile.avatar_url}
              alt="avatar"
              className="w-20 h-20 rounded-2xl object-cover"
              style={{ border: "3px solid rgba(255,255,255,0.2)" }}
            />
          ) : (
            <div
              className="w-20 h-20 rounded-2xl flex items-center justify-center text-2xl font-bold"
              style={{
                backgroundColor: "rgba(255,255,255,0.15)",
                color: "white",
                border: "3px solid rgba(255,255,255,0.2)",
                fontFamily: "var(--font-display)",
              }}
            >
              {initials}
            </div>
          )}
          {/* Camera overlay */}
          <button
            onClick={() => avatarInputRef.current?.click()}
            disabled={uploadingAvatar}
            className="absolute -bottom-2 -right-2 w-8 h-8 rounded-xl flex items-center justify-center transition-all hover:scale-105 disabled:opacity-60"
            style={{ backgroundColor: "var(--color-terracotta)", color: "white", boxShadow: "0 2px 8px rgba(0,0,0,0.2)" }}
            title="Change avatar"
          >
            {uploadingAvatar
              ? <Loader2 size={13} className="animate-spin" />
              : <Camera size={13} strokeWidth={2} />
            }
          </button>
          <input ref={avatarInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
        </div>

        {/* Name + meta */}
        <div className="flex-1 min-w-0">
          <p className="text-xl font-bold text-white truncate" style={{ fontFamily: "var(--font-display)" }}>
            {displayName || "Security Officer"}
          </p>
          {profile?.username && (
            <p className="text-sm mt-0.5" style={{ color: "rgba(255,255,255,0.6)" }}>
              @{profile.username}
            </p>
          )}
          <div className="mt-3 flex flex-wrap gap-2">
            <span
              className="flex items-center gap-1.5 text-[10px] font-bold px-2.5 py-1 rounded-full uppercase tracking-wide"
              style={{ backgroundColor: "rgba(255,255,255,0.15)", color: "white" }}
            >
              <Shield size={10} strokeWidth={2.5} />
              {profile?.role ?? "Security"}
            </span>
            <span
              className="flex items-center gap-1.5 text-[10px] font-bold px-2.5 py-1 rounded-full uppercase tracking-wide"
              style={{ backgroundColor: "rgba(255,255,255,0.15)", color: "white" }}
            >
              <BadgeCheck size={10} strokeWidth={2.5} />
              {profile?.status ?? "Active"}
            </span>
            {joinedDate && (
              <span
                className="flex items-center gap-1.5 text-[10px] font-bold px-2.5 py-1 rounded-full uppercase tracking-wide"
                style={{ backgroundColor: "rgba(255,255,255,0.15)", color: "white" }}
              >
                <CalendarDays size={10} strokeWidth={2.5} />
                Since {joinedDate}
              </span>
            )}
          </div>
        </div>
      </div>

      {/* ── Personal info ── */}
      <SectionCard
        title="Personal Information"
        icon={User}
        action={
          !editingProfile ? (
            <button
              onClick={() => setEditingProfile(true)}
              className="flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors hover:bg-black/5"
              style={{ color: "var(--color-forest)", border: "1px solid var(--color-forest)" + "40" }}
            >
              <Pencil size={12} strokeWidth={2} />
              Edit
            </button>
          ) : (
            <div className="flex gap-2">
              <button
                onClick={handleProfileSave}
                disabled={savingProfile}
                className="flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors hover:brightness-95 disabled:opacity-60"
                style={{ backgroundColor: "var(--color-forest)", color: "white" }}
              >
                {savingProfile ? <Loader2 size={12} className="animate-spin" /> : <Check size={12} strokeWidth={2.5} />}
                Save
              </button>
              <button
                onClick={handleProfileCancel}
                disabled={savingProfile}
                className="flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors hover:bg-black/5 disabled:opacity-60"
                style={{ color: "var(--color-text-muted)", border: "1px solid var(--color-border-soft)" }}
              >
                <X size={12} strokeWidth={2.5} />
                Cancel
              </button>
            </div>
          )
        }
      >
        {/* Error */}
        {profileError && (
          <div
            className="mb-4 flex items-center gap-2 rounded-xl px-4 py-3 text-sm"
            style={{ backgroundColor: "#FEF2F2", color: "var(--color-terracotta)", border: "1px solid #FECACA" }}
          >
            <AlertTriangle size={14} strokeWidth={2} />
            {profileError}
          </div>
        )}

        {editingProfile ? (
          <div className="grid gap-4 sm:grid-cols-2">
            <div className="sm:col-span-2">
              <Input
                label="Full Name"
                name="name"
                value={profileForm.name}
                onChange={(e) => setProfileForm((f) => ({ ...f, name: e.target.value }))}
                placeholder="Rohit Mehta"
                required
                disabled={savingProfile}
              />
            </div>
            <Input
              label="Username"
              name="username"
              value={profileForm.username}
              onChange={(e) => setProfileForm((f) => ({ ...f, username: e.target.value }))}
              placeholder="rohit_mehta"
              disabled={savingProfile}
            />
            <Input
              label="Phone"
              name="phone"
              value={profileForm.phone}
              onChange={(e) => setProfileForm((f) => ({ ...f, phone: e.target.value }))}
              placeholder="+91 98765 43210"
              disabled={savingProfile}
            />
            <Input
              label="City"
              name="city"
              value={profileForm.city}
              onChange={(e) => setProfileForm((f) => ({ ...f, city: e.target.value }))}
              placeholder="Mumbai"
              disabled={savingProfile}
            />
            <Input
              label="Country"
              name="country"
              value={profileForm.country}
              onChange={(e) => setProfileForm((f) => ({ ...f, country: e.target.value }))}
              placeholder="India"
              disabled={savingProfile}
            />
            <div className="sm:col-span-2">
              <label
                className="block text-[10px] font-bold uppercase tracking-widest mb-1.5"
                style={{ color: "var(--color-text-muted)" }}
              >
                Bio
              </label>
              <textarea
                rows={3}
                value={profileForm.bio}
                onChange={(e) => setProfileForm((f) => ({ ...f, bio: e.target.value }))}
                placeholder="Brief description about yourself…"
                disabled={savingProfile}
                className="w-full rounded-xl px-4 py-2.5 text-sm outline-none resize-none transition-all disabled:opacity-50"
                style={{
                  backgroundColor: "var(--color-cream-light)",
                  border: "1.5px solid var(--color-border-soft)",
                  color: "var(--color-text-dark)",
                }}
                onFocus={(e) => (e.target.style.borderColor = "var(--color-forest)")}
                onBlur={(e) => (e.target.style.borderColor = "var(--color-border-soft)")}
              />
            </div>
          </div>
        ) : (
          <div className="grid gap-5 sm:grid-cols-2">
            <div className="sm:col-span-2">
              <Field label="Full Name" value={displayName} />
            </div>
            <Field label="Username" value={profile?.username ? `@${profile.username}` : null} />
            <Field label="Phone" value={profile?.phone} />
            <Field label="City" value={profile?.city} />
            <Field label="Country" value={profile?.country} />
            {profile?.bio && (
              <div className="sm:col-span-2">
                <Field label="Bio" value={profile.bio} />
              </div>
            )}
          </div>
        )}
      </SectionCard>

      {/* ── Contact (read-only email) ── */}
      <SectionCard title="Contact" icon={Mail}>
        <div className="flex items-center justify-between">
          <div>
            <p
              className="text-[10px] font-bold uppercase tracking-widest mb-1"
              style={{ color: "var(--color-text-muted)" }}
            >
              Email Address
            </p>
            <p className="text-sm" style={{ color: "var(--color-text-dark)" }}>
              {profile?.email ?? "—"}
            </p>
          </div>
          <span
            className="flex items-center gap-1.5 text-[10px] font-bold px-2.5 py-1 rounded-full uppercase tracking-wide"
            style={{ backgroundColor: "var(--color-forest-pale)", color: "var(--color-forest)" }}
          >
            <BadgeCheck size={10} strokeWidth={2.5} />
            Verified
          </span>
        </div>
        <p className="mt-3 text-xs" style={{ color: "var(--color-text-muted)" }}>
          Email cannot be changed. Contact your admin to update it.
        </p>
      </SectionCard>

      {/* ── Change password ── */}
      <SectionCard
        title="Security"
        icon={Lock}
        action={
          !editingPassword ? (
            <button
              onClick={() => setEditingPassword(true)}
              className="flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors hover:bg-black/5"
              style={{ color: "var(--color-forest)", border: "1px solid var(--color-forest)" + "40" }}
            >
              <Pencil size={12} strokeWidth={2} />
              Change Password
            </button>
          ) : (
            <div className="flex gap-2">
              <button
                onClick={handlePasswordSave}
                disabled={savingPw}
                className="flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors hover:brightness-95 disabled:opacity-60"
                style={{ backgroundColor: "var(--color-forest)", color: "white" }}
              >
                {savingPw ? <Loader2 size={12} className="animate-spin" /> : <Check size={12} strokeWidth={2.5} />}
                Save
              </button>
              <button
                onClick={() => { setEditingPassword(false); setPwForm(EMPTY_PW); setPwError(null); }}
                disabled={savingPw}
                className="flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors hover:bg-black/5 disabled:opacity-60"
                style={{ color: "var(--color-text-muted)", border: "1px solid var(--color-border-soft)" }}
              >
                <X size={12} strokeWidth={2.5} />
                Cancel
              </button>
            </div>
          )
        }
      >
        {!editingPassword ? (
          <div className="flex items-center gap-3">
            <div
              className="w-8 h-8 rounded-lg flex items-center justify-center"
              style={{ backgroundColor: "var(--color-forest-pale)" }}
            >
              <Lock size={14} style={{ color: "var(--color-forest)" }} strokeWidth={1.8} />
            </div>
            <div>
              <p className="text-sm font-medium" style={{ color: "var(--color-text-dark)" }}>Password</p>
              <p className="text-xs" style={{ color: "var(--color-text-muted)" }}>Last changed — unknown</p>
            </div>
            <span className="ml-auto text-lg tracking-widest" style={{ color: "var(--color-text-muted)" }}>
              ••••••••
            </span>
          </div>
        ) : (
          <div className="space-y-4">
            {pwError && (
              <div
                className="flex items-center gap-2 rounded-xl px-4 py-3 text-sm"
                style={{ backgroundColor: "#FEF2F2", color: "var(--color-terracotta)", border: "1px solid #FECACA" }}
              >
                <AlertTriangle size={14} strokeWidth={2} />
                {pwError}
              </div>
            )}
            <PasswordInput
              label="Current Password"
              name="currentPassword"
              value={pwForm.currentPassword}
              onChange={(e) => setPwForm((f) => ({ ...f, currentPassword: e.target.value }))}
              disabled={savingPw}
            />
            <PasswordInput
              label="New Password"
              name="newPassword"
              value={pwForm.newPassword}
              onChange={(e) => setPwForm((f) => ({ ...f, newPassword: e.target.value }))}
              disabled={savingPw}
            />
            <PasswordInput
              label="Confirm New Password"
              name="confirmPassword"
              value={pwForm.confirmPassword}
              onChange={(e) => setPwForm((f) => ({ ...f, confirmPassword: e.target.value }))}
              disabled={savingPw}
            />
            <p className="text-xs" style={{ color: "var(--color-text-muted)" }}>
              Minimum 8 characters. Use a mix of letters, numbers, and symbols.
            </p>
          </div>
        )}
      </SectionCard>

      {/* Toast */}
      {toast && (
        <Toast message={toast.message} type={toast.type} onDone={() => setToast(null)} />
      )}
    </div>
  );
}

