import { useEffect, useState, useMemo } from "react";
import {
  UserX,
  UserCheck,
  RefreshCw,
  Inbox,
  Loader2,
  Mail,
  ShieldOff,
  Calendar,
  Search,
  X,
  Plus,
  AlertCircle
} from "lucide-react";
import securityService from "../../services/securityService";

function SuspendModal({ isOpen, onClose, onSuspend }) {
  const [search, setSearch] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [reason, setReason] = useState("");
  const [selectedUser, setSelectedUser] = useState(null);
  const [suspending, setSuspending] = useState(false);

  useEffect(() => {
    if (!search.trim()) {
      setResults([]);
      return;
    }
    const delay = setTimeout(async () => {
      setLoading(true);
      try {
        const res = await securityService.getAllUsers(`search=${search}&status=active`);
        setResults(res.data?.users || []);
      } catch (err) {
        console.error("Search failed", err);
      } finally {
        setLoading(false);
      }
    }, 400);
    return () => clearTimeout(delay);
  }, [search]);

  const handleSuspend = async () => {
    if (!selectedUser || !reason.trim()) return;
    setSuspending(true);
    try {
      await securityService.suspendUser(selectedUser.id, reason);
      onSuspend({ ...selectedUser, status: 'suspended', suspended_at: new Date().toISOString() });
      onClose();
      setSelectedUser(null);
      setReason("");
    } catch (err) {
      console.error("Suspension failed", err);
    } finally {
      setSuspending(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />
      <div className="relative w-full max-w-md bg-white rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
        <div className="p-6 border-b border-border-soft flex items-center justify-between">
          <h3 className="font-bold text-text-dark flex items-center gap-2">
            <UserX size={18} className="text-terracotta" /> Restrict User Access
          </h3>
          <button onClick={onClose} className="p-2 hover:bg-cream rounded-full"><X size={18} /></button>
        </div>

        <div className="p-6 space-y-4">
          {!selectedUser ? (
            <>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-text-muted" size={16} />
                <input 
                  type="text" 
                  placeholder="Search by name or email..."
                  className="w-full pl-10 pr-4 py-3 bg-cream-light rounded-xl border-none text-sm focus:ring-2 focus:ring-forest/20 outline-none"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  autoFocus
                />
              </div>
              <div className="max-h-60 overflow-y-auto space-y-2">
                {loading ? (
                  <div className="flex justify-center py-8"><Loader2 size={24} className="animate-spin text-forest/20" /></div>
                ) : results.length > 0 ? (
                  results.map(u => (
                    <button 
                      key={u.id}
                      onClick={() => setSelectedUser(u)}
                      className="w-full flex items-center gap-3 p-3 hover:bg-cream-light rounded-xl transition-colors text-left"
                    >
                      <div className="w-8 h-8 rounded-lg bg-forest/5 flex items-center justify-center text-forest font-bold text-xs uppercase">
                        {u.name?.[0] || "?"}
                      </div>
                      <div>
                        <p className="text-sm font-bold text-text-dark">{u.name}</p>
                        <p className="text-[10px] text-text-muted">{u.email}</p>
                      </div>
                    </button>
                  ))
                ) : search && (
                  <p className="text-center py-8 text-xs text-text-muted">No active users found.</p>
                )}
              </div>
            </>
          ) : (
            <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
              <div className="flex items-center gap-3 p-3 bg-terracotta/5 rounded-xl border border-terracotta/10">
                <div className="w-10 h-10 rounded-lg bg-terracotta/10 flex items-center justify-center text-terracotta font-bold text-sm uppercase">
                  {selectedUser.name?.[0] || "?"}
                </div>
                <div className="flex-1">
                  <p className="text-sm font-bold text-text-dark">{selectedUser.name}</p>
                  <p className="text-[10px] text-text-muted">{selectedUser.email}</p>
                </div>
                <button onClick={() => setSelectedUser(null)} className="text-[10px] font-bold text-terracotta hover:underline">Change</button>
              </div>

              <div>
                <label className="block text-[10px] font-bold uppercase tracking-widest text-text-muted mb-2">Reason for Restriction</label>
                <textarea 
                  className="w-full p-4 bg-cream-light rounded-xl border-none text-sm focus:ring-2 focus:ring-terracotta/20 outline-none h-24 resize-none"
                  placeholder="Explain why this account is being restricted..."
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                />
              </div>

              <button 
                onClick={handleSuspend}
                disabled={suspending || !reason.trim()}
                className="w-full py-4 bg-text-dark text-white rounded-2xl text-sm font-bold flex items-center justify-center gap-2 hover:bg-black transition-all disabled:opacity-50"
              >
                {suspending ? <Loader2 size={16} className="animate-spin" /> : <ShieldOff size={16} />}
                Confirm Restriction
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function UserCard({ user, onUnsuspend }) {
  const [confirming, setConfirming] = useState(false);
  const [loading, setLoading] = useState(false);

  const { id, full_name, name, email, role, status, suspended_at } = user;
  const displayName = full_name || name || "Unknown User";

  const suspendedDate = suspended_at
    ? new Date(suspended_at).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })
    : "Recently";

  const initials = displayName.split(" ").map((n) => n[0]).join("").toUpperCase().slice(0, 2);

  const handleUnsuspend = async () => {
    setLoading(true);
    try {
      await securityService.unsuspendUser(id);
      onUnsuspend(id);
    } catch {
      // silent
    } finally {
      setLoading(false);
      setConfirming(false);
    }
  };

  return (
    <div
      className="flex items-start gap-5 rounded-3xl p-6 transition-all duration-300 hover:shadow-xl hover:-translate-y-1 bg-white border border-border-soft"
    >
      <div
        className="w-14 h-14 rounded-2xl flex items-center justify-center text-lg font-bold shrink-0 shadow-inner"
        style={{ backgroundColor: "#FEF2F2", color: "var(--color-terracotta)" }}
      >
        {initials}
      </div>

      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-3">
          <p className="text-base font-bold text-text-dark">{displayName}</p>
          <span
            className="text-[10px] font-bold px-2.5 py-1 rounded-full uppercase tracking-widest flex items-center gap-1"
            style={{
              backgroundColor: status === "banned" ? "#450a0a" : "#FEF2F2",
              color: status === "banned" ? "#fca5a5" : "var(--color-terracotta)",
            }}
          >
            {status}
          </span>
        </div>

        <div className="mt-2 flex flex-wrap gap-4 text-xs text-text-muted">
          <span className="flex items-center gap-1.5"><Mail size={12} strokeWidth={2} /> {email}</span>
          <span className="flex items-center gap-1.5 capitalize"><ShieldOff size={12} strokeWidth={2} /> {role || "Member"}</span>
          <span className="flex items-center gap-1.5"><Calendar size={12} strokeWidth={2} /> Restricted {suspendedDate}</span>
        </div>
      </div>

      <div className="shrink-0 flex items-center gap-2">
        {!confirming ? (
          <button
            onClick={() => setConfirming(true)}
            className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-bold transition-all bg-forest/5 text-forest hover:bg-forest hover:text-white"
          >
            <UserCheck size={14} />
            Reinstate
          </button>
        ) : (
          <div className="flex items-center gap-2 animate-in zoom-in-95 duration-200">
            <button
              onClick={handleUnsuspend}
              disabled={loading}
              className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-xs font-bold bg-forest text-white shadow-lg shadow-forest/20 disabled:opacity-60"
            >
              {loading ? <Loader2 size={12} className="animate-spin" /> : <UserCheck size={12} />}
              Confirm
            </button>
            <button
              onClick={() => setConfirming(false)}
              className="p-2 rounded-xl bg-cream hover:bg-black/5 text-text-muted"
            >
              <X size={16} />
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

export default function SuspendedUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const load = () => {
    setLoading(true);
    setError(null);
    securityService
      .getSuspendedUsers()
      .then((res) => setUsers(res.data?.users ?? []))
      .catch(() => setError("Failed to load restricted database."))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const handleUnsuspend = (id) => {
    setUsers((prev) => prev.filter((u) => u.id !== id));
  };

  const handleNewSuspension = (newUser) => {
    setUsers(prev => [newUser, ...prev]);
  };

  return (
    <div className="max-w-4xl mx-auto px-8 py-12 space-y-10">
      {/* Header */}
      <div className="flex items-end justify-between">
        <div>
          <h1 className="text-4xl font-bold tracking-tight text-text-dark font-display">
            Restricted Accounts
          </h1>
          <p className="mt-2 text-base text-text-muted">
            Manage users with limited or revoked access to the Bond ecosystem.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <button
            onClick={load}
            className="p-3 rounded-2xl bg-white border border-border-soft text-text-muted hover:bg-cream-light transition-all"
            title="Refresh List"
          >
            <RefreshCw size={18} className={loading ? "animate-spin" : ""} />
          </button>
          <button
            onClick={() => setIsModalOpen(true)}
            className="flex items-center gap-2 px-6 py-3 bg-text-dark text-white rounded-2xl text-sm font-bold shadow-lg hover:bg-black transition-all"
          >
            <Plus size={18} /> Restrict User
          </button>
        </div>
      </div>

      {/* Overview Card */}
      {!loading && !error && (
        <div className="p-8 rounded-[2rem] bg-terracotta/[0.03] border border-terracotta/10 flex items-center gap-6">
          <div className="w-16 h-16 rounded-3xl bg-terracotta/10 flex items-center justify-center text-terracotta">
            <ShieldOff size={32} />
          </div>
          <div>
            <p className="text-2xl font-bold text-text-dark">{users.length} Active Suspensions</p>
            <p className="text-sm text-text-muted mt-1">Users currently blocked from login and platform activities.</p>
          </div>
          <div className="ml-auto hidden sm:block">
            <AlertCircle size={40} className="text-terracotta/20" />
          </div>
        </div>
      )}

      {/* Main List */}
      <div className="space-y-4">
        {loading ? (
          <div className="space-y-4">
            {[0, 1, 2].map((i) => (
              <div key={i} className="h-28 rounded-[2rem] animate-pulse bg-border-soft/20" />
            ))}
          </div>
        ) : error ? (
          <div className="py-20 text-center bg-terracotta/5 rounded-[2rem] border border-terracotta/10">
            <AlertCircle size={48} className="mx-auto text-terracotta mb-4" />
            <p className="text-text-dark font-bold text-lg">{error}</p>
            <button onClick={load} className="mt-4 text-sm font-bold text-terracotta underline">Try Again</button>
          </div>
        ) : users.length === 0 ? (
          <div className="flex flex-col items-center gap-4 py-24 bg-cream-light rounded-[2.5rem] border border-dashed border-border-soft">
            <div className="w-20 h-20 rounded-full bg-white flex items-center justify-center shadow-sm">
              <Inbox size={32} className="text-text-muted opacity-30" />
            </div>
            <div className="text-center">
              <p className="text-xl font-bold text-text-dark">Clean Slate</p>
              <p className="text-sm text-text-muted mt-1">No accounts are currently restricted.</p>
            </div>
          </div>
        ) : (
          <div className="grid gap-4">
            {users.map((u) => (
              <UserCard key={u.id} user={u} onUnsuspend={handleUnsuspend} />
            ))}
          </div>
        )}
      </div>

      <SuspendModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSuspend={handleNewSuspension} 
      />
    </div>
  );
}

import { useEffect, useRef, useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import {
  ShieldCheck, Users, FileText, Gift, Lock,
  MapPin, ChevronRight, Loader2, RefreshCw, AlertTriangle,
  Search, Building2,
} from "lucide-react";
import securityService from "../../services/securityService";
import communityService from "../../services/communityService";

// ── Status config ─────────────────────────────────────────────
const STATUS_CFG = {
  pending:  { label: "Pending",  bg: "#FEF3C7", text: "#92400E", dot: "#F59E0B" },
  verified: { label: "Verified", bg: "#D1FAE5", text: "#065F46", dot: "#10B981" },
  rejected: { label: "Rejected", bg: "#FEE2E2", text: "#991B1B", dot: "#EF4444" },
};

// ── Chip helper ───────────────────────────────────────────────
function Chip({ ok, label, icon: Icon }) {
  return (
    <span style={{
      display: "inline-flex", alignItems: "center", gap: 4,
      padding: "3px 8px", borderRadius: 99,
      fontSize: 10, fontWeight: 600,
      background: ok ? "#ECFDF5" : "#F3F4F6",
      color: ok ? "#065F46" : "#9CA3AF",
    }}>
      <Icon size={9} />
      {label}
    </span>
  );
}

export default function VerifyCommunities() {
  const navigate = useNavigate();

  const [communities,     setCommunities]     = useState([]);
  const [loading,         setLoading]         = useState(true);
  const [error,           setError]           = useState(null);
  const [search,          setSearch]          = useState("");
  const [filter,          setFilter]          = useState("all");
  const [verificationMap, setVerificationMap] = useState({});

  const cardsRef = useRef([]);

  // ── Fetch ──────────────────────────────────────────────────
  const load = useCallback(() => {
    setLoading(true);
    setError(null);

    securityService.getAllCommunities()
      .then((res) => {
        // FIX: unwrap axios response correctly
        // res.data is the ApiResponse body: { communities: [...] }
        const list = res?.data?.communities ?? res?.data ?? [];
        const safeList = Array.isArray(list) ? list : [];
        setCommunities(safeList);

        // FIX: only fetch verification for ids that are real non-empty strings
        const ids = safeList
          .map((c) => c?.id)
          .filter((id) => id && typeof id === "string" && id !== "undefined");

        if (ids.length === 0) return;

        Promise.allSettled(
          ids.map((id) =>
            communityService
              .getVerificationData(id)
              .then((r) => ({ id, data: r?.data ?? null }))
              .catch(() => ({ id, data: null }))
          )
        ).then((results) => {
          const map = {};
          results.forEach((r) => {
            if (r.status === "fulfilled" && r.value?.id) {
              map[r.value.id] = r.value.data;
            }
          });
          setVerificationMap(map);
        });
      })
      .catch((err) => {
        console.error("getPendingCommunities error:", err);
        setError("Failed to load communities.");
      })
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { load(); }, [load]);

  // ── GSAP animate cards ─────────────────────────────────────
  useEffect(() => {
    if (communities.length === 0) return;
    const els = cardsRef.current.filter(Boolean);
    if (els.length === 0) return;
    gsap.fromTo(els,
      { opacity: 0, y: 16 },
      { opacity: 1, y: 0, duration: 0.4, ease: "power2.out", stagger: 0.06, delay: 0.15 }
    );
  }, [communities]);

  // ── Filter + search ────────────────────────────────────────
  const filtered = communities.filter((c) => {
    const status = c.status ?? "pending";
    if (filter !== "all" && status !== filter) return false;
    if (search.trim()) {
      const q = search.toLowerCase();
      return (
        (c.name    ?? "").toLowerCase().includes(q) ||
        (c.village ?? "").toLowerCase().includes(q) ||
        (c.state   ?? "").toLowerCase().includes(q)
      );
    }
    return true;
  });

  // ── Chips for a community ─────────────────────────────────
  const getChips = (c) => {
    const v = verificationMap[c.id];
    const membersCount   = v?.members?.length   ?? 0;
    const docsCount      = v?.documents?.length ?? 0;
    const offeringsCount = v?.offerings?.length ?? 0;
    const consentOk      = !!c.consent_accepted_at;
    const regStep        = c.registration_step ?? 1;

    const checks = [regStep > 1, membersCount > 0, docsCount > 0, offeringsCount > 0, consentOk];
    const pct    = Math.round((checks.filter(Boolean).length / checks.length) * 100);

    return { membersCount, docsCount, offeringsCount, consentOk, pct };
  };

  // ── Loading ────────────────────────────────────────────────
  if (loading) return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "60vh", gap: 10 }}>
      <Loader2 size={20} className="animate-spin" style={{ color: "var(--color-forest)" }} />
      <span style={{ fontSize: 14, color: "var(--color-text-muted)" }}>Loading communities…</span>
    </div>
  );

  if (error) return (
    <div style={{ maxWidth: 480, margin: "80px auto", textAlign: "center", padding: "0 20px" }}>
      <AlertTriangle size={36} style={{ color: "#C0533A", margin: "0 auto 12px" }} />
      <h2 style={{ fontFamily: "var(--font-display)", marginBottom: 8 }}>Error</h2>
      <p style={{ fontSize: 14, color: "#7A8E84", marginBottom: 20 }}>{error}</p>
      <button onClick={load} style={{ padding: "10px 20px", borderRadius: 10, background: "#2D4A3E", color: "#fff", border: "none", cursor: "pointer", fontSize: 14 }}>
        Try again
      </button>
    </div>
  );

  return (
    <div>
      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 12 }}>
          <div>
            <h1 style={{ fontSize: 22, fontWeight: 700, color: "var(--color-text-dark)", margin: 0, display: "flex", alignItems: "center", gap: 10 }}>
              <ShieldCheck size={22} style={{ color: "var(--color-forest)" }} />
              Verify Communities
            </h1>
            <p style={{ fontSize: 13, color: "var(--color-text-muted)", margin: "4px 0 0" }}>
              Review and approve community registration applications.
            </p>
          </div>
        </div>
      </div>

      {/* Search + Filter */}
      <div style={{ display: "flex", gap: 10, marginBottom: 20, flexWrap: "wrap" }}>
        <div style={{ flex: 1, minWidth: 220, position: "relative" }}>
          <Search size={14} style={{ position: "absolute", left: 12, top: 12, color: "var(--color-text-muted)" }} />
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search by name, village, or state…"
            style={{
              width: "100%", padding: "10px 12px 10px 34px", borderRadius: 12,
              border: "1px solid var(--color-border-soft)", fontSize: 13,
              background: "#fff", outline: "none", color: "var(--color-text-dark)",
              boxSizing: "border-box",
            }}
          />
        </div>
      </div>

      <div style={{ display: "flex", gap: 12, marginBottom: 24, flexWrap: "wrap" }}>
        {[
          { 
            label: "Total",    
            count: communities.filter(c => ["pending", "verified"].includes(c.status ?? "pending")).length, 
            color: "var(--color-forest)" 
          },
          { 
            label: "Pending",  
            count: communities.filter((c) => (c.status ?? "pending") === "pending").length, 
            color: "#F59E0B" 
          },
          { 
            label: "Verified", 
            count: communities.filter((c) => c.status === "verified").length,      
            color: "#10B981" 
          },
          { 
            label: "Rejected", 
            count: communities.filter((c) => c.status === "rejected").length,      
            color: "#EF4444" 
          },
        ].map((s) => (
          <div key={s.label} style={{
            flex: "1 1 100px", padding: "14px 18px", borderRadius: 14,
            border: "1px solid var(--color-border-soft)", background: "#fff",
            display: "flex", flexDirection: "column", alignItems: "center", gap: 2,
          }}>
            <span style={{ fontSize: 22, fontWeight: 700, color: s.color }}>{s.count}</span>
            <span style={{ fontSize: 11, fontWeight: 600, color: "var(--color-text-muted)", textTransform: "uppercase", letterSpacing: "0.05em" }}>{s.label}</span>
          </div>
        ))}
      </div>

      {/* Empty state */}
      {filtered.length === 0 && (
        <div style={{
          textAlign: "center", padding: "60px 20px", borderRadius: 20,
          border: "1px dashed var(--color-border-soft)", background: "#fff",
        }}>
          <Building2 size={36} style={{ color: "var(--color-text-muted)", margin: "0 auto 12px" }} />
          <p style={{ fontSize: 15, fontWeight: 600, color: "var(--color-text-mid)", margin: 0 }}>
            {search ? "No communities match your search." : "No communities found."}
          </p>
          <p style={{ fontSize: 13, color: "var(--color-text-muted)", marginTop: 4 }}>
            Communities will appear here once they submit their registration.
          </p>
        </div>
      )}

      {/* Community cards */}
      <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
        {filtered.map((c, idx) => {
          // FIX: skip rendering cards with no valid id
          if (!c?.id || c.id === "undefined") return null;

          const status = c.status ?? "pending";
          const cfg    = STATUS_CFG[status] ?? STATUS_CFG.pending;
          const { membersCount, docsCount, offeringsCount, consentOk, pct } = getChips(c);
          const place  = [c.village, c.district, c.state].filter(Boolean).join(", ");

          return (
            <div
              key={c.id}
              ref={(el) => (cardsRef.current[idx] = el)}
              onClick={() => navigate(`/security/verify-communities/${c.id}`)}
              style={{
                opacity: 0,
                display: "flex", alignItems: "center", gap: 16,
                padding: "18px 22px", borderRadius: 16,
                border: "1px solid var(--color-border-soft)", background: "#fff",
                cursor: "pointer",
                transition: "box-shadow 0.2s, transform 0.15s",
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.boxShadow = "0 4px 20px rgba(45,74,62,0.1)";
                e.currentTarget.style.transform = "translateY(-1px)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.boxShadow = "none";
                e.currentTarget.style.transform = "none";
              }}
            >
              {/* Thumbnail */}
              <div style={{
                width: 64, height: 64, borderRadius: 14, flexShrink: 0, overflow: "hidden",
                background: "var(--color-forest-pale)",
                display: "flex", alignItems: "center", justifyContent: "center",
              }}>
                {c.cover_image_url
                  ? <img src={c.cover_image_url} alt={c.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                  : <Building2 size={24} style={{ color: "var(--color-forest)" }} />
                }
              </div>

              {/* Info */}
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4, flexWrap: "wrap" }}>
                  <h3 style={{ margin: 0, fontSize: 15, fontWeight: 700, color: "var(--color-text-dark)", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                    {c.name}
                  </h3>
                  <span style={{
                    fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 99,
                    background: cfg.bg, color: cfg.text, textTransform: "uppercase", letterSpacing: "0.05em",
                    display: "inline-flex", alignItems: "center", gap: 4, flexShrink: 0,
                  }}>
                    <span style={{ width: 6, height: 6, borderRadius: 99, background: cfg.dot }} />
                    {cfg.label}
                  </span>
                </div>

                {place && (
                  <p style={{ margin: "0 0 6px", fontSize: 12, color: "var(--color-text-muted)", display: "flex", alignItems: "center", gap: 4 }}>
                    <MapPin size={11} /> {place}
                  </p>
                )}

                <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                  <Chip ok={membersCount > 0}   label={`${membersCount} Member${membersCount !== 1 ? "s" : ""}`}   icon={Users} />
                  <Chip ok={docsCount > 0}       label={`${docsCount} Doc${docsCount !== 1 ? "s" : ""}`}           icon={FileText} />
                  <Chip ok={offeringsCount > 0}  label={`${offeringsCount} Offering${offeringsCount !== 1 ? "s" : ""}`} icon={Gift} />
                  <Chip ok={consentOk}           label={consentOk ? "Consent ✓" : "No Consent"}                   icon={Lock} />
                </div>
              </div>

              {/* Progress + Arrow */}
              <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6, flexShrink: 0 }}>
                <span style={{
                  fontSize: 18, fontWeight: 700,
                  color: pct === 100 ? "#10B981" : pct >= 60 ? "#F59E0B" : "var(--color-text-muted)",
                }}>
                  {pct}%
                </span>
                <div style={{ width: 48, height: 5, borderRadius: 99, background: "#F0EBE3", overflow: "hidden" }}>
                  <div style={{
                    height: "100%", borderRadius: 99, width: `${pct}%`,
                    background: pct === 100 ? "#10B981" : pct >= 60 ? "#F59E0B" : "#D1C9BF",
                    transition: "width 0.6s ease",
                  }} />
                </div>
              </div>

              <ChevronRight size={16} style={{ color: "var(--color-text-muted)", flexShrink: 0 }} />
            </div>
          );
        })}
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from "react";
import { useParams, useLocation, useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import { CheckCircle, AlertCircle, Calendar, Users, ArrowRight, Shield, MapPin, Star, Upload } from "lucide-react";
import { useAuth } from "../../context/AuthContext";
import bookingService from "../../services/bookingService";
import experienceService from "../../services/experienceService";
import PageShell from "../PageShell";

export default function ConfirmBooking() {
  const { id } = useParams();
  const { state } = useLocation();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [exp, setExp] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [confirming, setConfirming] = useState(false);
  const [idFile, setIdFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);

  const date = state?.date || new Date().toISOString().split("T")[0];
  const guests = state?.guests || 2;

  const cardRef = useRef(null);

  useEffect(() => {
    if (cardRef.current) {
      gsap.fromTo(
        cardRef.current,
        { opacity: 0, y: 20 },
        { opacity: 1, y: 0, duration: 0.6, ease: "power3.out" }
      );
    }
  }, [loading]);

  useEffect(() => {
    const fetchExp = async () => {
      try {
        const res = await experienceService.getById(id);
        setExp(res?.data?.experience || res?.experience);
      } catch (err) {
        setError(err.message || "Failed to load experience details.");
      } finally {
        setLoading(false);
      }
    };
    fetchExp();
  }, [id]);

  const handleConfirm = async () => {
    if (!idFile) {
      setError("Please upload a photo copy of your ID to confirm this booking.");
      return;
    }
    setConfirming(true);
    try {
      const formData = new FormData();
      formData.append("experience_id", id);
      formData.append("booking_date", date);
      formData.append("num_guests", guests);
      formData.append("special_requests", "");
      formData.append("document", idFile);

      await bookingService.create(formData);
      navigate("/tourist/bookings");
    } catch (err) {
      setError(err.message || "Failed to confirm booking.");
      setConfirming(false);
    }
  };

  if (loading) {
    return (
      <PageShell>
        <div className="min-h-screen flex items-center justify-center bg-[#FAF7F2]">
          <span className="h-8 w-8 animate-spin rounded-full border-4 border-[#3E7A58]/30 border-t-[#3E7A58]" />
        </div>
      </PageShell>
    );
  }

  if (error && !exp) {
    return (
      <PageShell>
        <div className="min-h-screen flex flex-col items-center justify-center bg-[#FAF7F2] text-[#5C1A1A] gap-3">
          <AlertCircle size={32} />
          <p className="text-sm font-medium">{error}</p>
          <button onClick={() => navigate(-1)} className="text-xs underline mt-2">Go back</button>
        </div>
      </PageShell>
    );
  }

  const pricePerPerson = parseFloat(exp?.price_per_person) || 0;
  const totalAmount = pricePerPerson * guests;

  return (
    <PageShell>
      <div className="min-h-screen bg-[#FAF7F2] px-4 pt-28 pb-16 flex items-start justify-center">
        <div ref={cardRef} className="max-w-4xl w-full bg-white rounded-[24px] border border-[#E8E1D5] p-6 md:p-8 shadow-sm flex flex-col md:flex-row gap-8">
          
          {/* Left Column: Details & ID Proof */}
          <div className="flex-1">
            {/* Header */}
            <div className="mb-6">
              <h1 className="text-2xl font-bold text-[#1A2820]" style={{ fontFamily: "'Playfair Display', serif" }}>
                Confirm Booking
              </h1>
              <p className="text-sm text-[#7A9285] mt-1">Review details before starting your journey</p>
            </div>

            {/* Experience snapshot */}
            <div className="bg-[#FAF7F2] rounded-[18px] p-4 border border-[#E8E1D5] mb-5 flex gap-4">
              {exp?.cover_image_url ? (
                <img src={exp.cover_image_url} alt={exp.title} className="w-20 h-20 object-cover rounded-[12px] border border-[#E0D8CE]" />
              ) : (
                <div className="w-20 h-20 bg-[#D4E6DC] text-[#3E7A58] rounded-[12px] flex items-center justify-center border border-[#E0D8CE]">
                  <MapPin size={24} />
                </div>
              )}
              <div className="flex-1 flex flex-col justify-center">
                <span className="text-xs font-semibold text-[#3E7A58] uppercase tracking-wide">{exp?.category || "Cultural"}</span>
                <h3 className="text-base font-semibold text-[#1A2820] mt-0.5 line-clamp-2">{exp?.title}</h3>
                <div className="flex items-center gap-1 mt-1 text-xs text-[#7A9285]">
                  <Star size={12} className="fill-amber-400 stroke-amber-400" />
                  <span>{exp?.avg_rating ? parseFloat(exp.avg_rating).toFixed(1) : "0.0"}</span>
                </div>
              </div>
            </div>

            {/* User Details */}
            <div className="mb-5">
              <span className="text-xs font-semibold text-[#9A9285] uppercase tracking-wider block mb-2">Guest Details</span>
              <div className="bg-white border border-[#E0D8CE] rounded-[14px] p-4 text-sm text-[#1A2820] flex flex-col gap-2">
                <div className="flex justify-between">
                  <span className="text-[#7A9285]">Name</span>
                  <span className="font-medium">{user?.full_name || user?.name}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-[#7A9285]">Email</span>
                  <span className="font-medium">{user?.email}</span>
                </div>
              </div>
            </div>

            {/* ID Proof Upload */}
            <div className="mb-0">
              <span className="text-xs font-semibold text-[#9A9285] uppercase tracking-wider block mb-2">Upload ID Proof</span>
              <div className="bg-[#FAF7F2] border border-[#E0D8CE] rounded-[14px] p-4 text-sm text-[#1A2820]">
                <label className="flex flex-col items-center justify-center border-2 border-dashed border-[#D9D0C2] rounded-[10px] p-6 cursor-pointer bg-white hover:border-[#3E7A58] transition-colors">
                  {previewUrl ? (
                    <img src={previewUrl} alt="ID Preview" className="w-full max-h-32 object-contain rounded-[8px] mb-2" />
                  ) : (
                    <Upload className="h-6 w-6 text-[#7A9285] mb-2" />
                  )}
                  <span className="text-xs font-semibold text-[#1A2820] text-center break-all px-2">
                    {idFile ? idFile.name : "Click to upload Photo ID proof"}
                  </span>
                  <span className="text-[10px] text-[#7A9285] mt-1">PDF, JPG, PNG up to 10MB</span>
                  <input
                    type="file"
                    accept="image/*,application/pdf"
                    className="hidden"
                    onChange={(e) => {
                      if (e.target.files?.[0]) {
                        const file = e.target.files[0];
                        setIdFile(file);
                        setError(null);
                        if (file.type.startsWith("image/")) {
                          const reader = new FileReader();
                          reader.onloadend = () => setPreviewUrl(reader.result);
                          reader.readAsDataURL(file);
                        } else {
                          setPreviewUrl(null);
                        }
                      }
                    }}
                  />
                </label>
              </div>
            </div>
          </div>

          {/* Right Column: Summary & Action CTA */}
          <div className="w-full md:w-[340px] flex flex-col justify-between border-t md:border-t-0 md:border-l border-[#E8E1D5] pt-6 md:pt-0 md:pl-8">
            <div>
              <span className="text-xs font-semibold text-[#9A9285] uppercase tracking-wider block mb-3">Experience Summary</span>
              <div className="bg-[#FAF7F2] border border-[#E0D8CE] rounded-[14px] p-4 text-sm text-[#1A2820] flex flex-col gap-3 mb-4">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2 text-[#7A9285]">
                    <Calendar size={16} />
                    <span>Date</span>
                  </div>
                  <span className="font-medium">{new Date(date).toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" })}</span>
                </div>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2 text-[#7A9285]">
                    <Users size={16} />
                    <span>Guests</span>
                  </div>
                  <span className="font-medium">{guests} {guests === 1 ? "person" : "people"}</span>
                </div>
                <div className="h-px bg-[#E0D8CE] my-1" />
                <div className="flex justify-between text-xs text-[#7A9285]">
                  <span>₹{pricePerPerson.toLocaleString()} × {guests} guests</span>
                  <span>₹{totalAmount.toLocaleString()}</span>
                </div>
                <div className="flex justify-between text-base font-bold text-[#1A2820] mt-1">
                  <span>Total Amount</span>
                  <span style={{ color: "var(--color-forest)" }}>₹{totalAmount.toLocaleString()}</span>
                </div>
              </div>

              {error && (
                <div className="flex items-center gap-2 rounded-[12px] border border-[#EBB8AA] bg-[#FAF0EC] px-4 py-3 text-xs text-[#A04D38] mb-4">
                  <AlertCircle size={14} className="shrink-0" />
                  <span>{error}</span>
                </div>
              )}
            </div>

            <div className="mt-auto">
              <button
                onClick={handleConfirm}
                disabled={confirming}
                className="w-full flex items-center justify-center gap-2 rounded-[14px] py-3.5 font-semibold text-sm text-[#F2EDE4] transition-all duration-200 hover:brightness-110 disabled:opacity-50 disabled:cursor-not-allowed shadow-sm active:scale-[0.98]"
                style={{ background: "var(--color-forest-deep)" }}
              >
                {confirming ? (
                  <span className="h-5 w-5 animate-spin rounded-full border-2 border-white/30 border-t-white" />
                ) : (
                  <>Confirm Booking <ArrowRight size={16} /></>
                )}
              </button>

              <div className="flex items-center justify-center gap-1.5 mt-4 text-[11px] text-[#7A9285]">
                <Shield size={13} />
                <span>Secure booking supported by Bond Verification</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </PageShell>
  );
}

import { useState, useEffect, useRef, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import { MapPin, Star, Trash2, Compass, Users, AlertCircle } from "lucide-react";
import userService from "../../services/userService";
import PageShell from "../PageShell";

// ─── Skeleton ──────────────────────────────────────────────────
function SkeletonCard() {
  return (
    <div className="bg-white rounded-[16px] border border-[#E0DAD0] overflow-hidden animate-pulse">
      <div className="h-[130px] bg-[#E8E3DA]" />
      <div className="p-4 space-y-3">
        <div className="h-4 w-3/4 rounded bg-[#EDE8E0]" />
        <div className="h-3 w-1/2 rounded bg-[#EDE8E0]" />
        <div className="h-3 w-full rounded bg-[#F5F2EE]" />
        <div className="h-3 w-4/5 rounded bg-[#F5F2EE]" />
      </div>
    </div>
  );
}

// ─── Card ──────────────────────────────────────────────────────
function FavoriteCard({ item, type, onRemove, index }) {
  const ref      = useRef(null);
  const navigate = useNavigate();
  const isExp    = type === "experience";

  useEffect(() => {
    gsap.fromTo(
      ref.current,
      { opacity: 0, y: 20 },
      { opacity: 1, y: 0, duration: 0.45, delay: index * 0.07, ease: "power3.out" }
    );
  }, [index]);

  const handleRemove = (e) => {
    e.stopPropagation();
    gsap.to(ref.current, {
      opacity: 0, scale: 0.94, duration: 0.28, ease: "power3.in",
      onComplete: () => onRemove(item.target_id, type),
    });
  };

  const title = item.name ?? `${isExp ? "Experience" : "Community"} #${String(item.target_id).slice(0, 6)}`;
  const place = item.location ?? null;

  return (
    <div
      ref={ref}
      onClick={() => navigate(isExp ? `/tourist/experience/${item.slug}` : `/tourist/community/${item.slug}`)}
      className="group bg-white rounded-[16px] border border-[#E0DAD0] overflow-hidden
                 hover:border-[#A8C4B0] transition-colors duration-200 cursor-pointer"
    >
      {/* Image / placeholder */}
      <div
        className="h-[130px] relative flex items-center justify-center overflow-hidden"
        style={{ background: isExp ? "#D4E6DC" : "#EBD9C0" }}
      >
        {item.cover_image_url ? (
          <img
            src={item.cover_image_url}
            alt={title}
            className="w-full h-full object-cover group-hover:scale-[1.03] transition-transform duration-500"
          />
        ) : (
          <div className="opacity-40">
            {isExp
              ? <Compass size={36} color="#2D6A4A" strokeWidth={1.5} />
              : <Users   size={36} color="#A0622A" strokeWidth={1.5} />
            }
          </div>
        )}

        {/* Type badge */}
        <div
          className="absolute top-2.5 left-2.5 flex items-center gap-1 text-[10px] font-medium
                     uppercase tracking-wider px-2.5 py-1 rounded-full"
          style={{
            background: isExp ? "rgba(28,61,46,.82)" : "rgba(124,74,20,.82)",
            color:      isExp ? "#D6EDE0" : "#F5E4CC",
          }}
        >
          {isExp ? <Compass size={10} /> : <Users size={10} />}
          {isExp ? "Experience" : "Community"}
        </div>

        {/* Remove */}
        <button
          onClick={handleRemove}
          title="Remove from favorites"
          className="absolute top-2.5 right-2.5 w-7 h-7 rounded-full flex items-center
                     justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200
                     hover:scale-110 active:scale-95"
          style={{ background: "rgba(255,255,255,.92)" }}
        >
          <Trash2 size={13} color="#B45C5C" />
        </button>
      </div>

      {/* Body */}
      <div className="p-4">
        <h3
          className="text-[14px] font-medium text-[#111D17] leading-snug mb-1.5 line-clamp-2"
          style={{ fontFamily: "Georgia, serif" }}
        >
          {title}
        </h3>

        {place && (
          <p className="flex items-center gap-1 text-[12px] text-[#8A8278] mb-2">
            <MapPin size={11} className="shrink-0" />
            {place}
          </p>
        )}

        {item.description && (
          <p className="text-[12px] text-[#8A8278] leading-relaxed line-clamp-2 mb-3">
            {item.description}
          </p>
        )}

        {/* Footer */}
        <div
          className="flex items-center justify-between pt-2.5 mt-auto"
          style={{ borderTop: "0.5px solid #EDE8E0" }}
        >
          <div className="flex items-center gap-1.5">
            {item.rating ? (
              <>
                <Star size={12} fill="#C4893F" color="#C4893F" />
                <span className="text-[12px] font-medium text-[#5A3D10]">
                  {Number(item.rating).toFixed(1)}
                </span>
              </>
            ) : (
              <span className="text-[11px] text-[#B0A89A]">No rating yet</span>
            )}
          </div>
          <span className="text-[11px] text-[#9A9285]">
            {isExp ? "View experience" : "View community"} →
          </span>
        </div>
      </div>
    </div>
  );
}

// ─── Section ───────────────────────────────────────────────────
function Section({ label, items, type, onRemove, visible }) {
  if (!visible || items.length === 0) return null;
  return (
    <div className="mb-8">
      <p
        className="text-[11px] font-medium uppercase tracking-widest mb-3.5"
        style={{ color: "#9A9285" }}
      >
        {label}
      </p>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {items.map((item, i) => (
          <FavoriteCard
            key={`${item.target_type}-${item.target_id}`}
            item={item}
            type={type}
            onRemove={onRemove}
            index={i}
          />
        ))}
      </div>
    </div>
  );
}

// ─── Empty ─────────────────────────────────────────────────────
function EmptyAll() {
  return (
    <div className="flex flex-col items-center py-24 text-center">
      <div
        className="w-14 h-14 rounded-2xl flex items-center justify-center mb-4"
        style={{ background: "#EDE8DE" }}
      >
        <Star size={24} color="#B09070" strokeWidth={1.5} />
      </div>
      <p className="text-[15px] font-medium text-[#111D17] mb-1">Nothing saved yet</p>
      <p className="text-[13px] text-[#9A9285] max-w-[200px] leading-relaxed">
        Explore and save experiences or communities you love
      </p>
    </div>
  );
}

// ─── Main ──────────────────────────────────────────────────────
const FILTERS = [
  { key: "all",        label: "All"          },
  { key: "experience", label: "Experiences"  },
  { key: "community",  label: "Communities"  },
];

export default function Favorites() {
  const [favorites, setFavorites] = useState([]);
  const [filter,    setFilter]    = useState("all");
  const [loading,   setLoading]   = useState(true);
  const [error,     setError]     = useState("");

  const headerRef = useRef(null);

  useEffect(() => {
    gsap.fromTo(
      headerRef.current,
      { opacity: 0, y: -16 },
      { opacity: 1, y: 0, duration: 0.6, ease: "power3.out" }
    );
  }, []);

  useEffect(() => {
    setLoading(true);
    userService
      .getFavorites()
      .then((res) => {
        const data = res?.data?.favorites ?? res?.favorites ?? [];
        setFavorites(Array.isArray(data) ? data : []);
      })
      .catch((err) => setError(err.message || "Failed to load favorites."))
      .finally(() => setLoading(false));
  }, []);

  const handleRemove = useCallback(async (targetId, targetType) => {
    try {
      await userService.removeFavorite(targetType, targetId);
      setFavorites((prev) =>
        prev.filter((f) => !(f.target_id === targetId && f.target_type === targetType))
      );
    } catch (err) {
      console.error("Remove favorite failed:", err);
    }
  }, []);

  const experiences = favorites.filter((f) => f.target_type === "experience");
  const communities = favorites.filter((f) => f.target_type === "community");
  const total       = favorites.length;

  return (
    <PageShell>
      <div className="min-h-screen px-6 py-10" style={{ background: "#F7F4EF" }}>
        <div className="max-w-5xl mx-auto">

          {/* ── Hero header ── */}
          <div ref={headerRef} className="flex items-end justify-between mb-8 flex-wrap gap-4">
            <div>
              <p
                className="text-[11px] font-medium uppercase tracking-[.1em] mb-2"
                style={{ color: "#7A8C80" }}
              >
                My collection
              </p>
              <h1
                className="text-[32px] leading-[1.1] font-medium text-[#111D17]"
                style={{ fontFamily: "Georgia, serif" }}
              >
                Your saved{" "}
                <span style={{ color: "#2D6A4A" }}>places</span>
              </h1>

              {!loading && total > 0 && (
                <div className="flex items-center gap-2 mt-3">
                  {experiences.length > 0 && (
                    <span
                      className="text-[12px] font-medium px-3 py-1 rounded-full"
                      style={{ background: "#D6EDE0", color: "#1C5C38" }}
                    >
                      {experiences.length} experience{experiences.length !== 1 ? "s" : ""}
                    </span>
                  )}
                  {communities.length > 0 && (
                    <span
                      className="text-[12px] font-medium px-3 py-1 rounded-full"
                      style={{ background: "#F0E8DA", color: "#7A4F1E" }}
                    >
                      {communities.length} {communities.length !== 1 ? "communities" : "community"}
                    </span>
                  )}
                </div>
              )}
            </div>

            {/* Filter pills */}
            <div className="flex gap-2">
              {FILTERS.map((f) => (
                <button
                  key={f.key}
                  onClick={() => setFilter(f.key)}
                  className="text-[12px] font-medium px-4 py-1.5 rounded-full border transition-all duration-200"
                  style={{
                    background:   filter === f.key ? "#1C3D2E" : "#fff",
                    color:        filter === f.key ? "#F2EDE4" : "#5A6360",
                    borderColor:  filter === f.key ? "#1C3D2E" : "#D1CBC0",
                  }}
                >
                  {f.label}
                </button>
              ))}
            </div>
          </div>

          {/* ── Divider ── */}
          <div style={{ height: "0.5px", background: "#E3DDD5", marginBottom: "28px" }} />

          {/* ── Content ── */}
          {loading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {[...Array(6)].map((_, i) => <SkeletonCard key={i} />)}
            </div>
          ) : error ? (
            <div className="flex flex-col items-center py-20 text-center">
              <div
                className="w-12 h-12 rounded-xl flex items-center justify-center mb-3"
                style={{ background: "#FEF2F2" }}
              >
                <AlertCircle size={20} color="#B45C5C" />
              </div>
              <p className="text-[14px] font-medium text-[#111D17]">Something went wrong</p>
              <p className="text-[12px] mt-1" style={{ color: "#9A9285" }}>{error}</p>
              <button
                onClick={() => window.location.reload()}
                className="mt-4 text-[12px] font-medium px-4 py-2 rounded-full"
                style={{ background: "#1C3D2E", color: "#F2EDE4" }}
              >
                Try again
              </button>
            </div>
          ) : total === 0 ? (
            <EmptyAll />
          ) : (
            <>
              <Section
                label="Experiences"
                items={experiences}
                type="experience"
                onRemove={handleRemove}
                visible={filter === "all" || filter === "experience"}
              />
              <Section
                label="Communities"
                items={communities}
                type="community"
                onRemove={handleRemove}
                visible={filter === "all" || filter === "community"}
              />
              {/* Edge case: filter active but that type is empty */}
              {((filter === "experience" && experiences.length === 0) ||
                (filter === "community"  && communities.length  === 0)) && (
                <EmptyAll />
              )}
            </>
          )}
        </div>
      </div>
    </PageShell>
  );
}

import { useState, useEffect, useRef } from "react";
import { gsap } from "gsap";
import { Sparkles, Check, Save, AlertCircle, CheckCircle } from "lucide-react";
import userService from "../../services/userService";
import PageShell from "../PageShell";

// All available interest tags
const ALL_INTERESTS = [
  { label: "Culture",      emoji: "🏛️" },
  { label: "Food",         emoji: "🍛" },
  { label: "Craft",        emoji: "🪡" },
  { label: "Nature",       emoji: "🌿" },
  { label: "Festivals",    emoji: "🎉" },
  { label: "Photography",  emoji: "📷" },
  { label: "Trekking",     emoji: "🥾" },
  { label: "Homestay",     emoji: "🏡" },
  { label: "Meditation",   emoji: "🧘" },
  { label: "Wildlife",     emoji: "🦚" },
  { label: "Rivers",       emoji: "🌊" },
  { label: "Weaving",      emoji: "🧵" },
  { label: "Music",        emoji: "🎵" },
  { label: "Agriculture",  emoji: "🌾" },
  { label: "Eco-tourism",  emoji: "♻️" },
  { label: "Slow travel",  emoji: "🚶" },
];

function InterestChip({ item, selected, onToggle, index }) {
  const ref = useRef(null);

  useEffect(() => {
    gsap.fromTo(ref.current,
      { opacity: 0, scale: 0.8, y: 16 },
      { opacity: 1, scale: 1, y: 0, duration: 0.45, delay: index * 0.04, ease: "back.out(1.4)" }
    );
  }, []);

  const handleClick = () => {
    gsap.to(ref.current, { scale: 0.9, duration: 0.08, yoyo: true, repeat: 1, ease: "power2.inOut" });
    onToggle(item.label);
  };

  return (
    <button
      ref={ref}
      type="button"
      onClick={handleClick}
      className="relative flex items-center gap-2 rounded-full px-4 py-2.5 text-sm font-medium transition-all duration-200 border"
      style={{
        background:   selected ? "#1C3D2E" : "#FFFFFF",
        borderColor:  selected ? "#1C3D2E" : "#E0D8CE",
        color:        selected ? "#F2EDE4" : "#3D5448",
      }}
    >
      <span>{item.emoji}</span>
      <span>{item.label}</span>
      {selected && (
        <span className="ml-0.5">
          <Check size={13} color="#A8CCBA" />
        </span>
      )}
    </button>
  );
}

function Toast({ type, message, onDone }) {
  const ref = useRef(null);
  useEffect(() => {
    gsap.timeline()
      .fromTo(ref.current, { y: 20, opacity: 0 }, { y: 0, opacity: 1, duration: 0.4, ease: "power3.out" })
      .to(ref.current, { y: 20, opacity: 0, duration: 0.4, ease: "power3.in", delay: 2.5, onComplete: onDone });
  }, []);
  const ok = type === "success";
  return (
    <div ref={ref} className="fixed bottom-6 right-6 z-50 flex items-center gap-2.5 rounded-[12px] px-4 py-3 shadow-xl text-sm font-medium"
      style={{ background: ok ? "#1C3D2E" : "#5C1A1A", color: "#F2EDE4" }}>
      {ok ? <CheckCircle size={16} /> : <AlertCircle size={16} />}
      {message}
    </div>
  );
}

export default function Interests() {
  const [selected, setSelected] = useState(new Set());
  const [loading, setLoading]   = useState(true);
  const [saving, setSaving]     = useState(false);
  const [toast, setToast]       = useState(null);
  const headerRef = useRef(null);
  const btnRef    = useRef(null);

  useEffect(() => {
    gsap.fromTo(headerRef.current, { opacity: 0, y: -14 }, { opacity: 1, y: 0, duration: 0.6, ease: "power3.out" });
  }, []);

  // Load saved interests
  useEffect(() => {
    userService.getInterests()
      .then(res => {
        const arr = res?.data?.interests ?? res?.interests ?? [];
        setSelected(new Set(Array.isArray(arr) ? arr : []));
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const toggle = (label) => {
    setSelected(prev => {
      const next = new Set(prev);
      next.has(label) ? next.delete(label) : next.add(label);
      return next;
    });
  };

  const handleSave = async () => {
    setSaving(true);
    gsap.to(btnRef.current, { scale: 0.97, duration: 0.1, yoyo: true, repeat: 1 });
    try {
      await userService.updateInterests([...selected]);
      setToast({ type: "success", message: "Interests saved!", key: Date.now() });
    } catch (err) {
      setToast({ type: "error", message: err.message || "Save failed.", key: Date.now() });
    } finally {
      setSaving(false);
    }
  };

  return (
    <PageShell>
      <div className="min-h-screen bg-[#FAF7F2] px-4 py-8">
        <div className="max-w-2xl mx-auto">

          {/* Header */}
          <div ref={headerRef} className="mb-6">
            <div className="flex items-center gap-3 mb-1">
              <div className="w-10 h-10 rounded-xl flex items-center justify-center" style={{ background: "#F0EDE5" }}>
                <Sparkles size={18} color="#C4893F" />
              </div>
              <h1 className="text-2xl font-bold text-[#1A2820]" style={{ fontFamily: "'Playfair Display', serif" }}>
                Travel Interests
              </h1>
            </div>
            <p className="text-sm text-[#9A9285] ml-[52px]">
              Tune recommendations around the experiences you care about
            </p>
          </div>

          {/* Selection counter */}
          {!loading && (
            <div className="flex items-center justify-between mb-4">
              <p className="text-xs text-[#9A9285]">
                <span className="font-semibold text-[#1A2820]">{selected.size}</span> selected
              </p>
              {selected.size > 0 && (
                <button onClick={() => setSelected(new Set())} className="text-xs text-[#B45C5C] hover:underline">
                  Clear all
                </button>
              )}
            </div>
          )}

          {/* Chips grid */}
          {loading ? (
            <div className="flex flex-wrap gap-3">
              {[...Array(12)].map((_, i) => (
                <div key={i} className="h-10 rounded-full bg-[#E8E1D5] animate-pulse" style={{ width: `${80 + Math.random() * 60}px` }} />
              ))}
            </div>
          ) : (
            <div className="flex flex-wrap gap-3 mb-8">
              {ALL_INTERESTS.map((item, i) => (
                <InterestChip
                  key={item.label}
                  item={item}
                  selected={selected.has(item.label)}
                  onToggle={toggle}
                  index={i}
                />
              ))}
            </div>
          )}

          {/* Save button */}
          <div className="sticky bottom-4">
            <button
              ref={btnRef}
              type="button"
              onClick={handleSave}
              disabled={saving || loading}
              className="w-full flex items-center justify-center gap-2 rounded-[14px] py-3.5 text-sm font-semibold shadow-lg transition-all disabled:opacity-60 hover:opacity-90"
              style={{ background: "#1C3D2E", color: "#F2EDE4" }}
            >
              {saving
                ? <span className="h-4 w-4 animate-spin rounded-full border-2 border-white/30 border-t-white" />
                : <><Save size={15} /> Save interests</>
              }
            </button>
          </div>
        </div>
      </div>

      {toast && <Toast key={toast.key} type={toast.type} message={toast.message} onDone={() => setToast(null)} />}
    </PageShell>
  );
}

import { useState, useEffect, useRef } from "react";
import { gsap } from "gsap";
import {
  Calendar, MapPin, Users, IndianRupee, Clock, CheckCircle,
  XCircle, AlertCircle, Hourglass, ChevronRight, Inbox, FileText,
  Star
} from "lucide-react";
import bookingService from "../../services/bookingService";
import PageShell from "../PageShell";
import ReviewModal from "../../components/features/bookings/ReviewModal";

const STATUS_CONFIG = {
  confirmed: { label: "Confirmed", icon: CheckCircle,  bg: "#E5EEE8", text: "#2A4D32", dot: "#4A8B5C" },
  pending:   { label: "Pending",   icon: Hourglass,    bg: "#F0EDE5", text: "#5C4A2A", dot: "#B48A3C" },
  completed: { label: "Completed", icon: CheckCircle,  bg: "#E8E5F0", text: "#2A2A5C", dot: "#5C5CB4" },
  cancelled: { label: "Cancelled", icon: XCircle,      bg: "#F0E8E8", text: "#5C2A2A", dot: "#B45C5C" },
  rejected:  { label: "Rejected",  icon: AlertCircle,  bg: "#F0E8E8", text: "#5C2A2A", dot: "#B45C5C" },
};

const FILTERS = ["all", "pending", "confirmed", "completed", "cancelled"];

function BookingCard({ booking, index, onCancel, onReviewOpen }) {
  const ref = useRef(null);
  const cfg = STATUS_CONFIG[booking.status] ?? STATUS_CONFIG.pending;
  const Icon = cfg.icon;
  const [cancelling, setCancelling] = useState(false);

  const handleCancel = async (e) => {
    e.stopPropagation();
    if (!window.confirm("Are you sure you want to cancel this booking?")) return;
    setCancelling(true);
    try {
      await bookingService.cancel(booking.id);
      if (onCancel) onCancel(booking.id);
    } catch (err) {
      alert(err.response?.data?.message || err.message || "Failed to cancel booking");
    } finally {
      setCancelling(false);
    }
  };

  useEffect(() => {
    gsap.fromTo(ref.current,
      { opacity: 0, x: -20 },
      { opacity: 1, x: 0, duration: 0.5, delay: index * 0.08, ease: "power3.out" }
    );
  }, []);

  const handleMouseEnter = () => gsap.to(ref.current, { x: 4, duration: 0.2, ease: "power2.out" });
  const handleMouseLeave = () => gsap.to(ref.current, { x: 0, duration: 0.2, ease: "power2.out" });

  const dateStr = booking.booking_date
    ? new Date(booking.booking_date).toLocaleDateString("en-IN", { day: "numeric", month: "short", year: "numeric" })
    : booking.date;

  return (
    <div
      ref={ref}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      className="group bg-white rounded-[16px] border border-[#E8E1D5] p-4 hover:shadow-md transition-shadow duration-300 cursor-pointer"
    >
      <div className="flex items-start justify-between gap-3">
        {/* Left: info */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            {/* Status pill */}
            <span className="inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5 text-xs font-semibold"
              style={{ background: cfg.bg, color: cfg.text }}>
              <span className="w-1.5 h-1.5 rounded-full" style={{ background: cfg.dot }} />
              {cfg.label}
            </span>
          </div>

          <h3 className="font-semibold text-[#1A2820] text-sm leading-snug truncate" style={{ fontFamily: "'Playfair Display', serif" }}>
            {booking.experience_title ?? booking.title ?? booking.experience?.title ?? "Experience"}
          </h3>

          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mt-2 text-xs text-[#9A9285]">
            {(booking.location ?? booking.experience?.community?.village) && (
              <span className="flex items-center gap-1"><MapPin size={11} />{booking.location ?? booking.experience?.community?.village}</span>
            )}
            {dateStr && (
              <span className="flex items-center gap-1"><Calendar size={11} />{dateStr}</span>
            )}
            {booking.num_guests && (
              <span className="flex items-center gap-1"><Users size={11} />{booking.num_guests} guest{booking.num_guests !== 1 ? "s" : ""}</span>
            )}
          </div>
        </div>

        {/* Right: amount */}
        <div className="text-right shrink-0">
          <div className="flex items-center justify-end gap-0.5">
            <IndianRupee size={13} className="text-[#1A2820]" />
            <span className="text-base font-bold text-[#1A2820]" style={{ fontFamily: "'Playfair Display', serif" }}>
              {(booking.total_amount ?? booking.total_price ?? booking.amount)?.toLocaleString("en-IN") ?? "—"}
            </span>
          </div>
          <p className="text-xs text-[#C4B8A8] mt-0.5">total</p>
        </div>
      </div>

      {/* Special requests */}
      {booking.special_requests && (
        <p className="mt-2 text-xs text-[#9A9285] italic border-t border-[#F0EBE3] pt-2">
          "{booking.special_requests}"
        </p>
      )}

      {/* ID Proof Visibility */}
      {booking.id_document_url && (
        <div className="mt-2 text-xs border-t border-[#F0EBE3] pt-2 flex items-center gap-1.5 text-[#3E7A58]">
          <FileText size={12} />
          <a href={booking.id_document_url} target="_blank" rel="noopener noreferrer" className="font-medium underline hover:text-[#1C3D2E] transition-colors">
            View Attached ID Proof
          </a>
        </div>
      )}

      {/* Actions */}
      <div className="mt-3 border-t border-[#F0EBE3] pt-3 flex justify-end gap-2">
        {/* Rate Action for Completed */}
        {booking.status?.toLowerCase() === 'completed' && (
          <button
            onClick={(e) => { e.stopPropagation(); onReviewOpen(booking); }}
            className="flex items-center gap-1.5 px-3.5 py-1.5 text-xs font-semibold rounded-full transition-all bg-[#3E7A58] text-[#F2EDE4] hover:bg-[#2A4D32] shadow-sm"
          >
            <Star size={12} className="fill-current" />
            Rate Experience
          </button>
        )}

        {/* Cancel Action for Pending/Confirmed */}
        {['pending', 'confirmed'].includes(booking.status) && (
          <button
            onClick={handleCancel}
            disabled={cancelling}
            className="px-3.5 py-1.5 text-xs font-semibold rounded-full transition-all border border-[#B45C5C] text-[#B45C5C] hover:bg-[#FAEAEA] disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {cancelling ? "Cancelling..." : "Cancel Booking"}
          </button>
        )}
      </div>
    </div>
  );
}

export default function MyBookings() {
  const [bookings, setBookings]   = useState([]);
  const [filter, setFilter]       = useState("all");
  const [loading, setLoading]     = useState(true);
  const [error, setError]         = useState("");
  const [selectedBooking, setSelectedBooking] = useState(null);
  
  const headerRef = useRef(null);
  const filterRef = useRef(null);

  const handleCancelSuccess = (id) => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status: 'cancelled' } : b));
  };

  const handleReviewSuccess = () => {
    // Optionally update local state if we want to hide the button
    // For now, refreshing or showing a toast is fine.
    alert("Thank you for your review!");
  };

  useEffect(() => {
    const tl = gsap.timeline();
    tl.fromTo(headerRef.current, { opacity: 0, y: -16 }, { opacity: 1, y: 0, duration: 0.6, ease: "power3.out" })
      .fromTo(filterRef.current, { opacity: 0, y: 10 }, { opacity: 1, y: 0, duration: 0.4, ease: "power3.out" }, "-=0.3");
  }, []);

  useEffect(() => {
    bookingService.getMyBookings()
      .then(res => {
        const data = res?.data?.bookings ?? res?.bookings ?? res?.data ?? [];
        setBookings(Array.isArray(data) ? data : []);
      })
      .catch(err => setError(err.message || "Failed to load bookings."))
      .finally(() => setLoading(false));
  }, []);

  const filtered = filter === "all" ? bookings : bookings.filter(b => b.status === filter);

  const counts = FILTERS.reduce((acc, f) => {
    acc[f] = f === "all" ? bookings.length : bookings.filter(b => b.status === f).length;
    return acc;
  }, {});

  return (
    <PageShell>
      <div className="min-h-screen bg-[#FAF7F2] px-4 py-8">
        <div className="max-w-2xl mx-auto">

          {/* Header */}
          <div ref={headerRef} className="mb-6">
            <h1 className="text-2xl font-bold text-[#1A2820]" style={{ fontFamily: "'Playfair Display', serif" }}>
              My Bookings
            </h1>
            <p className="text-sm text-[#9A9285] mt-0.5">Track upcoming and past experiences</p>
          </div>

          {/* Filter tabs */}
          <div ref={filterRef} className="flex gap-2 overflow-x-auto pb-1 mb-5 scrollbar-hide">
            {FILTERS.map(f => (
              <button key={f} onClick={() => setFilter(f)}
                className="shrink-0 flex items-center gap-1.5 rounded-full px-3.5 py-1.5 text-xs font-semibold transition-all duration-200 capitalize"
                style={{
                  background: filter === f ? "#1C3D2E" : "#F0EBE3",
                  color:      filter === f ? "#F2EDE4" : "#7A9285",
                }}>
                {f}
                {counts[f] > 0 && (
                  <span className="rounded-full px-1.5 py-0.5 text-[10px]"
                    style={{ background: filter === f ? "rgba(255,255,255,0.2)" : "#E0D8CE", color: filter === f ? "#F2EDE4" : "#9A9285" }}>
                    {counts[f]}
                  </span>
                )}
              </button>
            ))}
          </div>

          {/* Content */}
          {loading ? (
            <div className="space-y-3">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="bg-white rounded-[16px] border border-[#E8E1D5] h-28 animate-pulse" />
              ))}
            </div>
          ) : error ? (
            <div className="flex flex-col items-center py-16 text-center">
              <AlertCircle size={36} className="text-[#B45C5C] mb-2" />
              <p className="text-sm text-[#9A9285]">{error}</p>
            </div>
          ) : filtered.length === 0 ? (
            <div className="flex flex-col items-center py-16 text-center">
              <Inbox size={40} className="text-[#C4B8A8] mb-3" />
              <p className="text-sm text-[#9A9285]">
                {filter === "all" ? "No bookings yet. Start exploring!" : `No ${filter} bookings.`}
              </p>
            </div>
          ) : (
            <div className="space-y-3">
              {filtered.map((b, i) => (
                <BookingCard 
                  key={b.id} 
                  booking={b} 
                  index={i} 
                  onCancel={handleCancelSuccess} 
                  onReviewOpen={setSelectedBooking}
                />
              ))}
            </div>
          )}

          {selectedBooking && (
            <ReviewModal 
              booking={selectedBooking} 
              onClose={() => setSelectedBooking(null)} 
              onSuccess={handleReviewSuccess}
            />
          )}
        </div>
      </div>
    </PageShell>
  );
}

import { useEffect, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import { gsap } from "gsap";
import {
  ChevronRight,
  Compass,
  MapPin,
  Sparkles,
  Star,
  TrendingUp,
  Users,
  Shield,
  Leaf,
  Globe,
  ArrowRight,
  Search,
  BookOpen,
  Calendar,
  Heart,
  Clock,
  User,
} from "lucide-react";
import { useAuth } from "../../context/AuthContext";
import communityService from "../../services/communityService";
import storyService from "../../services/storyService";

function getCommunityImage(c) {
  return c.cover_image_url || c.images?.[0]?.image_url || c.image_url || "";
}

export default function TouristDashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [communities, setCommunities] = useState([]);
  const [stories, setStories] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const heroRef = useRef(null);
  const communitiesRef = useRef(null);
  const storiesRef = useRef(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [commRes, storyRes] = await Promise.all([
          communityService.list("status=verified&limit=6"),
          storyService.list("limit=4")
        ]);
        
        setCommunities(commRes?.data?.communities ?? commRes?.communities ?? []);
        setStories(storyRes?.data?.stories ?? storyRes?.stories ?? []);
      } catch (err) {
        console.error("Dashboard fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    if (loading) return;
    const ctx = gsap.context(() => {
      const tl = gsap.timeline({ defaults: { ease: "power3.out" } });
      
      tl.fromTo(heroRef.current, 
        { opacity: 0, y: 30 }, 
        { opacity: 1, y: 0, duration: 0.8 }
      );

      if (communitiesRef.current) {
        tl.fromTo(communitiesRef.current.children, 
          { opacity: 0, y: 20 }, 
          { opacity: 1, y: 0, duration: 0.6, stagger: 0.1 }, 
          "-=0.4"
        );
      }

      if (storiesRef.current) {
        tl.fromTo(storiesRef.current.children, 
          { opacity: 0, x: 20 }, 
          { opacity: 1, x: 0, duration: 0.6, stagger: 0.1 }, 
          "-=0.4"
        );
      }
    });
    return () => ctx.revert();
  }, [loading]);

  const firstName = user?.name?.split(" ")[0] || "Traveller";
  const hour = new Date().getHours();
  const greeting = hour < 12 ? "Good morning" : hour < 17 ? "Good afternoon" : "Good evening";

  return (
    <div style={{ background: "var(--color-cream)", minHeight: "100vh" }}>
      
      {/* ── HERO SECTION ── */}
      <div className="pt-24 pb-12 px-5 max-w-7xl mx-auto">
        <div 
          ref={heroRef}
          className="relative overflow-hidden rounded-[2.5rem] shadow-2xl"
          style={{
            background: "linear-gradient(135deg, #1C3D2E 0%, #2D6A4F 60%, #3E7A58 100%)",
            minHeight: "400px"
          }}
        >
          {/* Ambient visuals */}
          <div className="absolute inset-0 opacity-20 pointer-events-none">
            <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[80%] rounded-full bg-[#D4E6DC] blur-[120px]" />
            <div className="absolute bottom-[-20%] left-[-10%] w-[40%] h-[60%] rounded-full bg-[#C8883A] blur-[100px] opacity-30" />
          </div>

          <div className="relative h-full flex flex-col justify-center p-8 md:p-16">
            <div className="max-w-2xl">
              <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-white/10 backdrop-blur-md border border-white/20 mb-6">
                <Sparkles size={14} className="text-[#A8CCBA]" />
                <span className="text-[10px] font-bold uppercase tracking-widest text-[#A8CCBA]">
                  Welcome back, Explorer
                </span>
              </div>
              
              <h1 
                className="text-4xl md:text-6xl text-white mb-6 leading-[1.1]"
                style={{ fontFamily: "var(--font-display)", letterSpacing: "-0.02em" }}
              >
                {greeting}, <br className="hidden md:block" />
                <span style={{ color: "var(--color-amber-light)" }}>{firstName}</span>
              </h1>
              
              <p className="text-lg text-white/80 mb-10 leading-relaxed max-w-lg italic font-medium">
                "BOND — Because every community has a story worth travelling for."
              </p>

              <div className="flex flex-wrap gap-4">
                <button
                  onClick={() => navigate("/tourist/explore")}
                  className="group flex items-center gap-2 px-8 py-4 rounded-2xl bg-white text-[#1C3D2E] font-bold transition-all duration-300 hover:scale-105 hover:shadow-xl"
                >
                  <Search size={18} />
                  Start Exploring
                </button>
                <button
                  onClick={() => navigate("/tourist/bookings")}
                  className="flex items-center gap-2 px-8 py-4 rounded-2xl bg-white/10 backdrop-blur-md border border-white/20 text-white font-bold transition-all duration-300 hover:bg-white/20"
                >
                  <Calendar size={18} />
                  My Bookings
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ── FEATURED COMMUNITIES ── */}
      <section className="pb-32 px-5 max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-6">
          <div className="max-w-xl">
            <div className="flex items-center gap-3 mb-3">
              <div className="w-12 h-[1px] bg-[#3E7A58]/30" />
              <span className="text-[10px] font-black uppercase tracking-[0.3em] text-[#3E7A58]">Curated for you</span>
            </div>
            <h2 className="text-4xl md:text-5xl font-semibold text-[#1A2820]" style={{ fontFamily: "var(--font-display)" }}>
              Recommended <span className="text-[#3E7A58]">Communities</span>
            </h2>
            <p className="mt-4 text-gray-500 leading-relaxed">
              Hand-picked local communities offering authentic sustainable experiences across the Northeast.
            </p>
          </div>
          <button 
            onClick={() => navigate("/tourist/explore")}
            className="flex items-center gap-2 px-6 py-3 rounded-xl bg-[#D4E6DC] text-[#3E7A58] text-sm font-bold hover:bg-[#3E7A58] hover:text-white transition-all duration-300"
          >
            Explore All <ArrowRight size={16} />
          </button>
        </div>

        {loading ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
            {[1, 2, 3].map((i) => (
              <div key={i} className="h-[450px] rounded-[2.5rem] animate-pulse bg-black/5" />
            ))}
          </div>
        ) : (
          <div ref={communitiesRef} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
            {communities.map((c) => {
              const img = getCommunityImage(c);
              const loc = [c.village, c.state].filter(Boolean).join(", ") || "Northeast India";
              const rating = parseFloat(c.avg_rating) || 0;
              const reviewCount = parseInt(c.review_count) || 0;
              const memberCount = parseInt(c.member_count) || 0;
              
              return (
                <div 
                  key={c.id}
                  onClick={() => navigate(`/tourist/community/${c.slug || c.id}`)}
                  className="group relative flex flex-col bg-white rounded-[2.5rem] overflow-hidden transition-all duration-500 hover:shadow-[0_32px_64px_-12px_rgba(28,61,46,0.15)] border border-black/[0.04]"
                >
                  {/* Image Container */}
                  <div className="relative h-72 overflow-hidden">
                    {img ? (
                      <img 
                        src={img} 
                        alt={c.name} 
                        className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" 
                      />
                    ) : (
                      <div className="w-full h-full bg-[#D4E6DC] flex items-center justify-center text-[#3E7A58]">
                        <Globe size={48} />
                      </div>
                    )}
                    
                    {/* Top Layer */}
                    <div className="absolute inset-0 bg-gradient-to-t from-black/40 via-transparent to-transparent opacity-60" />
                    
                    {/* Badge */}
                    <div className="absolute top-6 left-6">
                      <div className="px-4 py-1.5 rounded-full bg-white/20 backdrop-blur-md border border-white/30 text-[9px] font-black uppercase text-white tracking-widest shadow-lg">
                        {c.status === "verified" ? "Verified Partner" : "Featured"}
                      </div>
                    </div>

                    {/* Rating on Image */}
                    <div className="absolute bottom-6 left-6 flex items-center gap-1.5 text-white">
                      <div className="flex items-center gap-1 px-2.5 py-1 rounded-lg bg-white text-[#1A2820] text-xs font-bold shadow-sm">
                        <Star size={12} fill="#F59E0B" color="#F59E0B" />
                        {rating > 0 ? rating.toFixed(1) : "0.0"}
                      </div>
                      <span className="text-[10px] font-bold text-white/90 drop-shadow-md uppercase tracking-wider">
                        {reviewCount} {reviewCount === 1 ? 'review' : 'reviews'}
                      </span>
                    </div>
                  </div>

                  {/* Content */}
                  <div className="p-8 flex flex-col flex-grow relative">
                    <div className="flex items-center gap-2 text-[10px] font-black text-[#3E7A58] uppercase tracking-[0.2em] mb-4">
                      <MapPin size={14} className="opacity-50" /> {loc}
                    </div>
                    
                    <h3 className="text-2xl font-semibold mb-4 text-[#1A2820] leading-tight" style={{ fontFamily: "var(--font-display)" }}>
                      {c.name}
                    </h3>
                    
                    <p className="text-sm text-gray-400 line-clamp-2 mb-8 leading-relaxed font-medium">
                      {c.description || "Immerse yourself in authentic cultural traditions and sustainable community-led initiatives."}
                    </p>
                    
                    <div className="mt-auto flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <div className="flex -space-x-2">
                          {[1, 2, 3].map(i => (
                            <div key={i} className="w-8 h-8 rounded-full border-2 border-white bg-[#D4E6DC] flex items-center justify-center overflow-hidden">
                              <User size={14} className="text-[#3E7A58]" />
                            </div>
                          ))}
                        </div>
                        <div className="flex flex-col">
                          <span className="text-[10px] font-black text-[#1A2820] leading-none">{memberCount}</span>
                          <span className="text-[8px] font-bold text-gray-400 uppercase tracking-tighter">Members</span>
                        </div>
                      </div>
                      
                      <div className="flex items-center gap-2 text-[11px] font-black text-[#3E7A58] uppercase tracking-widest group-hover:gap-4 transition-all duration-300">
                        Profile <ArrowRight size={16} />
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </section>

      {/* ── FOOTER CTA ── */}
      <div className="pb-32 px-5 max-w-4xl mx-auto">
        <div className="bg-[#1A2820] rounded-[3rem] p-12 md:p-20 text-center relative overflow-hidden shadow-2xl">
          <div className="absolute top-0 right-0 w-64 h-64 bg-[#3E7A58] blur-[120px] opacity-20" />
          <div className="absolute bottom-0 left-0 w-64 h-64 bg-[#C8883A] blur-[120px] opacity-10" />
          
          <div className="relative z-10">
            <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-8 text-[#A8CCBA] border border-white/10">
              <Heart size={32} />
            </div>
            <h3 className="text-3xl md:text-4xl font-bold mb-6 text-white" style={{ fontFamily: "var(--font-display)" }}>
              Ready to make an impact?
            </h3>
            <p className="text-white/60 mb-12 leading-relaxed max-w-xl mx-auto text-lg">
              Every booking contributes to the preservation of indigenous cultures and the protection of biodiversity in the region.
            </p>
            <button
              onClick={() => navigate("/tourist/explore")}
              className="px-12 py-5 rounded-2xl bg-white text-[#1A2820] font-bold text-lg transition-all duration-300 hover:shadow-2xl hover:scale-105"
            >
              Start Your Journey
            </button>
          </div>
        </div>
      </div>

    </div>
  );
}

